interface NodeRecord {
  id: string;
  confidence: number;
  validUntil?: number;
  sourceFile: string;
  /** The node's true allowlist sourceId (e.g. `clip:497ecba…`), resolved
   *  server-side via the source index. Distinct from `sourceFile` (the SDK's
   *  raw file string). Drives per-source redaction in Presentation Mode. */
  sourceId?: string;
  contentPreview: string;
  /** Section heading the node lives under (markdown `#`/`##` etc.). */
  section?: string;
  /** SDK NodeType — 'fact' | 'concept' | 'section' | 'document' | … */
  nodeType?: string;
  /** SDK-extracted entities (proper nouns, dates, acronyms, technical
   *  terms, …). Used by the App's entity-aware candidate ranking when
   *  surfacing "what other memories mention this person/place/topic?"
   *  in the typed-relationship suggestion panel. Empty/undefined if the
   *  node never went through entity extraction. */
  entities?: string[];
  /** Client-side tag: which engram this node was loaded from. Filled in
   *  by the global search loader so result rows can show an engram chip
   *  and the per-engram filter can narrow results without re-querying. */
  _graphId?: string;
  /** Client-side tag: this row was surfaced by GNN-Exploration augmentation
   *  (a Pro feature), not by direct substring/semantic match. The row
   *  renderer adds a 🧠 chip when set, and the score is the neural net's
   *  edge-prediction confidence. */
  _gnnAugmented?: boolean;
  /** GNN-edge confidence score (0–1) when _gnnAugmented is true. */
  _gnnScore?: number;
}

