// ── 3D Atlas navigation cheatsheet ─────────────────────────────────────
// Small overlay in the bottom-left of the atlas pane that explains the
// rotate/pan/zoom + selection shortcuts. Dismissable; the user's choice
// persists in localStorage so they don't see it every time once they've
// learned the bindings.
{
  const helpEl = document.getElementById('atlas-nav-help') as HTMLDivElement | null;
  const closeBtn = document.getElementById('btn-atlas-nav-close') as HTMLButtonElement | null;
  // The legend (top-left) and the axes gizmo (bottom-right) need to step
  // out of the cheatsheet's footprint when it's shown, then reclaim the
  // freed space when it's dismissed. We flag this on the .atlas-stage so
  // CSS can drive both adjustments with a single ancestor selector — and
  // it stays correct regardless of which child renders first.
  const stage = helpEl?.closest('.atlas-stage') as HTMLElement | null;
  const syncStageFlag = (visible: boolean) => {
    stage?.classList.toggle('nav-help-visible', visible);
  };
  // Always show on launch. The old behaviour persisted a "hidden" flag in
  // localStorage so dismissing the cheatsheet stuck across sessions, but
  // the navigation bindings are subtle enough (drag rotate, shift+drag
  // pan, scroll zoom) that a refresher every launch costs little and
  // helps occasional users. The close button still works for THIS
  // session — the cheatsheet just reappears on next app launch.
  if (helpEl) {
    helpEl.classList.remove('hidden');
    syncStageFlag(true);
  }
  closeBtn?.addEventListener('click', () => {
    helpEl?.classList.add('hidden');
    syncStageFlag(false);
    // Intentionally NOT persisted — see comment above.
  });
}

// ── Search input + ⌘F + clear ─────────────────────────────────────────

// Global ⌘F / Ctrl+F — jump straight to Check-in tab and focus the search bar
// from anywhere in the app. Works regardless of which pane or tab is active.
document.addEventListener('keydown', (e: KeyboardEvent) => {
  if ((e.metaKey || e.ctrlKey) && e.key === 'f' && !e.shiftKey && !e.altKey) {
    // Don't hijack ⌘K inside text inputs other than gSearch itself.
    const tag = (e.target as HTMLElement).tagName;
    if (tag === 'INPUT' || tag === 'TEXTAREA') return;
    e.preventDefault();
    // ⌘F opens the dedicated Search page (activateMode handles the pane +
    // checkin tab + body.search-mode + focusing the box).
    if (currentMode !== 'search') activateMode('search');
    els.gSearch.focus();
    els.gSearch.select();
  }
});

// Status-bar MCP area → navigate to Status page on click.
document.getElementById('status-mcp-area')?.addEventListener('click', () => {
  // Status page removed — the AI-client list lives on Get Connected now.
  activateMode('get-connected');
});

els.gSearch.addEventListener('focus', () => {
  // Search box is always visible above all tabs. Focusing it from any
  // non-checkin tab switches to Check-in so results are immediately visible.
  if (graphnosisActiveTab !== 'checkin') switchGraphnosisTab('checkin');
});

els.gSearch.addEventListener('input', () => {
  if (graphnosisSearchTimer !== null) clearTimeout(graphnosisSearchTimer);
  const hasValue = els.gSearch.value.length > 0;
  els.gSearchClear.classList.toggle('hidden', !hasValue);
  // 140ms gives a fluid feel without re-rendering on every keystroke when
  // typing fast. LLM enhancements are NOT triggered here — Enter key only.
  graphnosisSearchTimer = setTimeout(() => applyGraphnosisFilter(), 140);
});

els.gSearch.addEventListener('keydown', (e) => {
  // Esc clears the query → recenters the hero box (see search-mode CSS).
  if (e.key === 'Escape' && els.gSearch.value.length > 0) {
    e.preventDefault();
    els.gSearch.value = '';
    els.gSearchClear.classList.add('hidden');
    applyGraphnosisFilter();
    return;
  }
  if (e.key !== 'Enter') return;
  e.preventDefault();
  const q = els.gSearch.value.trim();
  if (q.length === 0 || graphnosisListRows.length === 0) return;
  // Enter with a live result set → run LLM enhancements if opted in.
  void applyLlmSearchEnhancements(q, graphnosisListRows);
});

// Sort dropdown — re-apply the filter when the user picks a new order.
// No debounce; the change is user-initiated and synchronous.
els.gSearchSortSelect.addEventListener('change', () => {
  const v = els.gSearchSortSelect.value;
  if (v === 'relevance' || v === 'confidence' || v === 'source') {
    searchSortMode = v;
    applyGraphnosisFilter();
  }
});

// Engram filter — scopes the global search to a single engram (or "All").
// Persisted to localStorage so the choice survives reloads.
try {
  const stored = localStorage.getItem('search:engramFilter');
  if (stored !== null) searchEngramFilter = stored;
} catch {}
els.gSearchEngramSelect.addEventListener('change', () => {
  searchEngramFilter = els.gSearchEngramSelect.value;
  try {
    if (searchEngramFilter) {
      localStorage.setItem('search:engramFilter', searchEngramFilter);
    } else {
      localStorage.removeItem('search:engramFilter');
    }
  } catch {}
  applyGraphnosisFilter();
});

els.gSearchClear.addEventListener('click', () => {
  els.gSearch.value = '';
  els.gSearchClear.classList.add('hidden');
  applyGraphnosisFilter();
  els.gSearch.focus();
});
// Mirror of the in-input × clear, lives in the search-results header so
// the user can dismiss the results panel without scrolling back up to the
// textbox. Same effect: empties the query, re-runs the filter (which
// hides the results panel and shows the dashboard), refocuses the input.
document.getElementById('btn-search-results-close')?.addEventListener('click', () => {
  els.gSearch.value = '';
  els.gSearchClear.classList.add('hidden');
  applyGraphnosisFilter();
  els.gSearch.focus();
});

// Memory Inspector close button — collapses the detail pane.
document.getElementById('btn-detail-close')?.addEventListener('click', () => {
  renderDetailEmpty();
});

// ── Keyboard shortcuts (only when Graphnosis pane is active) ──────────
//
// ⌘K — focus the search field, anywhere.
// ↑/↓ — move selection through the list (when not typing in an input).
// Enter — focus list (or open detail; the list is already showing).
// E — start inline edit on selected node.
// Delete/Backspace — forget selected node.
// Esc — deselect, or cancel edit.

document.addEventListener('keydown', (e) => {
  if (!isAtlasPaneMode()) return;
  const target = e.target as HTMLElement | null;
  const inField = !!target && (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable);

  // ⌘K: focus search from anywhere (even while inside another input).
  if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === 'k') {
    e.preventDefault();
    els.gSearch.focus();
    els.gSearch.select();
    return;
  }

  if (inField) {
    // While typing, only Esc has meaning (and Enter for the search field).
    if (e.key === 'Escape') {
      if (target === els.gSearch && els.gSearch.value.length > 0) {
        els.gSearch.value = '';
        els.gSearchClear.classList.add('hidden');
        applyGraphnosisFilter();
        e.preventDefault();
        return;
      }
      if (graphnosisEditingId) {
        graphnosisEditingId = null;
        renderDetailPane();
        e.preventDefault();
        return;
      }
      els.gSearch.blur();
      e.preventDefault();
      return;
    }
    if (target === els.gSearch && (e.key === 'ArrowDown' || e.key === 'Enter')) {
      // Jump from the search field into the first list row.
      e.preventDefault();
      if (graphnosisListRows.length > 0) {
        const first = graphnosisListRows[0];
        // trace:true — explicit keyboard navigation (Enter or ArrowDown
        // from the search box) is the user picking a result; should
        // persist onto 3D Engram tab.
        if (first) selectGraphnosisNode(first.id, { trace: true });
        els.gList.focus();
        scrollSelectedListRowIntoView();
      }
      return;
    }
    return;
  }

  // Typing a printable character while on a non-search tab → auto-switch
  // to Check-in so the keystroke lands in the search field naturally.
  if (graphnosisActiveTab !== 'checkin' && !e.metaKey && !e.ctrlKey && !e.altKey && e.key.length === 1) {
    activateMode('atlas');
    els.gSearch.focus();
    // Don't preventDefault — the character propagates into the now-focused search input.
    return;
  }

  // Not in a field. Keyboard nav over the list.
  switch (e.key) {
    case 'ArrowDown':
    case 'ArrowUp': {
      if (graphnosisListRows.length === 0) return;
      const idx = graphnosisSelectedId
        ? graphnosisListRows.findIndex((n) => n.id === graphnosisSelectedId)
        : -1;
      const step = e.key === 'ArrowDown' ? 1 : -1;
      const nextIdx = Math.max(0, Math.min(graphnosisListRows.length - 1, (idx === -1 ? 0 : idx + step)));
      const next = graphnosisListRows[nextIdx];
      if (next) {
        // trace:true — Arrow-key nav over the list is explicit user
        // navigation; persists onto 3D Engram tab.
        selectGraphnosisNode(next.id, { trace: true });
        scrollSelectedListRowIntoView();
      }
      e.preventDefault();
      break;
    }
    case 'Enter': {
      // Enter on a selected list row opens the detail (already shown), and
      // jumps focus into edit. Without selection, focus search.
      if (graphnosisSelectedId) {
        startInlineEdit(graphnosisSelectedId);
      } else {
        els.gSearch.focus();
      }
      e.preventDefault();
      break;
    }
    case 'e':
    case 'E': {
      if (graphnosisSelectedId) {
        startInlineEdit(graphnosisSelectedId);
        e.preventDefault();
      }
      break;
    }
    case 'Backspace':
    case 'Delete': {
      if (graphnosisSelectedId) {
        void forgetSelected();
        e.preventDefault();
      }
      break;
    }
    case 'Escape': {
      if (graphnosisSelectedId) {
        selectGraphnosisNode(null);
        e.preventDefault();
      }
      break;
    }
  }
});

function cssColorForCategory(cat: EdgeCategory): string {
  return `#${CATEGORY_COLOR[cat].toString(16).padStart(6, '0')}`;
}

// ── Activity (op-log timeline) ────────────────────────────────────────

// Growing fetch window: autonomous-brain ops (e.g. mass edge re-links) can fill
// the most-recent N events and bury the user's ingests/edits/forgets, which are
// older. So we start at 2000 and grow the window (see auto-load in renderActivity)
// until there's real variety. The sidecar's incremental cache makes re-slicing a
// bigger window cheap after the first cold read.
// Default ~500 events loaded; the user clicks "Load more" for more. The
// autonomous brain can emit tens of thousands of edge ops a day, so for a
// specific category (Ingested/Forgotten/Edits…) we pass `ops` to the sidecar so
// it pulls THAT type from the full op-log — no longer buried under edge spam.
// 500 felt thin. The render groups+collapses events by day→signature, so the DOM
// is bounded by GROUP count, not event count — the only cost is the op-log fetch,
// and the backend already pulls limit:10000 elsewhere. So we can start much higher
// and step bigger. 2000 initial loads in well under a second and shows real depth;
// "Load more" ramps 2000 at a time to a 20000 hard cap (a brief load at the top
// end, on demand).
const ACTIVITY_WINDOW_START = 2000;
const ACTIVITY_WINDOW_STEP = 2000;
const ACTIVITY_WINDOW_MAX = 20000;
let activityWindow = ACTIVITY_WINDOW_START;
let activityHasMore = false;      // fetched == window → more events may exist
let activityLoading = false;      // guards re-entrancy + the button spinner

/** Read the date-range inputs → an absolute ms window for the op-log fetch.
 *  `since` is exclusive (IPC uses `ts > since`), so we subtract 1ms from the
 *  start-of-day; `until` is inclusive end-of-day. Returns {} when no dates set. */
function activityDateBounds(): { since?: number; until?: number } {
  const out: { since?: number; until?: number } = {};
  const from = els.activityDateFrom.value;
  const to = els.activityDateTo.value;
  if (from) out.since = new Date(`${from}T00:00:00`).getTime() - 1;
  if (to) out.until = new Date(`${to}T23:59:59.999`).getTime();
  return out;
}
function activityDateRangeActive(): boolean {
  return Boolean(els.activityDateFrom.value || els.activityDateTo.value);
}

async function refreshActivityView(): Promise<void> {
  if (activityLoading) return;
  activityLoading = true;
  if (activityEvents.length === 0) {
    els.activityList.innerHTML = '<div class="home-skel"></div><div class="home-skel w70"></div><div class="home-skel"></div>';
  }
  try {
    const bounds = activityDateBounds();
    const dateScoped = activityDateRangeActive();
    // With an explicit date range, pull the WHOLE range from the op-log (up to
    // the hard cap) rather than the recent-N window — old days are otherwise
    // unreachable. Without one, keep the cheap recent-window paging.
    const params: { limit: number; ops?: string[]; since?: number; until?: number; actor?: string } =
      { limit: dateScoped ? ACTIVITY_WINDOW_MAX : activityWindow };
    if (activityCat !== 'all') params.ops = ACTIVITY_CAT_OPS[activityCat]; // server-side type filter
    if (bounds.since !== undefined) params.since = bounds.since;
    if (bounds.until !== undefined) params.until = bounds.until;
    // Actor ("who") is now a SERVER-side filter (applied across the full op-log,
    // like categories) so picking a rare actor surfaces their events even when
    // outside the recent window.
    const actorSel = els.activityActorSelect.value;
    if (actorSel) params.actor = actorSel;
    const r = await ipcCallTimeout<{ events: OpLogEvent[]; actors?: string[] }>('activity.list', params, 25_000);
    activityEvents = r.events ?? [];
    activityServerActors = r.actors ?? []; // complete distinct-actor set for the dropdown
    // Date-scoped fetches pull the whole range (no recent-window paging), so
    // "more" only means we hit the hard cap; otherwise it's window-relative.
    activityHasMore = dateScoped
      ? activityEvents.length >= ACTIVITY_WINDOW_MAX
      : activityEvents.length >= activityWindow;
    populateActivityEngramSelect();
    populateActivityActorSelect();
    applyActivityFilter();
  } catch {
    els.activityList.innerHTML =
      '<p class="subtitle">Couldn’t load activity — the op-log read timed out. ' +
      '<button id="btn-activity-retry" class="btn-sm" type="button">Retry</button></p>';
    document.getElementById('btn-activity-retry')?.addEventListener('click', () => { activityWindow = ACTIVITY_WINDOW_START; void refreshActivityView(); });
  } finally {
    activityLoading = false;
  }
}

/** Grow the fetch window by a batch and reload (the "Load more" button). */
function loadMoreActivity(): void {
  if (activityLoading || activityWindow >= ACTIVITY_WINDOW_MAX) return;
  activityWindow = Math.min(ACTIVITY_WINDOW_MAX, activityWindow + ACTIVITY_WINDOW_STEP);
  void refreshActivityView();
}

// Most-recent events from the last activity.list fetch. Chip/search/engram
// filtering runs against this cache so it's instant (no re-fetch per keystroke).
let activityEvents: OpLogEvent[] = [];
let activityFiltered: OpLogEvent[] = []; // last filtered set
type ActivityCat = 'all' | 'ingested' | 'nodes' | 'edits' | 'edges' | 'merged' | 'forgotten';
let activityCat: ActivityCat = 'all';
// op → friendly category. Granular: ingests, nodes, edits, edges, merges,
// forgets. Drives both the chips and their count badges.
const ACTIVITY_CAT_OPS: Record<Exclude<ActivityCat, 'all'>, OpLogEvent['op'][]> = {
  ingested: ['ingestSource'],
  nodes: ['addNode', 'deleteNode'],
  edits: ['editNode', 'supersede'],
  edges: ['addEdge', 'deleteEdge'],
  merged: ['merge'],
  forgotten: ['forgetSource'],
};
const ACTIVITY_CAT_LABELS: Record<ActivityCat, string> = {
  all: 'All', ingested: 'Ingested', nodes: 'Nodes', edits: 'Edits',
  edges: 'Edges', merged: 'Merged', forgotten: 'Forgotten',
};
function activityCatOf(op: OpLogEvent['op']): Exclude<ActivityCat, 'all'> | null {
  for (const cat of Object.keys(ACTIVITY_CAT_OPS) as Array<Exclude<ActivityCat, 'all'>>) {
    if (ACTIVITY_CAT_OPS[cat].includes(op)) return cat;
  }
  return null;
}

/** Fill the engram scope dropdown from ALL loaded engrams (not just those that
 *  happen to appear in the recent-events window), preserving the selection. */
function populateActivityEngramSelect(): void {
  const prev = els.activityEngramSelect.value;
  const graphs = loadedGraphs.filter((g) => !g.metadata.archived);
  const ids = graphs.map((g) => g.graphId)
    .sort((a, b) => engramName(a).localeCompare(engramName(b)));
  els.activityEngramSelect.innerHTML =
    '<option value="">All engrams</option>' +
    ids.map((id) => `<option value="${escape(id)}">${escape(engramName(id))}</option>`).join('');
  if (prev && ids.includes(prev)) els.activityEngramSelect.value = prev;
}

/** Fill the "who" dropdown from the distinct actors present in the loaded
 *  events (You, Autonomous brain, Claude Code / other AI clients, App…),
 *  preserving the current selection. */
// Distinct actor labels are computed SERVER-SIDE across the full op-log scope
// (activity.list returns `actors`), so the dropdown is always complete — no
// dependence on which events happen to be in the recent-N window.
let activityServerActors: string[] = [];
function populateActivityActorSelect(): void {
  const prev = els.activityActorSelect.value;
  els.activityActorSelect.innerHTML =
    '<option value="">Anyone</option>' +
    activityServerActors.map((l) => `<option value="${escape(l)}">${escape(l)}</option>`).join('');
  // Keep the current selection even if it's not in the latest set (e.g. it's
  // the active filter and the server excluded it from `actors`); re-add it.
  if (prev) {
    if (!activityServerActors.includes(prev)) {
      els.activityActorSelect.insertAdjacentHTML('beforeend', `<option value="${escape(prev)}">${escape(prev)}</option>`);
    }
    els.activityActorSelect.value = prev;
  }
}

/** Category is server-filtered (via `ops`); here we only apply the engram scope
 *  + text query to the fetched set, then render. */
/** Parse a "HH:MM" time input → minutes-since-midnight, or null if empty. */
function activityHourMinutes(val: string): number | null {
  const m = /^(\d{2}):(\d{2})$/.exec(val);
  if (!m) return null;
  return Number(m[1]) * 60 + Number(m[2]);
}

function applyActivityFilter(): void {
  const engram = els.activityEngramSelect.value;
  // Actor is filtered server-side (refetch on change) — not here.
  const query = els.activitySearch.value.trim().toLowerCase();
  const matchesText = (e: OpLogEvent): boolean => {
    if (!query) return true;
    const hay = `${e.op} ${e.graphId} ${engramName(e.graphId)} ${activityLabel(e).replace(/<[^>]+>/g, '')} ${activityDetail(e).replace(/<[^>]+>/g, '')}`.toLowerCase();
    return hay.includes(query);
  };
  // Hour-of-day window (applies to every selected day). Supports wrap-around
  // (e.g. 22:00 → 06:00 = overnight) by inverting the test when from > to.
  const hourFrom = activityHourMinutes(els.activityHourFrom.value);
  const hourTo = activityHourMinutes(els.activityHourTo.value);
  const matchesHour = (e: OpLogEvent): boolean => {
    if (hourFrom === null && hourTo === null) return true;
    const d = new Date(e.ts);
    const mins = d.getHours() * 60 + d.getMinutes();
    const lo = hourFrom ?? 0;
    const hi = hourTo ?? 24 * 60 - 1;
    return lo <= hi ? (mins >= lo && mins <= hi) : (mins >= lo || mins <= hi);
  };
  els.activityChips.querySelectorAll<HTMLButtonElement>('.g-activity-chip').forEach((chip) => {
    const cat = (chip.dataset.cat ?? 'all') as ActivityCat;
    chip.classList.toggle('active', cat === activityCat);
    chip.textContent = ACTIVITY_CAT_LABELS[cat]; // no counts — category now pulls full history
  });
  // Reflect whether any date/hour filter is active on the Clear button.
  const rangeActive = activityDateRangeActive() || hourFrom !== null || hourTo !== null;
  els.activityDateClear.classList.toggle('hidden', !rangeActive);
  activityFiltered = activityEvents
    .filter((e) => (!engram || e.graphId === engram)
      && matchesText(e) && matchesHour(e))
    .slice().sort((a, b) => b.ts - a.ts);
  renderActivity();
}

const activityDayLabel = (ts: number): string => {
  const d = new Date(ts);
  const today = new Date();
  const yesterday = new Date(today); yesterday.setDate(today.getDate() - 1);
  if (d.toDateString() === today.toDateString()) return 'Today';
  if (d.toDateString() === yesterday.toDateString()) return 'Yesterday';
  return d.toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric' });
};
const activityTime = (ts: number): string => new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

/** Who/what triggered an op — derived from the scattered provenance fields
 *  (addedBy / correctedBy MCP client, triggeredBy user:/brain:/ipc:, edge reason). */
function activityActor(e: OpLogEvent): { label: string; cls: string } {
  // Prefer the server-computed actor (activity.list attaches it) so labels match
  // the dropdown + filter exactly; fall back to client classification otherwise.
  if (e.actor) return { label: e.actor, cls: e.actorCls ?? 'app' };
  const a = (e.after ?? {}) as Record<string, unknown>;
  const b = (e.before ?? {}) as Record<string, unknown>;
  const client = (a['addedBy'] ?? a['correctedBy']) as string | undefined;
  if (client) return { label: friendlyClient(client), cls: 'ai' };
  const trig = ((a['triggeredBy'] ?? b['triggeredBy']) as string | undefined) ?? '';
  const reason = ((a['reason'] ?? b['reason']) as string | undefined) ?? '';
  if (trig.startsWith('user:')) return { label: 'You', cls: 'user' };
  if (trig.startsWith('brain:') || /\bbrain:|auto-relink|auto-link/i.test(reason)) return { label: 'Autonomous brain', cls: 'brain' };
  if (/user-confirmed/i.test(reason)) return { label: 'You', cls: 'user' };
  if (trig.startsWith('ipc:')) return { label: 'App', cls: 'app' };
  return { label: 'System', cls: 'app' };
}

/** Grouping key: identical events (same op, engram, actor, detail) collapse. */
function activitySig(e: OpLogEvent): string {
  // Use the grouping-stable detail (omits per-node addNode content) so 350
  // identical "Added a memory node" events still collapse into one ×350 group.
  return `${e.op}|${e.graphId}|${activityActor(e).label}|${activityDetail(e, { forGrouping: true }).replace(/<[^>]+>/g, '')}`;
}

function actorBadge(a: { label: string; cls: string }): string {
  // Presentation Mode: external identities redact — connectors follow the
  // connectors surface, AI clients the mcpClients surface. "You" / "Autonomous
  // brain" / "App" / "System" are generic and stay visible.
  const tag = a.label.startsWith('connector:') ? 'surface:connectors'
    : a.cls === 'ai' ? 'surface:mcpClients' : '';
  const attr = tag ? ` data-pres="${tag}"` : '';
  return `<span class="activity-actor actor-${a.cls}" title="Who made this change"${attr}>${escape(a.label)}</span>`;
}

/** Translate the internal reason/trigger codes into plain language an auditor
 *  can read. The parenthetical in auto-relink reasons IS the shared entity. */
function humanizeReason(reason: string): string {
  const r = reason.toLowerCase();
  const paren = reason.match(/\(([^)]+)\)/)?.[1];
  if (r.includes('consolidation-cleanup')) return 'removed a redundant connection during consolidation';
  if (r.includes('transitive-inference')) return 'inferred from a chain of related memories';
  // NOTE: the SDK's "same-person" heuristic flags any capitalised entity (e.g.
  // "Remote Access", "2026"), so don't assert it's a person — just say both
  // memories reference it. The SAME-PERSON badge already conveys the edge type.
  if (r.startsWith('auto-relink: same-person')) return paren ? `both reference ${paren}` : 'both reference the same entity';
  if (r.startsWith('auto-relink: shares-entity')) return paren ? `both mention ${paren}` : 'both mention the same entity';
  if (r.startsWith('auto-relink')) return paren ? `shared reference — ${paren}` : 'shared reference';
  if (r.startsWith('auto-link')) { const m = reason.match(/(\d+%)/); return m ? `semantically similar (${m[1]})` : 'semantically similar'; }
  if (r.includes('reinforcement')) return 'confidence reinforced by repeated recall';
  if (r.includes('user-confirmed')) return 'you confirmed this connection';
  if (r.startsWith('user:')) return 'you · ' + reason.slice(5);
  if (r.startsWith('brain:')) return 'autonomous brain · ' + reason.slice(6);
  if (r.startsWith('ipc:')) return 'app · ' + reason.slice(4);
  return reason;
}

/** Best-effort node-id → content preview, from the engrams currently loaded in
 *  memory. Rebuilt per render. Cross-engram / unvisited engrams won't resolve
 *  client-side — full coverage needs sidecar enrichment (see the audit plan). */
let _activityNodePreviews = new Map<string, string>();
function rebuildActivityNodePreviews(): void {
  _activityNodePreviews = new Map();
  for (const nodes of graphnosisGlobalNodes.values()) for (const n of nodes) if (n.contentPreview) _activityNodePreviews.set(n.id, n.contentPreview);
  for (const n of graphnosisAllNodes) if (n.contentPreview) _activityNodePreviews.set(n.id, n.contentPreview);
}
function nodePreview(id: string): string | null {
  const p = _activityNodePreviews.get(id);
  return p && p.trim() ? p.trim() : null;
}

function renderActivity(): void {
  rebuildActivityNodePreviews(); // for resolving node ids → content in rows
  const total = activityEvents.length;
  const all = activityFiltered;

  if (all.length === 0) {
    els.activityStats.textContent = `0 of ${total} loaded event${total === 1 ? '' : 's'}`;
    els.activityList.innerHTML = '<p class="subtitle">No events match these filters.</p>';
    return;
  }

  // Group by day, then collapse identical events (same op · ENGRAM · actor ·
  // detail) within each day. The engram is part of the signature, so groups
  // never merge across engrams. Count top-level items to drive auto-load.
  const byDay = new Map<string, OpLogEvent[]>();
  for (const e of all) {
    const k = activityDayLabel(e.ts);
    (byDay.get(k) ?? byDay.set(k, []).get(k)!).push(e);
  }

  let html = '';
  let topLevelItems = 0;
  for (const [day, dayEvents] of byDay) {
    html += `<p class="activity-day-divider">${escape(day)}</p>`;
    const groups = new Map<string, OpLogEvent[]>();
    const order: string[] = [];
    for (const e of dayEvents) {
      const sig = activitySig(e);
      if (!groups.has(sig)) { groups.set(sig, []); order.push(sig); }
      groups.get(sig)!.push(e);
    }
    for (const sig of order) {
      const evs = groups.get(sig)!;
      html += evs.length > 1 ? renderActivityGroup(evs) : renderActivityRow(evs[0]);
      topLevelItems++;
    }
  }

  const scope = activityCat === 'all' ? '' : ` · ${ACTIVITY_CAT_LABELS[activityCat]} only`;
  els.activityStats.textContent = `${topLevelItems} group${topLevelItems === 1 ? '' : 's'} · ${all.length} event${all.length === 1 ? '' : 's'} loaded${scope}`;

  if (activityHasMore && activityWindow < ACTIVITY_WINDOW_MAX) {
    html += `<button id="activity-load-more" class="activity-load-more" type="button">↓ Load ${ACTIVITY_WINDOW_STEP} more…</button>`;
  } else if (activityWindow >= ACTIVITY_WINDOW_MAX && activityHasMore) {
    html += `<p class="subtitle" style="text-align:center; padding:10px;">Showing the most recent ${ACTIVITY_WINDOW_MAX.toLocaleString()} — filter by a category or engram to dig deeper.</p>`;
  }
  els.activityList.innerHTML = html;

  document.getElementById('activity-load-more')?.addEventListener('click', (e) => {
    const btn = e.currentTarget as HTMLButtonElement;
    btn.innerHTML = '<span class="activity-spinner"></span> Loading…';
    btn.disabled = true;
    loadMoreActivity();
  });
  els.activityList.querySelectorAll<HTMLButtonElement>('.activity-group-head').forEach((h) => {
    h.addEventListener('click', () => h.closest('.activity-group')?.classList.toggle('open'));
  });
}

function renderActivityRow(e: OpLogEvent): string {
  const detail = activityDetail(e);
  return `<div class="activity-row">
    <span class="ar-when">${escape(activityTime(e.ts))}</span>
    <span class="ar-dot ${e.op}"></span>
    <div>
      <div>${activityLabel(e)} ${actorBadge(activityActor(e))}</div>
      ${detail ? `<div class="ar-detail" data-pres="node:${escape(e.target.id)}" data-pres-engram="${escape(e.graphId)}"${presSourceAttr(e.target.kind === 'source' ? e.target.id : e.targetSourceId)}>${detail}</div>` : ''}
    </div>
  </div>`;
}

/** Collapsed-by-default box for N identical same-day events. */
/** Per-event descriptor for an expanded subrow — the specific thing each
 *  (otherwise-identical) event touched: the source filename, the corrected
 *  content, the edge endpoints + type, etc. Falls back to the target id. */
function activitySubrowDesc(e: OpLogEvent): string {
  const a = (e.after ?? {}) as Record<string, unknown>;
  const b = (e.before ?? {}) as Record<string, unknown>;
  const clip = (s: string, n: number): string => escape(s.length > n ? s.slice(0, n) + '…' : s);
  if (e.op === 'ingestSource') {
    const ref = a['ref'] as string | undefined;
    return ref ? `<span class="ar-sub-name">${clip(ref, 110)}</span>` : `<code>${escape(e.target.id.slice(0, 16))}…</code>`;
  }
  if (e.op === 'forgetSource') {
    const ref = (b['ref'] ?? a['ref']) as string | undefined;
    return ref ? `<span class="ar-sub-name">${clip(ref, 110)}</span>` : `<code>${escape(e.target.id.slice(0, 16))}…</code>`;
  }
  // Resolve a node id → content preview. Prefer the server-side `resolved`
  // block (works for ANY engram), then the client-side cache (only the open
  // engram), then fall back to the truncated id.
  const nodeRef = (id: string | undefined, max = 70, resolved?: string): string => {
    const p = resolved ?? (id ? nodePreview(id) : undefined);
    if (p) return `<span class="ar-sub-name">“${clip(p, max)}”</span>`;
    return id ? `<code>${escape(id.slice(0, 12))}…</code>` : '';
  };
  if (e.op === 'addNode') {
    return nodeRef(e.target.id, 120, e.resolved?.target);
  }
  if (e.op === 'editNode' || e.op === 'supersede') {
    const content = (a['content'] as string | undefined) ?? e.resolved?.target ?? nodePreview(e.target.id) ?? undefined;
    if (content) return `<span class="ar-sub-name">“${clip(content, 140)}”</span>`;
    const reason = a['reason'] as string | undefined;
    if (reason) return `<span class="ar-why">${escape(humanizeReason(reason))}</span>`;
  }
  if (e.op === 'deleteNode') {
    const preview = (b['preview'] as string | undefined) ?? e.resolved?.target ?? nodePreview(e.target.id) ?? undefined;
    if (preview) return `<span class="ar-sub-name">was: “${clip(preview, 130)}”</span>`;
    const reason = a['reason'] as string | undefined;
    if (reason) return `<span class="ar-why">${escape(humanizeReason(reason))}</span>`;
  }
  if (e.op === 'addEdge' || e.op === 'deleteEdge') {
    const type = a['type'] as string | undefined;
    const from = a['fromNodeId'] as string | undefined;
    const to = a['toNodeId'] as string | undefined;
    const reason = a['reason'] as string | undefined;
    const parts: string[] = [];
    if (type) parts.push(`<span class="ar-kind">${escape(type)}</span>`);
    if (from && to) parts.push(`${nodeRef(from, 46, e.resolved?.from)} → ${nodeRef(to, 46, e.resolved?.to)}`);
    if (reason) parts.push(`<span class="ar-why">${escape(humanizeReason(reason))}</span>`);
    if (parts.length) return parts.join(' · ');
  }
  return `<code>${escape(e.target.id.slice(0, 18))}…</code>`;
}

/** Full (untruncated) plain-text descriptor for a subrow's hover tooltip. */
function activitySubrowTitle(e: OpLogEvent): string {
  const a = (e.after ?? {}) as Record<string, unknown>;
  const full = (id: string | undefined, resolved?: string): string => resolved ?? (id ? (nodePreview(id) ?? id) : '');
  if (e.op === 'addEdge' || e.op === 'deleteEdge') {
    const from = full(a['fromNodeId'] as string | undefined, e.resolved?.from);
    const to = full(a['toNodeId'] as string | undefined, e.resolved?.to);
    const reason = a['reason'] as string | undefined;
    return `From: ${from}\nTo: ${to}${reason ? `\nWhy: ${humanizeReason(reason)}` : ''}`;
  }
  if (e.op === 'ingestSource' || e.op === 'forgetSource') {
    const ref = (a['ref'] ?? (e.before as Record<string, unknown> | undefined)?.['ref']) as string | undefined;
    return ref ?? e.target.id;
  }
  return full(e.target.id, e.resolved?.target) || e.target.id;
}

function renderActivityGroup(evs: OpLogEvent[]): string {
  const e = evs[0];
  // Group head uses the grouping-stable detail (reason/confidence only) since
  // the N events differ in per-item content — that lives in the subrows.
  const detail = activityDetail(e, { forGrouping: true });
  const last = activityTime(evs[0].ts);
  const first = activityTime(evs[evs.length - 1].ts);
  const range = first === last ? last : `${first}–${last}`;
  const children = evs.map((x) => `<div class="activity-subrow" title="${escape(activitySubrowTitle(x))}"><span class="ar-when">${escape(activityTime(x.ts))}</span><span class="activity-subrow-desc" data-pres="node:${escape(x.target.id)}" data-pres-engram="${escape(x.graphId)}"${presSourceAttr(x.target.kind === 'source' ? x.target.id : x.targetSourceId)}>${activitySubrowDesc(x)}</span></div>`).join('');
  return `<div class="activity-group">
    <button class="activity-group-head" type="button">
      <span class="ar-when">${escape(range)}</span>
      <span class="ar-dot ${e.op}"></span>
      <div class="activity-group-main">
        <div>${activityLabel(e)} ${actorBadge(activityActor(e))} <span class="activity-group-count">×${evs.length}</span></div>
        <div class="ar-detail">${evs.length} identical events${detail ? ` · <span data-pres="node:${escape(e.target.id)}" data-pres-engram="${escape(e.graphId)}"${presSourceAttr(e.target.kind === 'source' ? e.target.id : e.targetSourceId)}>${detail}</span>` : ''} — tap to expand</div>
      </div>
      <span class="activity-group-chevron" aria-hidden="true">▾</span>
    </button>
    <div class="activity-group-children">${children}</div>
  </div>`;
}

function activityLabel(e: OpLogEvent): string {
  // Show the friendly engram name, not the raw slug. Fall back to the slug
  // only if the engram isn't loaded (engramName handles that).
  const inEngram = ` in <span class="ar-engram" data-pres="engram:${escape(e.graphId)}">${escape(engramName(e.graphId))}</span>`;
  const a = (e.after ?? {}) as Record<string, unknown>;
  switch (e.op) {
    case 'ingestSource': {
      const ref = typeof a['ref'] === 'string' ? a['ref'] as string : 'source';
      const file = ref.split('/').pop() ?? ref;
      const count = Array.isArray(a['nodeIds']) ? (a['nodeIds'] as unknown[]).length : 0;
      const kind = typeof a['kind'] === 'string' ? ` <span class="ar-kind">${escape(a['kind'] as string)}</span>` : '';
      return `Ingested <strong data-pres="source:${escape(e.target.id)}" data-pres-engram="${escape(e.graphId)}">${escape(file)}</strong>${kind} <span class="ar-quiet">+${count} node${count === 1 ? '' : 's'}</span>${inEngram}`;
    }
    case 'forgetSource': {
      const ref = typeof a['ref'] === 'string' ? (a['ref'] as string) : ((e.before as Record<string, unknown> | undefined)?.['ref'] as string | undefined);
      const nc = (e.before as Record<string, unknown> | undefined)?.['nodeCount'];
      const file = ref ? (ref.split('/').pop() ?? ref) : `${e.target.id.slice(0, 12)}…`;
      return `Forgot source <strong data-pres="source:${escape(e.target.id)}" data-pres-engram="${escape(e.graphId)}">${escape(file)}</strong>${typeof nc === 'number' ? ` <span class="ar-quiet">(${nc} node${nc === 1 ? '' : 's'})</span>` : ''}${inEngram}`;
    }
    case 'editNode':   return `Corrected a memory${inEngram}`;
    case 'supersede':  return `Replaced a memory with a corrected version${inEngram}`;
    case 'addNode':    return `Added a memory node${inEngram}`;
    case 'deleteNode': return `Soft-deleted a memory${inEngram}`;
    case 'addEdge': {
      const t = typeof a['type'] === 'string' ? ` <span class="ar-kind">${escape(a['type'] as string)}</span>` : '';
      return `Linked two memories${t}${inEngram}`;
    }
    case 'deleteEdge': return `Unlinked two memories${inEngram}`;
    case 'merge':      return `Merged duplicate memories${inEngram}`;
    default:           return `${escape(e.op)}${inEngram}`;
  }
}

/** The "why / what changed" line — pulled from the op's before/after payload. */
function activityDetail(e: OpLogEvent, opts?: { forGrouping?: boolean }): string {
  const a = (e.after ?? {}) as Record<string, unknown>;
  const b = (e.before ?? {}) as Record<string, unknown>;
  const bits: string[] = [];
  const reason = (a['reason'] ?? b['reason']) as string | undefined;
  if (reason) bits.push(`<span class="ar-why">${escape(humanizeReason(reason))}</span>`);
  // Per-item content (the specific node touched) is omitted in `forGrouping`
  // mode so N events with different content still collapse into one ×N group;
  // the expanded subrows (activitySubrowDesc) carry each item's content. It's
  // shown on single (ungrouped) rows and on every subrow.
  if (!opts?.forGrouping) {
    const content = (a['content'] as string | undefined) ?? (e.op === 'editNode' || e.op === 'supersede' ? e.resolved?.target : undefined);
    if (content && (e.op === 'editNode' || e.op === 'supersede')) {
      bits.push(`“${escape(content.slice(0, 120))}${content.length > 120 ? '…' : ''}”`);
    }
    const preview = (b['preview'] as string | undefined) ?? (e.op === 'deleteNode' ? e.resolved?.target : undefined);
    if (preview && (e.op === 'deleteNode' || e.op === 'forgetSource')) {
      bits.push(`was: “${escape(preview.slice(0, 100))}${preview.length > 100 ? '…' : ''}”`);
    }
    if (e.op === 'addNode' && e.resolved?.target) {
      bits.push(`“${escape(e.resolved.target.slice(0, 120))}${e.resolved.target.length > 120 ? '…' : ''}”`);
    }
  }
  if (typeof a['confidence'] === 'number') bits.push(`confidence → ${(a['confidence'] as number).toFixed(2)}`);
  return bits.join(' · ');
}

// Category chips → filter the cached events (no re-fetch).
els.activityChips.addEventListener('click', (e) => {
  const chip = (e.target as HTMLElement).closest<HTMLButtonElement>('.g-activity-chip');
  if (!chip) return;
  activityCat = (chip.dataset.cat ?? 'all') as ActivityCat;
  // Category is now a SERVER-side filter (so a rare type pulls from the full
  // op-log, not the recent window) — refetch with the new ops, reset paging.
  activityWindow = ACTIVITY_WINDOW_START;
  void refreshActivityView();
});
// Text filter + engram scope → also re-filter the cache live.
let activitySearchTimer: number | null = null;
els.activitySearch.addEventListener('input', () => {
  if (activitySearchTimer !== null) clearTimeout(activitySearchTimer);
  activitySearchTimer = window.setTimeout(() => applyActivityFilter(), 120);
});
els.activityEngramSelect.addEventListener('change', () => applyActivityFilter());
els.activityActorSelect.addEventListener('change', () => { activityWindow = ACTIVITY_WINDOW_START; void refreshActivityView(); });
// Date range changes the fetch window (since/until) → re-fetch from the op-log.
els.activityDateFrom.addEventListener('change', () => { activityWindow = ACTIVITY_WINDOW_START; void refreshActivityView(); });
els.activityDateTo.addEventListener('change', () => { activityWindow = ACTIVITY_WINDOW_START; void refreshActivityView(); });
// Hour-of-day is a client-side narrowing of the already-fetched set.
els.activityHourFrom.addEventListener('change', () => applyActivityFilter());
els.activityHourTo.addEventListener('change', () => applyActivityFilter());
els.activityDateClear.addEventListener('click', () => {
  els.activityDateFrom.value = '';
  els.activityDateTo.value = '';
  els.activityHourFrom.value = '';
  els.activityHourTo.value = '';
  activityWindow = ACTIVITY_WINDOW_START;
  void refreshActivityView();
});
// Refresh re-fetches from the sidecar (picks up new events).
els.btnActivityRefresh.addEventListener('click', () => void refreshActivityView());

// ── Snapshots ────────────────────────────────────────────────────────

els.btnSnapshotsOpen.addEventListener('click', () => {
  els.snapshotsModal.classList.remove('hidden');
  els.snapshotsNote.textContent = '';
  void refreshSnapshots();
});
els.btnSnapshotsClose.addEventListener('click', () => {
  els.snapshotsModal.classList.add('hidden');
});
els.btnSnapshotsCreate.addEventListener('click', async () => {
  els.btnSnapshotsCreate.disabled = true;
  els.btnSnapshotsCreate.textContent = 'Snapshotting…';
  els.snapshotsNote.textContent = '';
  try {
    const r = (await invoke('create_snapshot')) as { id: string; sizeBytes: number; fileCount: number };
    els.snapshotsNote.textContent = `Snapshot ${r.id} created — ${r.fileCount} files, ${formatBytes(r.sizeBytes)}.`;
    await refreshSnapshots();
  } catch (e) {
    els.snapshotsNote.textContent = `Snapshot failed: ${e}`;
  } finally {
    els.btnSnapshotsCreate.disabled = false;
    els.btnSnapshotsCreate.textContent = 'Create snapshot now';
  }
});

async function refreshSnapshots(): Promise<void> {
  els.snapshotsBody.innerHTML = '<p class="subtitle">Loading…</p>';
  try {
    const r = (await invoke('list_snapshots')) as { snapshots: SnapshotInfo[] };
    if (r.snapshots.length === 0) {
      els.snapshotsBody.innerHTML = `
        <p class="subtitle">No snapshots yet.</p>
        <p class="subtitle" style="margin-top: 8px; font-size: 15px;">
          Snapshots are useful before a risky re-ingest, a big batch of corrections,
          or any change you might want to undo. They live in <code>&lt;cortex&gt;/.snapshots/</code>
          and stay encrypted.
        </p>`;
      return;
    }
    els.snapshotsBody.innerHTML = r.snapshots.map((s) => `
      <div class="snapshot-row" style="display:flex; align-items:center; gap:12px; padding:8px 0;">
        <div style="flex:1; min-width:0;">
          <div style="overflow:hidden; text-overflow:ellipsis;"><code data-pres="surface:__snapshots__">${escape(s.id)}</code></div>
          <div class="snapshot-meta">${escape(new Date(s.createdAt).toLocaleString())}</div>
        </div>
        <div class="snapshot-meta">${s.fileCount} files</div>
        <div class="snapshot-meta">${formatBytes(s.sizeBytes)}</div>
        <button class="btn-sm btn-snapshot-restore" data-snap-id="${escape(s.id)}" title="Replace the current engrams with this snapshot. A new safety snapshot is taken first.">Restore</button>
        <button class="btn-sm btn-snapshot-delete" data-snap-id="${escape(s.id)}" title="Permanently delete this snapshot.">Delete</button>
      </div>
    `).join('');
    // Wire Restore + Delete buttons (delegated per-row would also work; this
    // is more explicit and the list isn't huge).
    els.snapshotsBody.querySelectorAll<HTMLButtonElement>('.btn-snapshot-restore').forEach((btn) => {
      btn.addEventListener('click', async () => {
        const label = btn.dataset['snapId'] ?? '';
        if (!label) return;
        if (!confirm(
          `Restore engrams from snapshot "${label}"?\n\n` +
          `This REPLACES the current .gai files with the snapshot's copies. ` +
          `A fresh safety snapshot of the current state is taken first, so this ` +
          `action is itself reversible.\n\n` +
          `Engrams will reload from the restored disk state on next access.`,
        )) return;
        btn.disabled = true;
        btn.textContent = 'Restoring…';
        try {
          const result = await ipcCall<{ ok: boolean; restored: number; safetySnapshot: string }>('snapshots:restore', { label });
          els.snapshotsNote.textContent = result.ok
            ? `Restored ${result.restored} engram(s). Safety snapshot created.`
            : 'Restore failed.';
          await refreshSnapshots();
        } catch (e) {
          els.snapshotsNote.textContent = `Restore failed: ${(e as Error).message ?? e}`;
          btn.disabled = false;
          btn.textContent = 'Restore';
        }
      });
    });
    els.snapshotsBody.querySelectorAll<HTMLButtonElement>('.btn-snapshot-delete').forEach((btn) => {
      btn.addEventListener('click', async () => {
        const label = btn.dataset['snapId'] ?? '';
        if (!label) return;
        if (!confirm(`Permanently delete snapshot "${label}"? This cannot be undone.`)) return;
        btn.disabled = true;
        try {
          await ipcCall('snapshots:delete', { label });
          await refreshSnapshots();
        } catch (e) {
          els.snapshotsNote.textContent = `Delete failed: ${(e as Error).message ?? e}`;
          btn.disabled = false;
        }
      });
    });
  } catch (e) {
    els.snapshotsBody.innerHTML = `<p class="error">${escape(String(e))}</p>`;
  }
}

function formatBytes(n: number): string {
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  if (n < 1024 * 1024 * 1024) return `${(n / 1024 / 1024).toFixed(1)} MB`;
  return `${(n / 1024 / 1024 / 1024).toFixed(2)} GB`;
}

// Atlas perf A/B harness — exposes `atlasPerfApply()` to DevTools so you
// can flip a flag and immediately see the effect on the live graph.
// `globalThis.atlasPerf` is defined in atlas.ts with the flag defaults.
globalThis.atlasPerfApply = (): void => {
  mainAtlas?.reapplyPerfFlags();
};

// Tray-driven status updates push us into the right view in real time.
void listen<StatusSnapshot>('graphnosis://status', (evt) => render(evt.payload));

// Sidecar startup progress — shown in the lock screen while the cortex loads.
// Each event carries a step name and a human-readable detail string.
// We show it while the unlock-progress bar is visible and clear it on success.
void listen<{ step: string; detail: string }>('graphnosis://sidecar-boot-status', (evt) => {
  const { step, detail } = evt.payload;
  els.bootStatusText.textContent = detail;
  els.unlockStatus.classList.remove('hidden');
  if (step === 'ready') {
    // Socket is up — hide the status line shortly after, BUT only if the
    // boot sequence hasn't already taken over (unlockPending = true means
    // render() has started its own status messages — don't stomp on them).
    setTimeout(() => {
      if (!unlockPending) els.unlockStatus.classList.add('hidden');
    }, 1200);
  }
});

// ── Atlas render-loop power management ──────────────────────────────
//
// Three.js (via 3d-force-graph) runs its WebGL render loop at 60fps
// regardless of whether the window is visible. For a 2000+ node graph
// with active physics that's a constant ~5-15% CPU drain on every
// machine, every second the App is open — including while the user is
// on another desktop space, has the app minimized, or has the App
// window unfocused behind another window.
//
// We pause the loop on visibilitychange (whole window hidden) and on
// window blur (focus moved to another app). Resume on visibility +
// focus. Together these cover macOS Mission Control / window minimize,
// Cmd-Tabbing away, lock screen, and switching to another Space.
//
// Side effect: when the App is the active window but the user has
// navigated to a non-Atlas pane (e.g., Sources), the renderer keeps
// running. Not worth additional plumbing — the pane-switching case
// is rare and brief compared to "window not focused for hours."

if (typeof document !== 'undefined') {
  document.addEventListener('visibilitychange', () => {
    if (document.hidden) mainAtlas?.pauseAnimation();
    else mainAtlas?.resumeAnimation();
  });
}
if (typeof window !== 'undefined') {
  window.addEventListener('blur', () => mainAtlas?.pauseAnimation());
  window.addEventListener('focus', () => mainAtlas?.resumeAnimation());
}

// ── Activity log ───────────────────────────────────────────────────

type ActivityOpKind = 'addNode' | 'editNode' | 'deleteNode' | 'addEdge' | 'deleteEdge'
  | 'supersede' | 'merge' | 'ingestSource' | 'forgetSource' | 'ingestGroup';

interface ActivityEntry {
  id: string;
  ts: number;
  op: ActivityOpKind;
  target: { kind: string; id: string };
  preview?: string;
  sourceRef?: string;
  nodeCount?: number;
  triggeredBy?: string;
  nodes?: Array<{ id: string; ts: number; target: { kind: string; id: string }; preview?: string }>;
}

interface ActivityLogResult {
  entries: ActivityEntry[];
  total: number;
  hasMore: boolean;
}

const ACTIVITY_PAGE_SIZE = 20;
let activityFilter: string = 'all';
let activitySearch: string = '';
let activityOffset: number = 0;
let activityEntries: ActivityEntry[] = [];
let activityScrollObserver: IntersectionObserver | null = null;

/** Map op kind → filter category */
function opToFilter(op: ActivityOpKind): string {
  if (op === 'ingestSource' || op === 'addNode' || op === 'ingestGroup') return 'add';
  if (op === 'editNode' || op === 'supersede') return 'edit';
  if (op === 'deleteNode' || op === 'forgetSource') return 'delete';
  if (op === 'addEdge' || op === 'deleteEdge') return 'edge';
  return 'add';
}

/** Icon + CSS class for each op */
function opMeta(op: ActivityOpKind): { icon: string; cls: string; label: string } {
  switch (op) {
    case 'ingestGroup':   return { icon: '↓', cls: 'op-add',    label: 'Ingested' };
    case 'ingestSource':  return { icon: '↓', cls: 'op-add',    label: 'Ingested' };
    case 'addNode':       return { icon: '+', cls: 'op-add',    label: 'Node added' };
    case 'editNode':      return { icon: '✎', cls: 'op-edit',   label: 'Edited' };
    case 'supersede':     return { icon: '↻', cls: 'op-edit',   label: 'Corrected' };
    case 'deleteNode':    return { icon: '−', cls: 'op-delete', label: 'Node deleted' };
    case 'forgetSource':  return { icon: '✕', cls: 'op-delete', label: 'Forgotten' };
    case 'addEdge':       return { icon: '⟵', cls: 'op-edge',   label: 'Edge added' };
    case 'deleteEdge':    return { icon: '⟶', cls: 'op-edge',   label: 'Edge removed' };
    default:              return { icon: '·', cls: 'op-edit',   label: op };
  }
}

function relativeTime(ts: number): string {
  const diff = Date.now() - ts;
  const s = Math.floor(diff / 1000);
  if (s < 60) return 'just now';
  const m = Math.floor(s / 60);
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  if (d < 7) return `${d}d ago`;
  return new Date(ts).toLocaleDateString();
}

function triggeredByLabel(tb: string | undefined): { text: string; cls: string } | null {
  if (!tb) return null;
  if (tb.startsWith('mcp:'))       return { text: `Claude · ${tb.slice(4)}`, cls: 'tb-mcp' };
  if (tb.startsWith('brain:'))     return { text: `Brain · ${tb.slice(6)}`, cls: 'tb-brain' };
  if (tb.startsWith('connector:')) return { text: `Connector${tb.length > 10 ? ': ' + tb.slice(10) : ''}`, cls: 'tb-connector' };
  if (tb.startsWith('user:'))      return { text: 'You', cls: '' };
  return { text: tb, cls: '' };
}

function renderActivityEntry(e: ActivityEntry): string {
  const { icon, cls, label } = opMeta(e.op);
  const nodeCountBadge = e.nodeCount != null
    ? ` <span style="font-weight:400;opacity:0.7">· ${e.nodeCount} node${e.nodeCount === 1 ? '' : 's'}</span>`
    : '';
  const preview = e.preview
    ? `<div class="g-activity-preview">${escHtml(truncate(e.preview, 180))}</div>` : '';
  const tb = triggeredByLabel(e.triggeredBy);
  const tbBadge = tb
    ? `<span class="g-activity-triggered ${tb.cls}">${escHtml(tb.text)}</span>` : '';
  const sourceRefSpan = e.sourceRef
    ? `<span class="g-activity-meta-sep">·</span><span>${escHtml(truncate(e.sourceRef, 36))}</span>` : '';

  const expandId = `act-nodes-${escHtml(e.id)}`;
  const expandBtn = (e.nodes?.length)
    ? `<button class="g-activity-expand-btn" onclick="
        const el=document.getElementById('${expandId}');
        if(el){el.hidden=!el.hidden;this.textContent=el.hidden?'▸ ${e.nodeCount ?? e.nodes.length} nodes':'▾ Hide nodes';}
       ">▸ ${e.nodeCount ?? e.nodes.length} nodes</button>`
    : '';
  const nodeRows = (e.nodes?.length)
    ? `<div id="${expandId}" class="g-activity-nodes" hidden>${
        e.nodes.slice(0, 10).map(n =>
          `<div class="g-activity-node-row">${escHtml(truncate(n.preview ?? n.target.id, 120))}</div>`
        ).join('') +
        (e.nodes.length > 10 ? `<div class="g-activity-node-row" style="opacity:0.45">…and ${e.nodes.length - 10} more</div>` : '')
      }</div>`
    : '';

  // "Open in Sources" action for ingest rows with a known source ref
  const openSourceBtn = (e.op === 'ingestGroup' || e.op === 'ingestSource') && e.sourceRef
    ? `<button class="g-activity-action" data-action="open-source" data-source-ref="${escHtml(e.sourceRef)}">Open in Sources ↗</button>`
    : '';

  return `<div class="g-activity-entry">
    <span class="g-activity-icon ${cls}">${icon}</span>
    <div class="g-activity-body">
      <div class="g-activity-top">
        <span class="g-activity-label">${escHtml(label)}${nodeCountBadge}</span>
        <span class="g-activity-time">${relativeTime(e.ts)}</span>
      </div>
      ${preview}
      ${expandBtn}${nodeRows}
      ${openSourceBtn}
      <div class="g-activity-meta">${tbBadge}${sourceRefSpan}</div>
    </div>
  </div>`;
}

function escHtml(s: string): string {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function truncate(s: string, max: number): string {
  return s.length > max ? s.slice(0, max - 1) + '…' : s;
}

function activitySetupScrollObserver(): void {
  // Disconnect any previous observer before creating a new one.
  activityScrollObserver?.disconnect();
  activityScrollObserver = null;

  const sentinel = els.gActivityList.querySelector<HTMLDivElement>('.g-activity-sentinel');
  if (!sentinel) return;

  activityScrollObserver = new IntersectionObserver(
    (entries) => {
      if (entries[0]?.isIntersecting) {
        void refreshActivityLog(false);
      }
    },
    { root: els.gActivityList, threshold: 0.1 },
  );
  activityScrollObserver.observe(sentinel);
}

async function refreshActivityLog(reset = false): Promise<void> {
  if (!atlasActiveGraph) return;
  if (reset) {
    activityScrollObserver?.disconnect();
    activityScrollObserver = null;
    activityOffset = 0;
    activityEntries = [];
  }

  const ops: string[] = activityFilter === 'all' ? [] :
    activityFilter === 'add'    ? ['add'] :
    activityFilter === 'edit'   ? ['edit'] :
    activityFilter === 'delete' ? ['delete'] :
    activityFilter === 'edge'   ? ['edge'] : [];

  let result: ActivityLogResult;
  try {
    result = await ipcCall<ActivityLogResult>('activity.log', {
      graphId: atlasActiveGraph,
      limit: ACTIVITY_PAGE_SIZE,
      offset: activityOffset,
      ops: ops.length ? ops : undefined,
      search: activitySearch.trim() || undefined,
    });
  } catch {
    if (reset) {
      els.gActivityList.innerHTML = '<p class="subtitle" style="padding:16px 0;text-align:center">Could not load activity log.</p>';
    }
    return;
  }

  if (reset) activityEntries = result.entries;
  else activityEntries = [...activityEntries, ...result.entries];

  if (activityEntries.length === 0) {
    els.gActivityList.innerHTML = '<p class="subtitle" style="padding:16px 0;text-align:center">No activity recorded yet.</p>';
    return;
  }

  activityOffset += result.entries.length;

  // Append new rows (on reset, rebuild everything).
  if (reset) {
    els.gActivityList.innerHTML = activityEntries.map(renderActivityEntry).join('');
  } else {
    // Remove existing sentinel before appending new rows.
    els.gActivityList.querySelector('.g-activity-sentinel')?.remove();
    const frag = document.createDocumentFragment();
    const tmp = document.createElement('div');
    tmp.innerHTML = result.entries.map(renderActivityEntry).join('');
    while (tmp.firstChild) frag.appendChild(tmp.firstChild);
    els.gActivityList.appendChild(frag);
  }

  // Append scroll sentinel if there are more items.
  if (result.hasMore) {
    const sentinel = document.createElement('div');
    sentinel.className = 'g-activity-sentinel';
    els.gActivityList.appendChild(sentinel);
    activitySetupScrollObserver();
  }
}

// Event delegation for action buttons inside the list (survives innerHTML rebuilds).
els.gActivityList.addEventListener('click', (e) => {
  const btn = (e.target as HTMLElement).closest<HTMLButtonElement>('[data-action]');
  if (!btn) return;
  if (btn.dataset['action'] === 'open-source') {
    const ref = btn.dataset['sourceRef'] ?? '';
    if (ref) {
      // Pre-fill the sources filter and navigate to Sources pane.
      sourcesFilterTerm = ref;
      els.sourcesFilter.value = ref;
      activateMode('sources');
    }
  }
});

// Wire filter chips
document.querySelectorAll<HTMLButtonElement>('.g-activity-chip').forEach((btn) => {
  btn.addEventListener('click', () => {
    document.querySelectorAll('.g-activity-chip').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    activityFilter = btn.dataset['filter'] ?? 'all';
    void refreshActivityLog(true);
  });
});

// Wire search (debounced)
{
  let searchTimer: ReturnType<typeof setTimeout> | null = null;
  els.gActivitySearch.addEventListener('input', () => {
    if (searchTimer) clearTimeout(searchTimer);
    searchTimer = setTimeout(() => {
      activitySearch = els.gActivitySearch.value;
      void refreshActivityLog(true);
    }, 280);
  });
}

// ── Mutation push-channel ───────────────────────────────────────────
//
// The sidecar broadcasts a `graphnosis://graph-mutation` Tauri event
// every time any graph is mutated (ambient ingest, MCP `remember`,
// auto-relink, user corrections). We delegate the refresh work to
// `pollGraphMutations` — same function the 3s timer calls — so the
// push path and the poll path share one ground-truth refresh
// sequence (reload data, re-render dashboard/atlas/detail, update
// recap, update forgotten row).
//
// Three layers of staleness defence:
//   1. Push events  → sub-second updates when everything's healthy
//   2. 3s poll      → catches dropped events (backpressure, socket
//                     reconnect race)
//   3. Hello frame  → catches sidecar-restart drift (events emitted
//                     between sidecar relock and our reconnect)
//
// `pollGraphMutations` itself maintains the canonical
// `lastSeenMutationAt` cursor, so the push path doesn't need its own
// state — calling it is idempotent if the cursor hasn't advanced.

interface GraphMutationPayload {
  graphId: string;
  ts: number;
  /** Optional partial training-output chunk. Set when graphId matches the
   *  `__skill_train_chunk__<streamId>` pattern broadcast by skill:train. */
  chunk?: string;
  /** Optional per-operation status label. Set on `__skill_train_status__`
   *  frames — a short, generic, non-sensitive description of the current
   *  training step for the status bar. */
  label?: string;
}

interface EventStreamConnectedPayload {
  ts: number;
  cursor: Record<string, number>;
}

// Per-source live-ingest delta. The sidecar pushes just the NEW source's nodes
// as each source finishes ingesting — we append them to the active engram's
// cache and push INCREMENTALLY (existing nodes pinned → no re-heat) with NO full
// re-fetch, so the 3D graph grows source-by-source. The 3s poll still reconciles
// to the authoritative full set.
interface GraphDeltaPayload { graphId: string; sourceId: string; nodes: NodeRecord[] }
void listen<GraphDeltaPayload>('graphnosis://graph-delta', (evt) => {
  const d = evt.payload;
  // Only when we're watching this exact engram in 3D — and not in the
  // deferred-import holding state (that does a full render when the import ends).
  if (!d || d.graphId !== atlasActiveGraph || currentMode !== 'engram') return;
  if (deferredAtlasLoadGraph === d.graphId) return;
  const existing = new Set(graphnosisAllNodes.map((n) => n.id));
  let added = 0;
  for (const n of d.nodes) {
    if (existing.has(n.id)) continue;
    graphnosisAllNodes.push({ ...n, sourceId: d.sourceId, _graphId: d.graphId } as NodeRecord);
    existing.add(n.id);
    added++;
  }
  if (added === 0) return;
  graphnosisGlobalNodes.set(d.graphId, graphnosisAllNodes);
  if (shouldPushAtlasNow()) pushDataIntoAtlas(false, true); // incremental → no re-heat, no re-fetch
});

void listen<GraphMutationPayload>('graphnosis://graph-mutation', (evt) => {
  const graphId = evt.payload.graphId ?? '';
  // Skill-trainer streaming frames hitch a ride on the graph-mutation
  // channel. Three frame types — start/chunk/done — distinguished by
  // the graphId prefix. The payload's `chunk` field carries the actual
  // partial output text on chunk frames.
  if (graphId.startsWith('__skill_train_')) {
    handleSkillTrainFrame(graphId, evt.payload);
    return;
  }
  if (graphId.startsWith('__brain')) {
    handleBrainFrame(graphId);
    return;
  }
  // Don't filter on graphId here — pollGraphMutations checks the
  // active-engram-changed predicate against the full cursor set
  // returned by inspector_stats and only repaints when relevant.
  void pollGraphMutations();
  // Live-refresh the Activity Log if the Status pane is open and the
  // mutation targets the currently displayed engram.
  if (currentMode === 'status' && graphId === atlasActiveGraph) {
    void refreshActivityLog(true);
  }
});

// Hello frame fires once per event-stream (re)connect. Run a full
// poll to reconcile cursor drift from the gap between sidecar restart
// and our subscription being established.
void listen<EventStreamConnectedPayload>('graphnosis://event-stream-connected', () => {
  void pollGraphMutations();
});

// ── Layer-4 consent: in-app prompt (replaces phrase typing when GUI is up) ──
// Sidecar emits this when an AI client hits the consent gate AND the user's
// per-client policy says "ask". One click on the modal resolves the prompt;
// the AI's recall call proceeds (Allow) or errors cleanly (Deny). On timeout
// (no response in 60s) the sidecar falls back to phrase typing — that path
// stays alive for headless / SSH / CI setups with no desktop window.
type ConsentPromptPayload = {
  promptId: string;
  clientName: string;
  tiers: Array<'personal' | 'sensitive'>;
  /** The specific engram(s) access is requested for (per-engram consent). When
   *  present the modal names them so the user authorises exactly these. */
  engrams?: Array<{ graphId: string; name: string; tier: 'personal' | 'sensitive' }>;
  suggestedDurations: Array<{ tier: string; durationMs: number }>;
  privacyUrl: string | null;
};
// ── In-app update modal ───────────────────────────────────────────────────
// Rust emits `graphnosis://update-available` with the new version string
// immediately after updating the tray and posting the OS notification.
{
  const modal  = document.getElementById('update-available-modal');
  const verEl  = document.getElementById('update-available-version');
  const installBtn = document.getElementById('update-install-btn');
  const laterBtn   = document.getElementById('update-later-btn');

  void listen<string>('graphnosis://update-available', (evt) => {
    if (!modal) return;
    if (verEl) verEl.textContent = `Version ${evt.payload} is ready`;
    modal.classList.remove('hidden');
  });

  installBtn?.addEventListener('click', async () => {
    if (installBtn) {
      (installBtn as HTMLButtonElement).disabled = true;
      installBtn.textContent = 'Installing…';
    }
    try {
      await invoke('install_update');
      // App restarts automatically — no further UI needed.
    } catch (e) {
      if (installBtn) {
        (installBtn as HTMLButtonElement).disabled = false;
        installBtn.textContent = 'Install & Restart';
      }
      showError(`Update failed: ${e}`);
    }
  });

  laterBtn?.addEventListener('click', () => {
    modal?.classList.add('hidden');
  });
}

let activeConsentPromptId: string | null = null;
void listen<ConsentPromptPayload>('graphnosis://consent-prompt', (evt) => {
  const p = evt.payload;
  activeConsentPromptId = p.promptId;
  const titleEl = document.getElementById('consent-prompt-title');
  const subEl = document.getElementById('consent-prompt-subtitle');
  const tiersEl = document.getElementById('consent-prompt-tiers');
  const privEl = document.getElementById('consent-prompt-privacy') as HTMLAnchorElement | null;
  if (titleEl) titleEl.textContent = `${p.clientName} wants to read your memories`;
  const engrams = p.engrams ?? [];
  if (subEl) {
    // Name the specific engram(s) so the user authorises exactly these, not the
    // whole tier (per-engram consent). Fall back to tiers for older payloads.
    subEl.textContent = engrams.length
      ? `Access requested to ${engrams.length === 1 ? 'engram' : 'engrams'}: ${engrams.map((e) => e.name).join(', ')}`
      : `Access requested: ${p.tiers.join(' + ')} tier${p.tiers.length === 1 ? '' : 's'}`;
  }
  if (tiersEl) {
    tiersEl.innerHTML = engrams.length
      ? engrams.map((e) =>
          `<span class="consent-tier-pill${e.tier === 'sensitive' ? ' sensitive' : ''}">${e.tier === 'sensitive' ? '⚠ ' : ''}${escape(e.name)} <em>(${e.tier})</em></span>`,
        ).join('')
      : p.tiers.map((t) =>
          `<span class="consent-tier-pill${t === 'sensitive' ? ' sensitive' : ''}">${t === 'sensitive' ? '⚠ ' : ''}${t.toUpperCase()} tier</span>`,
        ).join('');
  }
  if (privEl) {
    if (p.privacyUrl) {
      privEl.href = p.privacyUrl;
      privEl.style.display = '';
    } else {
      privEl.style.display = 'none';
    }
  }
  document.getElementById('consent-prompt-modal')?.classList.remove('hidden');
  // Bring the window to focus so the user sees the modal even if they
  // were in the AI client when the request fired.
  window.focus();
});
async function resolveConsentPrompt(action: 'allow' | 'deny', durationMs?: number): Promise<void> {
  if (!activeConsentPromptId) return;
  const id = activeConsentPromptId;
  activeConsentPromptId = null;
  document.getElementById('consent-prompt-modal')?.classList.add('hidden');
  try {
    await ipcCall('consent.resolvePrompt', {
      promptId: id,
      action,
      ...(durationMs !== undefined ? { durationMs } : {}),
    });
  } catch (e) {
    console.error('consent.resolvePrompt failed', e);
  }
}
document.getElementById('consent-prompt-deny')?.addEventListener('click', () => void resolveConsentPrompt('deny'));
document.getElementById('consent-prompt-once')?.addEventListener('click', () => void resolveConsentPrompt('allow', 0));
document.getElementById('consent-prompt-1h')?.addEventListener('click', () => void resolveConsentPrompt('allow', 3_600_000));
document.getElementById('consent-prompt-1d')?.addEventListener('click', () => void resolveConsentPrompt('allow', 86_400_000));
// External link routed through Tauri opener — same pattern as the MCP
// Tools docs link, keeps the WebView from navigating itself.
document.getElementById('consent-prompt-privacy')?.addEventListener('click', (e) => {
  const a = e.currentTarget as HTMLAnchorElement;
  if (a.href && a.href !== '#') {
    e.preventDefault();
    void invoke('plugin:opener|open_url', { url: a.href });
  }
});

// ── First-connect policy chooser (Option 3) ─────────────────────────────────
// Pops once per never-before-seen AI client. The sidecar seeds a default
// policy at first contact; this modal lets the user override it before
// the next recall. Saving the form writes back via `ai.setClientPolicy`.
type FirstConnectPayload = {
  clientName: string;
  policy: { personalTier: string; sensitiveTier: string; firstSeenAt: number };
};
let activeFirstConnectClient: string | null = null;
void listen<FirstConnectPayload>('graphnosis://first-connect-policy', (evt) => {
  const p = evt.payload;
  activeFirstConnectClient = p.clientName;
  const titleEl = document.getElementById('first-connect-title');
  if (titleEl) titleEl.textContent = `${p.clientName} is connecting for the first time`;
  const personalSel = document.getElementById('first-connect-personal') as HTMLSelectElement | null;
  const sensitiveSel = document.getElementById('first-connect-sensitive') as HTMLSelectElement | null;
  if (personalSel) personalSel.value = p.policy.personalTier;
  if (sensitiveSel) sensitiveSel.value = p.policy.sensitiveTier;
  document.getElementById('first-connect-modal')?.classList.remove('hidden');
  window.focus();
});
document.getElementById('first-connect-save')?.addEventListener('click', () => {
  const personalSel = document.getElementById('first-connect-personal') as HTMLSelectElement | null;
  const sensitiveSel = document.getElementById('first-connect-sensitive') as HTMLSelectElement | null;
  if (!activeFirstConnectClient || !personalSel || !sensitiveSel) return;
  const clientName = activeFirstConnectClient;
  activeFirstConnectClient = null;
  document.getElementById('first-connect-modal')?.classList.add('hidden');
  void ipcCall('ai.setClientPolicy', {
    clientName,
    personalTier: personalSel.value,
    sensitiveTier: sensitiveSel.value,
  }).catch((e) => console.error('ai.setClientPolicy failed', e));
});

// Background engram loading progress. The sidecar loads the default engram
// first (~1-2s) then all others in parallel (~17-20s). We react to each event
// so the UI shows data as soon as the first engram is available, and switches
// to the session-saved engram the moment it becomes available.
/**
 * Switch the active engram in-place after boot — used by both the engrams-
 * loading handler (when the saved engram becomes available) and the post-
 * reveal catch-up check. Refreshes Check-in deck AND atlas view so the UI
 * actually reflects the new engram (not just the picker label).
 */
/** Full Cortex has no single active engram, so the per-page scope dropdowns
 *  (Search / Sources / Activity) fall back to "All engrams". Resets the
 *  selects + their filter state and re-applies whichever scoped view is live. */
function resetPageScopesForFullCortex(): void {
  searchEngramFilter = '';
  try { localStorage.removeItem('search:engramFilter'); } catch { /* storage off */ }
  if (els.gSearchEngramSelect) els.gSearchEngramSelect.value = '';
  sourcesEngramFilter = '';
  if (els.sourcesEngramSelect) els.sourcesEngramSelect.value = '';
  if (els.activityEngramSelect) els.activityEngramSelect.value = '';
  if (currentMode === 'sources') applySourcesFilter();
  if (currentMode === 'activity') applyActivityFilter();
}

async function switchActiveEngram(graphId: string): Promise<void> {
  if (atlasActiveGraph === graphId && !atlasGalaxyMode) return;
  atlasGalaxyMode = false; // leaving Full Cortex for a real engram
  atlasActiveGraph = graphId;
  persistActiveEngram(graphId);
  refreshActiveEngramLabel();
  syncEngramPicker();
  // Reset the deck to card 1 when the user deliberately switches engrams —
  // the new engram is a different dataset so the old position is meaningless.
  graphnosisDeckIndex = 0;
  // Wipe the 3D atlas IMMEDIATELY before we start loading — otherwise the
  // user sees the OLD engram's nodes while waiting for the new one, which
  // reads as "the switch didn't work" on larger graphs that take 1–3s to
  // fetch. Clearing first + showing the loading overlay makes the
  // transition feel deliberate. Cheap: setNodes([]) just drops sim state.
  if (mainAtlas) {
    mainAtlas.setNodes([]);
    mainAtlas.setEdges([], []);
  }
  // Surface the overlay only when the 3D tab is the active view. On other
  // tabs the canvas isn't visible anyway, so the overlay would be invisible
  // chrome that the user never sees.
  const friendlyName = loadedGraphs.find((g) => g.graphId === graphId)?.metadata.displayName ?? graphId;
  showAtlasLoading(friendlyName);
  try {
    await loadGraphnosisData(graphId);
    // Now we know the size — surface a count to the user so the overlay
    // feels informative on big engrams ("Loading X… 4,231 memories").
    // Tiny engrams hide before the human eye notices this text anyway.
    const n = graphnosisAllNodes.length;
    setAtlasLoadingSub(`${n.toLocaleString()} memor${n === 1 ? 'y' : 'ies'}`);
    applyGraphnosisFilter();
    // Always push the new engram's data into the 3D atlas AND fit the view,
    // even when the 3D tab isn't visible. That way when the user later
    // switches to "3D Engram", the camera is already framed on the new
    // engram instead of showing the previous engram's leftover camera
    // position. The atlas engine is a headless THREE.js scene — pushing
    // data + fitting is cheap when invisible (no rendering until visible).
    if (isAtlasPaneMode()) {
      void refreshAtlasView();
    } else if (mainAtlas) {
      pushDataIntoAtlas();
      // Let the physics warmup settle so the bounding-sphere is honest.
      setTimeout(() => mainAtlas?.zoomToFit(700, 20), 800);
    }
  } finally {
    hideAtlasLoading();
  }
}

/** Show the 3D-atlas loading overlay with a friendly label and an
 *  optional sub-line for node-count progress. Pops only if we're on the
 *  atlas-bearing tab; on other tabs the canvas isn't visible so the
 *  overlay would be invisible chrome. Idempotent. */
function showAtlasLoading(label: string, sub?: string): void {
  const overlay = document.getElementById('atlas-loading-overlay');
  if (!overlay) return;
  const labelEl = overlay.querySelector<HTMLElement>('.atlas-loading-label');
  const subEl = document.getElementById('atlas-loading-sub');
  if (labelEl) labelEl.textContent = `Loading ${label}…`;
  if (subEl) subEl.textContent = sub ?? '';
  overlay.classList.remove('hidden');
}

function hideAtlasLoading(): void {
  document.getElementById('atlas-loading-overlay')?.classList.add('hidden');
}

/** Surface a load failure on the atlas overlay with a one-click Retry, instead
 *  of silently leaving the previously-selected engram on screen. */
function showAtlasLoadError(graphId: string): void {
  const overlay = document.getElementById('atlas-loading-overlay');
  if (!overlay) return;
  const labelEl = overlay.querySelector<HTMLElement>('.atlas-loading-label');
  const subEl = document.getElementById('atlas-loading-sub');
  const spinner = overlay.querySelector<HTMLElement>('.atlas-loading-spinner');
  if (spinner) spinner.style.display = 'none';
  if (labelEl) labelEl.textContent = `Couldn’t load ${engramName(graphId)}`;
  if (subEl) {
    subEl.innerHTML = 'The engram read timed out. <button id="btn-atlas-retry" class="btn-sm" type="button">Retry</button>';
    subEl.querySelector<HTMLButtonElement>('#btn-atlas-retry')?.addEventListener('click', () => {
      if (spinner) spinner.style.display = '';
      // Re-enter the atlas tab path, which re-runs the stale guard + load.
      switchGraphnosisTab('atlas');
    });
  }
  overlay.classList.remove('hidden');
}

/** Update just the sub-line of the loading overlay — used to surface
 *  "N memories · M edges" once the IPC returns, just before the atlas
 *  paints. Caller is responsible for hideAtlasLoading() when done. */
function setAtlasLoadingSub(sub: string): void {
  const subEl = document.getElementById('atlas-loading-sub');
  if (subEl) subEl.textContent = sub;
}

// Auto-recovery from interrupted shutdown — fired by the sidecar after it
// notices one or more engrams were auto-quarantined during boot load (their
// .gai files failed integrity checks, almost always because of a force-quit
// or lid-close mid-save) and then successfully replayed the op-log to
// rebuild them. The user sees a friendly toast instead of the alarming
// "Synapse failed during startup. Most likely cause: wrong passphrase or
// a corrupted cortex file." Rust message — because the sidecar no longer
// fails startup at all in that case.
interface QuarantineRecoveredPayload {
  quarantinedEngrams: number;
  sourcesAttempted: number;
  sourcesRecovered: number;
  sourcesSkipped: number;
  sourcesFailed: number;
}
void listen<QuarantineRecoveredPayload>('graphnosis://cortex-recovered-from-quarantine', (evt) => {
  const p = evt.payload;
  const engramWord = p.quarantinedEngrams === 1 ? 'engram' : 'engrams';
  const sourceWord = p.sourcesRecovered === 1 ? 'memory' : 'memories';
  const label = `Recovered ${p.quarantinedEngrams} ${engramWord} from op-log`;
  const message = p.sourcesFailed === 0
    ? `Rebuilt ${p.sourcesRecovered} ${sourceWord} after an interrupted shutdown. Your memory is intact.`
    : `Rebuilt ${p.sourcesRecovered} ${sourceWord}, ${p.sourcesFailed} could not be recovered. The original quarantined files are in your cortex folder as .gai.corrupt-* for forensics.`;
  const id = addIngestToast(label, message);
  // Show as success unless any sources failed — in that case keep it as an
  // error so the user notices + reads the message.
  finishIngestToast(id, p.sourcesFailed === 0 ? 'success' : 'error');
});

/** Debounce handle for the engrams-loading → skills-library refresh. */
let _skillsRefreshTimer: number | null = null;

/** Most-recent engrams-loading payload that arrived while `unlockPending` was
 *  true. Used by the post-unlock catch-up to re-fire the listener logic with
 *  the latest state, so events that boot saw get reflected in the picker.
 *  Null when no events were missed. */
let _missedDuringUnlockPayload: { loaded: number; total: number } | null = null;

void listen<{ loaded: number; total: number }>('graphnosis://engrams-loading', (evt) => {
  const { loaded, total } = evt.payload;
  const remaining = total - loaded;
  const allDone = remaining <= 0;

  // Unblock any docs reingest that was waiting for loading to complete.
  if (allDone) markEngramsLoaded();

  // Status bar: always show a count so the user sees progress.
  if (els.statusSaved) {
    els.statusSaved.textContent = allDone
      ? ''
      : `Loading ${remaining} more engram${remaining === 1 ? '' : 's'}…`;
  }

  // During boot, the boot sequence owns atlasActiveGraph / loadedGraphs /
  // view refreshes. Touching them here races against the boot's awaits and
  // can either show empty data or freeze the lock screen mid-load. Record
  // the latest payload so the post-unlock catch-up can re-process it; the
  // bail itself is the same as before, just no longer silent.
  if (unlockPending) {
    _missedDuringUnlockPayload = evt.payload;
    return;
  }

  processEngramsLoadingRefresh(allDone);
});

/** Re-fetch loadedGraphs + sync UI after an engrams-loading event (or after
 *  the post-unlock catch-up flushes a missed event). Extracted so both the
 *  live listener AND the catch-up can call it. */
function processEngramsLoadingRefresh(allDone: boolean): void {
  const saved = localStorage.getItem(LAST_ENGRAM_KEY);
  void invoke<GraphWithMetadata[]>('list_graphs_with_metadata', { includeUnloaded: true }).then((graphs) => {
    loadedGraphs = graphs;
    populateStudioEngramSelects();
    if (saved && saved !== atlasActiveGraph
        && graphs.some((g) => !g.metadata.archived && g.graphId === saved && g.loaded !== false)) {
      void switchActiveEngram(saved);
      schedulePeriodicGreyedRefresh();
      return;
    }
    syncEngramPicker();
    if (allDone && isAtlasPaneMode()) void refreshAtlasView();
    if (activeStudioTool === 'skills') {
      if (_skillsRefreshTimer) clearTimeout(_skillsRefreshTimer);
      _skillsRefreshTimer = window.setTimeout(() => {
        _skillsRefreshTimer = null;
        void (async () => {
          await fetchSkillsLibrary();
          renderSkillsLibrary();
          if (allDone) void warmVitalityCache();
        })();
      }, allDone ? 0 : 350);
    }
    schedulePeriodicGreyedRefresh();
  });
}

/** Periodic catch-up: while ANY engram in loadedGraphs is still greyed
 *  (loaded === false), poll the sidecar every 5s for a fresh snapshot.
 *  Self-stops once all engrams report loaded — no recurring timer cost
 *  in steady state. Defensive against missed `engrams-loading` events:
 *  even if a broadcast is dropped (events-socket flap, etc.), the picker
 *  self-heals within 5 seconds.
 *
 *  Idempotent: calling it while a timer is already scheduled is a no-op.
 *  The single tick re-schedules itself if still needed. */
let _periodicGreyedRefreshTimer: ReturnType<typeof setTimeout> | null = null;
function schedulePeriodicGreyedRefresh(): void {
  // Obsolete under lazy-boot: loaded:false is now the normal "on disk, not
  // resident" state, not a transient "still loading at boot" — there's no
  // background load to poll for, so this must NOT spin a 5s timer forever (it
  // would never self-terminate now that some engram is always unloaded). The
  // picker lists every engram regardless, and loaded-state refreshes when an
  // engram is selected (switch flow) or evicted. No-op; clear any stray timer.
  if (_periodicGreyedRefreshTimer !== null) {
    clearTimeout(_periodicGreyedRefreshTimer);
    _periodicGreyedRefreshTimer = null;
  }
}

// ── Sidecar IPC helper ────────────────────────────────────────────────────
// Generic pass-through to the sidecar's IPC dispatch via the Tauri command
// `sidecar_ipc_call`. Used for brain and LLM methods.
async function ipcCall<T = unknown>(method: string, params: unknown): Promise<T> {
  return invoke<T>('sidecar_ipc_call', { method, params });
}

// ipcCall with a hard client-side deadline. The base ipcCall can hang
// indefinitely if a heavy sidecar call (a full-graph walk, a huge op-log
// slice) is slow — leaving Home cards stuck on their skeletons forever. Home's
// non-critical cards use this so a slow call rejects → the card shows its quiet
// empty state instead of spinning. NOTE: it doesn't cancel the sidecar work;
// it just stops the UI from waiting on it.
function ipcCallTimeout<T = unknown>(method: string, params: unknown, ms = 8000): Promise<T> {
  return Promise.race([
    ipcCall<T>(method, params),
    new Promise<T>((_resolve, reject) => setTimeout(() => reject(new Error(`ipc '${method}' timed out after ${ms}ms`)), ms)),
  ]);
}

// Same hard-deadline guard, but for raw Tauri `invoke` (Rust commands like
// `inspector_stats`) rather than sidecar IPC. A Rust command that fans out to a
// slow sidecar op-log walk can hang the same way — this stops the UI from
// waiting forever. Does NOT cancel the underlying Rust work.
function withTimeout<T>(p: Promise<T>, ms: number, label = 'operation'): Promise<T> {
  return Promise.race([
    p,
    new Promise<T>((_resolve, reject) => setTimeout(() => reject(new Error(`${label} timed out after ${ms}ms`)), ms)),
  ]);
}

// Retry a raw Tauri invoke on a TRANSIENT sidecar-connection failure. During a
// heavy ingest the single-threaded sidecar can briefly stop servicing its IPC
// socket (a stop-the-world GC parks the event loop), so the FIRST attempt of a
// user action can fail to connect even though the same call a moment later
// succeeds — the "delete the engram, it bounces back, second click works" bug.
// Only connection-class errors are retried; real errors (not-found, validation)
// throw immediately so we never mask a genuine failure.
async function invokeRetry<T>(cmd: string, args?: Record<string, unknown>, tries = 3, delayMs = 600): Promise<T> {
  let lastErr: unknown;
  for (let attempt = 0; attempt < tries; attempt++) {
    try {
      return await invoke<T>(cmd, args);
    } catch (e) {
      lastErr = e;
      const transient = /connect to sidecar|sidecar\.sock|ECONNREFUSED|ENOENT|connection refused|broken pipe|not connected|did not respond|timed out|was busy|sidecar.{0,12}busy/i.test(String(e));
      if (!transient || attempt === tries - 1) throw e;
      await new Promise((r) => setTimeout(r, delayMs * (attempt + 1))); // 600ms, 1.2s backoff
    }
  }
  throw lastErr;
}

// ── Brain / Alive state ───────────────────────────────────────────────────

type BrainGoal = {
  nodeId: string; sourceId: string; graphId: string; title: string;
  milestones: string[]; targetDate?: number; createdAt: number;
};
let brainGoals: BrainGoal[] = [];

/** Retrieval-quality Memory Health report — Deterministic Consolidation tab. */
let brainMemoryHealth: {
  overall: number;
  connectivity: number;
  integration: number;
  confidence: number;
  coherence: number;
  reinforcementActivity: number;
  weightSpread: number;
  crossEngramConnections: number;
  inferredEdges: number;
  computedAt: number;
} | null = null;

/** Graphnosis Neural Network status — Deterministic Consolidation tab. */
let brainNeuralNetworkStatus: {
  enabled: boolean;
  gnnEdgeCount: number;
  isRunning?: boolean;
  lastRun: { at: number; edgesAdded: number; edgesPruned: number } | null;
} | null = null;
/** True while the user is mid-confirm on enabling the neural network. */
let nnConfirmPending = false;
/** True from the moment the user confirms until the IPC resolves and
 *  brainNeuralNetworkStatus.enabled flips true. Shows a "Enabling…"
 *  state with a Cancel button instead of snapping back to "Enable…". */
let nnEnablingInProgress = false;

// Sidecar scan status — lastRun timestamps + interval lengths, used for the
// scan-status countdown line. Refreshed on tab open and after each scan.
let brainStatus: {
  scanning: boolean;
  lastRun: Record<string, number>;
  intervals: Record<string, number>;
  lastDecayReport: { graphsProcessed: number; nodesDecayed: number } | null;
  sessionSynapsesFormed: number;
  sessionAutoLinksFormed: number;
  sessionReinforced: number;
  sessionConnectionsFormed: number;
  sessionInferred: number;
  sessionEdgesCleaned: number;
  sessionCrossEngram: number;
  lastConsolidation: { at: number; inferredEdges: number; communities: number; edgesCleaned: number } | null;
  // Diagnostic for the most recent runInsight() pass — drives the honest
  // empty-state copy on the Insights tab so users know why nothing
  // appeared (timeout, LLM unreachable, no data, parse failure, etc.).
  lastInsightResult: {
    at: number;
    status: 'ok' | 'no-llm' | 'no-data' | 'timeout' | 'parse-error' | 'error';
    count: number;
    message?: string;
  } | null;
} | null = null;
// Phases (e.g. 'fullscan', 'duplicate-scan') with a live start-frame but
// no done-frame yet. Non-empty ⇒ the pane shows its "scanning" state.
const brainActivePhases = new Set<string>();
// Current skill-training operation label for the status bar (per-operation
// status set from __skill_train_status__ frames). Null when no train is
// running. Takes priority over brain phases in renderStatusProcess since it's
// a user-initiated foreground action. The label is intentionally generic (no
// skill/engram name or memory content), and #status-process-text carries
// data-pres="surface:statusProcess" so it also redacts in Presentation Mode.
let skillTrainStatusLabel: string | null = null;
// 1s ticker for the countdown line; runs only while the brain pane is shown.
let scanTickerTimer: ReturnType<typeof setInterval> | null = null;
// Whether a local LLM is reachable with a model installed. Drives the
// honest "this is expected, not broken" copy on LLM-only brain features
// (insights, synapse formation). Refreshed by refreshLlmStatus().
let brainLlmReady = false;
// Whether the local LLM daemon (Ollama / future backends) is reachable on its
// loopback port — independent of model installation or the master toggle.
// Drives the loopback chip's lit-vs-dim state: the chip is about "is the
// endpoint up on 127.0.0.1?", not "is the LLM fully ready for inference?".
let localLlmReachable = false;
// Ollama is up and has at least one model — gates on-demand search features
// (Synthesize answer, Enhanced ranking) independently of the LLM master
// switch. Background autonomous features still require brainLlmReady.
let ollamaReadyForSearch = false;
// Periodic poll that keeps the Ollama status badge current while the
// settings modal is open. Started on open, cleared on close.
let ollamaStatusPollTimer: ReturnType<typeof setInterval> | null = null;

function startOllamaStatusPoll(): void {
  if (ollamaStatusPollTimer !== null) return; // already running
  ollamaStatusPollTimer = setInterval(() => { void refreshLlmStatus(); }, 30_000);
}
function stopOllamaStatusPoll(): void {
  if (ollamaStatusPollTimer !== null) {
    clearInterval(ollamaStatusPollTimer);
    ollamaStatusPollTimer = null;
  }
}

const BRAIN_PHASE_LABELS: Record<string, string> = {
  fullscan: 'Running a full self-scan',
  'duplicate-scan': 'Scanning for duplicate memories',
  'auto-heal': 'Merging a duplicate',
  'auto-link': 'Weaving connections',
  'healing-review': 'Re-checking past merges',
  synapse: 'Forming new connections',
  insight: 'Synthesizing insights',
  temporal: 'Applying memory decay',
  'goal-check': 'Checking goals',
  reinforce: 'Strengthening connections',
  consolidate: 'Consolidating memory',
  'cross-engram': 'Linking engrams',
  'neural-network': 'Graphnosis Neural Network',
  'edge-prediction': 'Predicting edges',
};

/**
 * Status-bar process line — categorization for each background phase.
 * Maps the raw phase name (from brain-engine's emitActivity frames) to a
 * user-facing prefix that groups by determinism layer:
 *   - "Self-healing" — deterministic duplicate detection + connection weaving
 *   - "Consolidation" — deterministic reinforcement, decay, cross-engram
 *   - "Insights" — LLM-backed pattern surfacing
 *   - "GLL" — local LLM overlay work (edge prediction, synapse)
 *   - "GNN" — neural-network overlay work
 * The label after the colon is the verb form ("scanning for duplicates")
 * so the status reads "Self-healing: scanning for duplicates…" naturally.
 */
interface PhaseLine { prefix: string; verb: string; tone: 'det' | 'gll' | 'gnn' | 'llm' }
const PHASE_LINE: Record<string, PhaseLine> = {
  'duplicate-scan': { prefix: 'Self-healing', verb: 'scanning for duplicates',   tone: 'det' },
  'auto-heal':      { prefix: 'Self-healing', verb: 'merging a duplicate',       tone: 'det' },
  'auto-link':      { prefix: 'Self-healing', verb: 'weaving connections',       tone: 'det' },
  'healing-review': { prefix: 'Self-healing', verb: 're-checking past merges',   tone: 'llm' },
  temporal:         { prefix: 'Consolidation', verb: 'applying memory decay',    tone: 'det' },
  'goal-check':     { prefix: 'Consolidation', verb: 'checking goals',           tone: 'det' },
  reinforce:        { prefix: 'Consolidation', verb: 'strengthening connections',tone: 'det' },
  consolidate:      { prefix: 'Consolidation', verb: 'consolidating memory',     tone: 'det' },
  'cross-engram':   { prefix: 'Consolidation', verb: 'linking engrams',          tone: 'det' },
  synapse:          { prefix: 'GLL',           verb: 'forming new connections',  tone: 'gll' },
  insight:          { prefix: 'Insights',      verb: 'synthesizing patterns',    tone: 'llm' },
  'edge-prediction':{ prefix: 'GLL',           verb: 'predicting edges',         tone: 'gll' },
  'neural-network': { prefix: 'GNN',           verb: 'training',                 tone: 'gnn' },
  fullscan:         { prefix: 'Background',    verb: 'running a self-scan',      tone: 'det' },
  purge:            { prefix: 'Cortex',        verb: 'purging forgotten memories', tone: 'det' },
};

/** Dot color per category — matches the visual identity of GLL / GNN pills
 *  (which use the Graphnosis wordmark gradient endpoints) so the user can
 *  read the dot at a glance. */
const PHASE_TONE_COLOR: Record<PhaseLine['tone'], string> = {
  det:  '#9aa4ad',  // grey-ish for deterministic
  llm:  '#6ab3c8',  // turquoise — matches GLL pill (and the wordmark start)
  gll:  '#6ab3c8',
  gnn:  '#a78bfa',  // purple — matches GNN pill (and the wordmark end)
};

/**
 * Paint the status-bar process line from brainActivePhases. Hidden when
 * nothing is running. When multiple phases are active simultaneously,
 * shows the most user-relevant one (LLM/GNN over deterministic, since
 * deterministic passes are quick and the user is more curious about
 * the slow heavy work). Re-rendered from handleBrainFrame on every
 * start/done event.
 */
function renderStatusProcess(): void {
  const wrap = els.statusProcess;
  const text = els.statusProcessText;
  if (!wrap || !text) return;
  // Skill training is a user-initiated foreground operation — show its
  // per-operation status with top priority over background brain phases.
  // (Presentation Mode redaction is handled by the element's data-pres tag.)
  if (skillTrainStatusLabel !== null) {
    wrap.style.display = 'flex';
    text.textContent = skillTrainStatusLabel;
    const dot = wrap.querySelector<HTMLElement>('.status-process-dot');
    if (dot) dot.style.background = PHASE_TONE_COLOR.llm;
    return;
  }
  if (brainActivePhases.size === 0) {
    wrap.style.display = 'none';
    return;
  }
  // Pick the most "interesting" active phase. Order of priority:
  // GNN > GLL > Insights/LLM > deterministic. The 'fullscan' wrapper
  // gets the lowest priority because it's a container, not an actual
  // unit of work.
  const TONE_PRIORITY: Record<PhaseLine['tone'], number> = { gnn: 4, gll: 3, llm: 2, det: 1 };
  let chosen: { phase: string; line: PhaseLine } | null = null;
  for (const phase of brainActivePhases) {
    const line = PHASE_LINE[phase];
    if (!line) continue;
    if (phase === 'fullscan' && brainActivePhases.size > 1) continue; // suppress wrapper when sub-phases exist
    if (!chosen || TONE_PRIORITY[line.tone] > TONE_PRIORITY[chosen.line.tone]) {
      chosen = { phase, line };
    }
  }
  if (!chosen) {
    wrap.style.display = 'none';
    return;
  }
  wrap.style.display = 'flex';
  text.textContent = `${chosen.line.prefix}: ${chosen.line.verb}…`;
  const dot = wrap.querySelector<HTMLElement>('.status-process-dot');
  if (dot) dot.style.background = PHASE_TONE_COLOR[chosen.line.tone];
}

/** Pull all brain state from the sidecar into module cache, then repaint. */
async function refreshBrainState(): Promise<void> {
  // Each panel applies its own IPC result independently. The previous
  // Promise.all-then-assign pattern meant that ONE slow IPC (memory health
  // walks the whole graph; vitality used to block on first-scan completion)
  // stalled every panel — vitality, insights, GNN, all stuck on their
  // "Loading…" placeholders. Promise.allSettled paints each panel as soon
  // as its own call returns, and a failure on one doesn't poison the rest.
  const fetchers: Array<{ name: string; promise: Promise<unknown>; apply: (v: unknown) => void }> = [
    { name: 'vitality',     promise: ipcCall('brain:getVitality', {}),             apply: (v) => { brainVitalityReport = v as typeof brainVitalityReport; } },
    { name: 'insights',     promise: ipcCall('brain:getInsights', {}),             apply: (v) => { brainInsights = v as typeof brainInsights; } },
    { name: 'goals',        promise: ipcCall('brain:listGoals', {}),               apply: (v) => { brainGoals = v as BrainGoal[]; } },
    { name: 'healing',      promise: ipcCall('brain:getHealingJournal', {}),       apply: (v) => { brainHealingJournal = v as BrainHealingRecord[]; } },
    { name: 'memoryHealth', promise: ipcCall('brain:getMemoryHealth', {}),         apply: (v) => { brainMemoryHealth = v as typeof brainMemoryHealth; } },
    { name: 'gnn',          promise: ipcCall('brain:getNeuralNetworkStatus', {}),  apply: (v) => { brainNeuralNetworkStatus = v as typeof brainNeuralNetworkStatus; } },
  ];
  // Each panel paints as soon as its own data arrives. We still need a
  // single combined paint at the end so any cross-pane derived state
  // (rail connect chips, layer pills) sees the full picture.
  await Promise.all(fetchers.map(async (f) => {
    try {
      const v = await f.promise;
      f.apply(v);
      // Repaint after each one — cheap, and means each panel flips out of
      // its placeholder the instant its data lands rather than waiting on
      // the slowest sibling.
      updateBrainUI();
    } catch (e) {
      // A single panel failing should never wedge the others. Log + move on.
      console.error(`[refreshBrainState] ${f.name} fetch failed: ${(e as Error).message}`);
    }
  }));
  renderRailGetConnected();
  refreshLayerPills();
}

/** Animate the vitality ring + score counter + status-bar chip from wherever
 *  they currently sit to `target` over ~1.1 s (ease-out cubic). */
function animateVitality(target: number): void {
  const startScore = parseInt(els.lbVitalityScore.textContent ?? '0', 10) || 0;
  const startV     = parseFloat(els.lbVitalityRing.style.getPropertyValue('--v') || '0') || 0;
  const duration   = 1100;
  const began      = performance.now();
  const targetOpacity = 0.4 + (target / 100) * 0.6;

  const tick = (now: number) => {
    const t = Math.min((now - began) / duration, 1);
    const ease = 1 - Math.pow(1 - t, 3); // cubic ease-out
    const cur = Math.round(startScore + (target - startScore) * ease);
    const curV = startV + (target - startV) * ease;

    els.lbVitalityScore.textContent  = String(cur);
    els.lbVitalityRing.style.setProperty('--v', String(curV));
    els.brainVitality.textContent    = `🧠 Vitality ${cur}`;
    els.brainVitality.style.opacity  = String(0.4 + (cur / 100) * 0.6);

    if (t < 1) requestAnimationFrame(tick);
    else {
      // Snap to exact target to avoid floating-point drift.
      els.lbVitalityScore.textContent = String(target);
      els.lbVitalityRing.style.setProperty('--v', String(target));
      els.brainVitality.textContent   = `🧠 Vitality ${target}`;
      els.brainVitality.style.opacity = String(targetOpacity);
      // Remove the fast-pulse scanning class now that the score is settled.
      els.livingBrain.classList.remove('lb-scanning');
    }
  };
  requestAnimationFrame(tick);
}

/** Status-bar chip + atlas animation + Autonomous Brain pane. Cheap; no IPC. */
function updateBrainUI(): void {
  // Vitality-dependent UI (status bar chip, atlas overlay, vitality ring)
  // only repaints when we actually have a number. But the rest of the
  // Autonomous-Brain pane (GNN status, insights, healing log, memory
  // health) must repaint regardless — otherwise a fresh `enable` click
  // can land its IPC update without the UI reflecting it, because vitality
  // happened to be null in that moment. That was the "Snapshot & enable
  // reverts to Enable…" bug.
  if (brainVitalityReport) {
    const v = brainVitalityReport.overall;
    els.brainVitality.style.display = '';
    mainAtlas?.setBrainVitality?.(v);
    animateVitality(v);
  }
  renderLivingBrainPane();
}

// ── Autonomous Brain pane ─────────────────────────────────────────────────

/** Full refresh: pull state + LLM status + scan status, then paint. */
async function renderLivingBrain(): Promise<void> {
  els.lbVitalityTitle.textContent = 'Checking your cortex…';
  ensureFeedPlaceholder();
  await Promise.all([refreshBrainState(), refreshLlmStatus(), refreshBrainStatus()]);
  // refreshBrainState only repaints on success — paint again so a failed
  // fetch still resolves to an honest "brain unavailable" state.
  renderLivingBrainPane();
  renderScanStatus();
}

/** Paint the pane from cached module state — no IPC, safe to call often. */
function renderLivingBrainPane(): void {
  renderLbVitality();
  renderMemoryHealth();
  renderLbHealingLog();
  renderLbInsights();
  renderLbGoals();
  renderNeuralNetwork();
  renderBrainSchedule();
  ensureFeedPlaceholder();
}

/** Map a graphId to its human display name for the engram chips. Falls
 *  back to the raw id if the graph isn't in loadedGraphs (e.g. archived). */
function engramName(graphId: string): string {
  return loadedGraphs.find((g) => g.graphId === graphId)?.metadata.displayName ?? graphId;
}

// ─────────────────────────────────────────────────────────────────────────
// Presentation Mode — demo-safe redaction layer.
//
// Lets the user pre-select exactly what to reveal (per-item: engrams / sources
// / skills / goals, plus fixed "surface" toggles) and then navigate the real
// app with everything else REDACTED IN PLACE (solid blocks; layout preserved,
// not hidden, not blurred). This is a DEFAULT-DENY model: any element tagged
// `data-pres="<kind>:<id>"` is redacted by CSS unless the masking sweep marks
// it `.pres-reveal`. A missed tag (or a render we didn't anticipate) fails
// SAFE — it stays masked. A MutationObserver re-sweeps on every DOM change so
// async / freshly-rendered content can't slip through unmasked.
//
// IMPORTANT for future code: any NEW surface that shows personal content must
// carry a `data-pres="…"` attribute, or it will appear in full during a demo.
// ─────────────────────────────────────────────────────────────────────────
const PRESENTATION_KEY = 'graphnosis:presentationConfig';
// Surfaces are fixed app-wide chrome (not per-engram data). Memory CONTENT
// (search results, studio results, activity row text, node previews) is NOT a
// surface — it's tagged `node:`/`source:` and governed by the engram/source
// allowlist, so it reveals only for the engrams/sources the user picked.
type PresSurface =
  | 'cortexPath' | 'stats' | 'vitality' | 'mcpClients' | 'connectors'
  | 'recents' | 'studioResults' | 'predict' | 'foresight' | 'remoteAccess' | 'statusProcess' | 'appVersion' | 'license';
const PRES_SURFACE_DEFS: Array<{ key: PresSurface; label: string; hint: string }> = [
  { key: 'stats',          label: 'Stats & counts',     hint: 'Node / source / engram totals, growth bars' },
  { key: 'vitality',       label: 'Vitality & health',  hint: 'Cortex grade, memory-health figures' },
  { key: 'cortexPath',     label: 'Cortex folder path',  hint: 'The on-disk location in the status bar' },
  { key: 'mcpClients',     label: 'AI clients',         hint: 'Connected MCP client names (status bar, Home, MCP Tools)' },
  { key: 'connectors',     label: 'Data sources / connectors', hint: 'Connector names + file paths in Get Connected' },
  { key: 'recents',        label: 'Recents',            hint: 'Recently-touched memory previews' },
  { key: 'studioResults',  label: 'Memory Studio results', hint: 'Recall / dig-deeper output (per-engram sections still follow your engram picks)' },
  { key: 'predict',        label: 'Foresight — Predict',  hint: 'The Predict output (risks & opportunities) on the Foresight page' },
  { key: 'foresight',      label: 'Foresight — Insights', hint: 'The Insights output on the Foresight page and the Home Foresight teaser' },
  { key: 'remoteAccess',   label: 'Remote access (QR / URL / token)', hint: 'Mobile & Remote QR codes, server URL, and bearer token — leave OFF to keep credentials hidden' },
  { key: 'statusProcess',  label: 'Background process line', hint: 'The live "Self-healing…/GLL…" status-bar text' },
  { key: 'appVersion',     label: 'App version',        hint: 'The version pill in the status bar' },
  { key: 'license',        label: 'License / account',  hint: 'Subscription + account identifiers in Settings' },
];
const presState = {
  active: false, // NEVER persisted — the app always boots un-masked.
  allow: {
    engrams: new Set<string>(),
    sources: new Set<string>(),
    skills: new Set<string>(),
    goals: new Set<string>(),
  },
  surfaces: Object.fromEntries(PRES_SURFACE_DEFS.map((d) => [d.key, false])) as Record<PresSurface, boolean>,
  // Phrases to black out wherever they appear in VISIBLE content (even inside
  // revealed engrams) — e.g. a project codename you never want on screen.
  phrases: [] as string[],
};
function presActive(): boolean { return presState.active; }

// Snapshot of what was selected the moment Presentation Mode started, keyed
// `<kind>:<id>`. While active, the config-page checkboxes for everything NOT in
// this set are disabled — so you can't reveal anything new mid-demo (you can
// still UNcheck a started-checked item to hide more). Cleared on exit.
let presStartChecked = new Set<string>();
function snapshotPresStartChecked(): void {
  presStartChecked = new Set<string>([
    ...[...presState.allow.engrams].map((id) => `engram:${id}`),
    ...[...presState.allow.sources].map((id) => `source:${id}`),
    ...[...presState.allow.skills].map((id) => `skill:${id}`),
    ...[...presState.allow.goals].map((id) => `goal:${id}`),
    ...PRES_SURFACE_DEFS.filter((d) => presState.surfaces[d.key]).map((d) => `surface:${d.key}`),
  ]);
}
/** Lock the config page during a live presentation: disable every checkbox not
 *  selected at start; re-enable all when not presenting. */
function applyPresConfigLock(): void {
  const body = document.getElementById('presentation-body');
  if (!body) return;
  body.querySelectorAll<HTMLInputElement>('input[data-pres-pick]').forEach((cb) => {
    cb.disabled = presState.active && !presStartChecked.has(`${cb.dataset['presPick']}:${cb.dataset['id']}`);
  });
  // Bulk "Select all" toggles can only ADD reveals, so disable them while
  // presenting (the per-row checked boxes can still be unchecked to hide more,
  // and "Clear all" stays live since clearing only reduces what's shown).
  body.querySelectorAll<HTMLButtonElement>('.pres-selectall, .pres-grp-selectall').forEach((btn) => {
    btn.disabled = presState.active;
  });
}

/** Should an `engram:` tagged element reveal? (also the cascade source.) */
function presRevealEngram(graphId: string): boolean { return presState.allow.engrams.has(graphId); }

// Engrams that have ≥1 individually-selected source — recomputed each sweep
// from presSourcesCache (sourceId → graphId). When an engram is in this set,
// the engram-level cascade is OVERRIDDEN by the per-source picks: only the
// checked sources (and their nodes) reveal; the rest redact.
let presEngramsWithSourceSel = new Set<string>();
// Engrams revealed at the engram level but EMPTY at presentation setup (no
// sources yet — e.g. a fresh manual-sync engram about to be ingested live). Their
// sources, as they ingest during the demo, must REDACT rather than cascade-
// reveal — so the user can show the graph filling without exposing source
// filenames. (Graph dots still render; only labels + source names mask.)
let presEngramsRedactSources = new Set<string>();
function recomputePresSourceScopes(): void {
  presEngramsWithSourceSel = new Set();
  presEngramsRedactSources = new Set();
  const engramsWithSources = new Set(presSourcesCache.map((s) => s.graphId));
  for (const gid of presState.allow.engrams) {
    if (!engramsWithSources.has(gid)) presEngramsRedactSources.add(gid);
  }
  if (presState.allow.sources.size === 0) return;
  const byId = new Map(presSourcesCache.map((s) => [s.sourceId, s.graphId]));
  for (const sid of presState.allow.sources) {
    const gid = byId.get(sid);
    if (gid) presEngramsWithSourceSel.add(gid);
  }
}

/** Node/source reveal. The explicitly-checked source always reveals. The
 *  engram-level cascade reveals everything in a checked engram — UNLESS the
 *  user narrowed that engram by checking specific sources, in which case only
 *  the checked sources reveal. A node whose source is unknown inside such a
 *  narrowed engram fails SAFE (redacts) — we can't prove it belongs to a
 *  selected source, so we hide it. */
function presRevealSource(sourceId: string | undefined, graphId: string | undefined): boolean {
  if (sourceId && presState.allow.sources.has(sourceId)) return true;
  if (graphId && presState.allow.engrams.has(graphId)) {
    // Cascade only when the engram isn't narrowed by per-source picks AND wasn't
    // empty at setup (empty-at-setup engrams redact their live-ingested sources).
    return !presEngramsWithSourceSel.has(graphId) && !presEngramsRedactSources.has(graphId);
  }
  return false;
}

/** Resolve a node's allowlist sourceId from the loaded caches (server-enriched
 *  on `list_nodes`/`search_nodes`). Used at render sites that have a nodeId but
 *  not the full record (connection neighbors, recents) so they can carry an
 *  exact `data-pres-source` for per-source redaction. */
function nodeSourceId(nodeId: string, graphId?: string): string | undefined {
  if (graphId) {
    const hit = graphnosisGlobalNodes.get(graphId)?.find((n) => n.id === nodeId);
    if (hit?.sourceId) return hit.sourceId;
  }
  return graphnosisAllNodes.find((n) => n.id === nodeId)?.sourceId;
}

/** Build the ` data-pres-source="…"` attribute fragment (empty when unknown, so
 *  the node falls back to engram-level / fail-safe redaction). */
function presSourceAttr(sourceId: string | undefined): string {
  return sourceId ? ` data-pres-source="${escape(sourceId)}"` : '';
}

/** Decide reveal/redact for a single tagged element from its data attributes. */
function presElementRevealed(el: HTMLElement): boolean {
  const tag = el.dataset['pres'];
  if (!tag) return true;
  const idx = tag.indexOf(':');
  const kind = idx === -1 ? tag : tag.slice(0, idx);
  const id = idx === -1 ? '' : tag.slice(idx + 1);
  const eng = el.dataset['presEngram'];
  const src = el.dataset['presSource'];
  switch (kind) {
    case 'engram': return presRevealEngram(id);
    case 'source': return presRevealSource(id, eng);
    case 'node':   return presRevealSource(src, eng);
    case 'skill':  return presState.allow.skills.has(id) || (!!eng && presState.allow.engrams.has(eng));
    case 'goal':   return presState.allow.goals.has(id) || (!!eng && presState.allow.engrams.has(eng));
    case 'surface': return !!presState.surfaces[id as PresSurface];
    default: return false; // unknown kind → redact (safe default)
  }
}

/** Reveal-sweep: every `[data-pres]` under root is revealed iff allowlisted.
 *  Anything inside a `[data-pres-exempt]` subtree (the config page itself) is
 *  always revealed so the user can read names while choosing. */
function applyPresentationMasking(root: ParentNode = document.querySelector('main') ?? document.body): void {
  if (!presState.active) return;
  recomputePresSourceScopes(); // which engrams are narrowed by per-source picks
  root.querySelectorAll<HTMLElement>('[data-pres]').forEach((el) => {
    if (el.closest('[data-pres-exempt]')) { el.classList.add('pres-reveal'); return; }
    el.classList.toggle('pres-reveal', presElementRevealed(el));
  });
  // Disable native hover popups while presenting — `title` (and image `alt` /
  // `aria-label`, which some platforms surface on hover or to a11y tools)
  // can't be CSS-masked and routinely leak full content (filenames, node text,
  // reasons). Stash each in a data-pres-* attr so we can restore it on exit.
  // Skip the config page (data-pres-exempt) so its helper tooltips still work.
  for (const attr of ['title', 'alt', 'aria-label'] as const) {
    const stash = `data-pres-${attr}`;
    root.querySelectorAll<HTMLElement>(`[${attr}]`).forEach((el) => {
      if (el.closest('[data-pres-exempt]')) return;
      if (el.hasAttribute(stash)) return; // already stripped
      el.setAttribute(stash, el.getAttribute(attr) ?? '');
      el.removeAttribute(attr);
    });
  }
  // Native <select> option labels can't be CSS-masked (the browser renders the
  // list natively), so rewrite the LABEL of any option that names an
  // unselected engram to a block — covers every engram scope dropdown (search,
  // activity, sources, studio, skills target) and their open lists at once.
  // The text-equality guards keep our own writes from retriggering the observer.
  const PRES_BLOCK = '████████';
  const graphIds = new Set(loadedGraphs.map((g) => g.graphId));
  // Generic Activity actors that are never an external identity (never redacted).
  const GENERIC_ACTORS = new Set(['', 'You', 'Autonomous brain', 'System', 'App', 'Unknown client']);
  root.querySelectorAll<HTMLOptionElement>('option').forEach((opt) => {
    // Decide whether this option's label must be hidden.
    //  • Activity "who" select: every actor that isn't generic is an external
    //    identity → connectors follow the connectors surface, the rest (AI
    //    clients / agents) follow mcpClients.
    //  • Elsewhere: engram-scope selects (graphId values) + connector options.
    const inActorSelect = opt.closest('select')?.id === 'activity-actor-select';
    const isEngram = graphIds.has(opt.value);
    const isConnector = opt.value.startsWith('connector:');
    let hide: boolean;
    if (inActorSelect) {
      if (GENERIC_ACTORS.has(opt.value)) return;
      hide = isConnector ? !presState.surfaces.connectors : !presState.surfaces.mcpClients;
    } else {
      if (!isEngram && !isConnector) return; // All / sentinels / non-engram selects
      hide = isEngram ? !presRevealEngram(opt.value) : !presState.surfaces.connectors;
    }
    if (!hide) {
      if (opt.dataset['presOrig'] != null && opt.text !== opt.dataset['presOrig']) opt.text = opt.dataset['presOrig'];
      if (opt.dataset['presOrig'] != null) delete opt.dataset['presOrig'];
    } else {
      if (opt.dataset['presOrig'] == null) opt.dataset['presOrig'] = opt.text;
      if (opt.text !== PRES_BLOCK) opt.text = PRES_BLOCK;
    }
  });
  applyPhraseRedaction(root);
}

/** Black out user-specified phrases wherever they appear in visible text —
 *  even inside revealed content. Replaces each match with same-length block
 *  chars inside a `.pres-phrase` span (original stashed for restore on exit).
 *  Idempotent: the replacement text contains no phrase, so re-sweeps converge.
 *  Only runs when phrases are set, so it's zero-cost for everyone else. */
function applyPhraseRedaction(root: ParentNode): void {
  const phrases = presState.phrases.map((p) => p.trim()).filter((p) => p.length >= 2);
  if (phrases.length === 0) return;
  const re = new RegExp(
    phrases.sort((a, b) => b.length - a.length).map((p) => p.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|'),
    'gi',
  );
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
    acceptNode(n): number {
      const p = (n as Text).parentElement;
      if (!p) return NodeFilter.FILTER_REJECT;
      if (p.classList.contains('pres-phrase')) return NodeFilter.FILTER_REJECT; // already redacted
      if (p.closest('[data-pres-exempt]')) return NodeFilter.FILTER_REJECT;     // config inputs
      if (['SCRIPT', 'STYLE', 'TEXTAREA', 'INPUT', 'OPTION'].includes(p.tagName)) return NodeFilter.FILTER_REJECT;
      re.lastIndex = 0;
      return re.test(n.nodeValue ?? '') ? NodeFilter.FILTER_ACCEPT : NodeFilter.FILTER_REJECT;
    },
  });
  const nodes: Text[] = [];
  let cur: Node | null;
  while ((cur = walker.nextNode())) nodes.push(cur as Text);
  for (const node of nodes) {
    const text = node.nodeValue ?? '';
    re.lastIndex = 0;
    const frag = document.createDocumentFragment();
    let last = 0;
    let m: RegExpExecArray | null;
    while ((m = re.exec(text)) !== null) {
      if (m.index > last) frag.appendChild(document.createTextNode(text.slice(last, m.index)));
      const span = document.createElement('span');
      span.className = 'pres-phrase';
      span.dataset['presPhraseOrig'] = m[0];
      span.textContent = '█'.repeat(m[0].length);
      frag.appendChild(span);
      last = m.index + m[0].length;
      if (m.index === re.lastIndex) re.lastIndex++; // zero-width guard
    }
    if (last < text.length) frag.appendChild(document.createTextNode(text.slice(last)));
    node.parentNode?.replaceChild(frag, node);
  }
}

let presObserver: MutationObserver | null = null;
let presSweepScheduled = false;
function schedulePresSweep(): void {
  if (presSweepScheduled) return;
  presSweepScheduled = true;
  requestAnimationFrame(() => { presSweepScheduled = false; applyPresentationMasking(); });
}
function attachPresObserver(): void {
  if (presObserver) return;
  const root = document.querySelector('main') ?? document.body;
  // Observe new/removed nodes only (attributeFilter on data-pres). We do NOT
  // observe `class`, so our own `.pres-reveal` toggles can't retrigger a loop.
  presObserver = new MutationObserver(() => schedulePresSweep());
  presObserver.observe(root, { childList: true, subtree: true, attributes: true, attributeFilter: ['data-pres'] });
}
function detachPresObserver(): void { presObserver?.disconnect(); presObserver = null; }

/** Redact MemoryStudio's raw-context prompt per engram while presenting. The
 *  prompt is one text blob with `## <Engram display name>` section headers;
 *  sections whose engram isn't allowlisted get their header + body replaced
 *  with a block. (The whole panel is also gated by the `studioResults` surface
 *  — this is the finer, per-engram pass for when that surface is on.) */
function presRedactRecallPrompt(prompt: string): string {
  if (!presActive()) return prompt;
  const allowedNames = new Set([...presState.allow.engrams].map((id) => engramName(id)));
  const lines = prompt.split('\n');
  const out: string[] = [];
  let curAllowed = true;
  let inSection = false;
  for (const line of lines) {
    const m = /^##\s+(.+?)\s*$/.exec(line);
    if (m) {
      inSection = true;
      curAllowed = allowedNames.has(m[1] ?? '');
      out.push(curAllowed ? line : '## ████████');
      if (!curAllowed) out.push('[content hidden — this engram isn’t selected for Presentation Mode]');
      continue;
    }
    if (!inSection || curAllowed) out.push(line); // preamble + allowed sections pass through
  }
  return out.join('\n');
}

/** Re-push 3D data so canvas labels pick up (or drop) redaction — the THREE.js
 *  canvas can't be masked by CSS, so masking happens in nodesToAtlas/galaxy. */
function presRefreshAtlas(): void {
  if (!mainAtlas) return;
  if (atlasGalaxyMode || atlasActiveGraph === FULL_CORTEX) { void loadFullCortexGalaxy(); return; }
  pushDataIntoAtlas();
}

function showPresentationBanner(): void {
  document.getElementById('presentation-banner')?.classList.remove('hidden');
}
function hidePresentationBanner(): void {
  document.getElementById('presentation-banner')?.classList.add('hidden');
}

function startPresentation(): void {
  presState.active = true;
  savePresentationConfig();
  snapshotPresStartChecked(); // freeze what's revealable; lock the rest
  document.body.classList.add('presentation-active');
  attachPresObserver();
  applyPresentationMasking();
  applyPresConfigLock();
  mainAtlas?.setHoverSuppressed(true); // no hover tips → no raw node text leaking past the bars
  presRefreshAtlas();
  showPresentationBanner();
  // Start the demo on Home so the user lands on the dashboard, not the config.
  activateMode('atlas');
}
function stopPresentation(): void {
  if (!presState.active) return;
  presState.active = false;
  document.body.classList.remove('presentation-active');
  mainAtlas?.setHoverSuppressed(false); // restore node hover tips
  detachPresObserver();
  document.querySelectorAll('.pres-reveal').forEach((el) => el.classList.remove('pres-reveal'));
  // Restore native tooltips / alt / aria-label stashed during masking.
  for (const attr of ['title', 'alt', 'aria-label'] as const) {
    const stash = `data-pres-${attr}`;
    document.querySelectorAll<HTMLElement>(`[${stash}]`).forEach((el) => {
      el.setAttribute(attr, el.getAttribute(stash) ?? '');
      el.removeAttribute(stash);
    });
  }
  // Restore <select> option labels masked during presentation.
  document.querySelectorAll<HTMLOptionElement>('option[data-pres-orig]').forEach((opt) => {
    opt.text = opt.dataset['presOrig'] ?? opt.text;
    delete opt.dataset['presOrig'];
  });
  // Unwrap phrase-redaction spans back to their original text.
  document.querySelectorAll<HTMLElement>('span.pres-phrase').forEach((span) => {
    span.replaceWith(document.createTextNode(span.dataset['presPhraseOrig'] ?? span.textContent ?? ''));
  });
  presStartChecked.clear();
  applyPresConfigLock(); // re-enable all checkboxes
  presRefreshAtlas();
  hidePresentationBanner();
  // Re-render the config page so its Start/Stop affordance reflects the state.
  if (currentMode === 'presentation') renderPresentationPane();
}

function savePresentationConfig(): void {
  try {
    localStorage.setItem(PRESENTATION_KEY, JSON.stringify({
      engrams: [...presState.allow.engrams],
      sources: [...presState.allow.sources],
      skills: [...presState.allow.skills],
      goals: [...presState.allow.goals],
      surfaces: presState.surfaces,
      phrases: presState.phrases,
    }));
  } catch { /* storage off — selection just won't persist */ }
}
function loadPresentationConfig(): void {
  try {
    const raw = localStorage.getItem(PRESENTATION_KEY);
    if (!raw) return;
    const o = JSON.parse(raw) as Partial<{ engrams: string[]; sources: string[]; skills: string[]; goals: string[]; surfaces: Record<string, boolean>; phrases: string[] }>;
    presState.allow.engrams = new Set(o.engrams ?? []);
    presState.allow.sources = new Set(o.sources ?? []);
    presState.allow.skills = new Set(o.skills ?? []);
    presState.allow.goals = new Set(o.goals ?? []);
    if (o.surfaces) for (const d of PRES_SURFACE_DEFS) presState.surfaces[d.key] = !!o.surfaces[d.key];
    presState.phrases = Array.isArray(o.phrases) ? o.phrases.filter((p) => typeof p === 'string') : [];
  } catch { /* corrupt config — ignore, start blank */ }
}

/** Total number of things the user has chosen to reveal. */
function presSelectionCount(): number {
  return presState.allow.engrams.size + presState.allow.sources.size
    + presState.allow.skills.size + presState.allow.goals.size
    + PRES_SURFACE_DEFS.filter((d) => presState.surfaces[d.key]).length;
}

function presCheckboxRow(checked: boolean, dataAttr: string, title: string, sub?: string, presTag?: string): string {
  // `.pres-row-flag` is shown via CSS (:has(input:checked)) — a green "will be
  // visible" tag so the user can see at a glance what they've opted to reveal.
  // `presTag` tags the NAME so it redacts on the config page too while masking
  // is active (the checkbox stays usable) — so the page itself is screen-share
  // safe. Surfaces pass no tag (their labels are generic, not sensitive).
  const titleAttr = presTag ? ` data-pres="${escape(presTag)}"` : '';
  return `<label class="pres-row">
    <input type="checkbox" ${checked ? 'checked' : ''} ${dataAttr} />
    <span class="pres-row-body">
      <span class="pres-row-title"${titleAttr}>${escape(title)}</span>
      ${sub ? `<span class="pres-row-sub">${escape(sub)}</span>` : ''}
    </span>
    <span class="pres-row-flag">✓ will be visible</span>
  </label>`;
}

// Cache of the last-fetched source list so "Select all" for Sources knows every
// id without re-hitting inspector_stats.
let presSourcesCache: SourceRecord[] = [];

/** All ids currently selectable for a category — drives the Select-all toggle. */
function presAllIdsFor(kind: 'engram' | 'source' | 'skill' | 'goal' | 'surface'): string[] {
  if (kind === 'engram') return loadedGraphs.filter((g) => !g.metadata.archived).map((g) => g.graphId);
  if (kind === 'source') return presSourcesCache.map((s) => s.sourceId);
  if (kind === 'skill') return skillsLibrary.map((s) => s.sourceId);
  if (kind === 'goal') return brainGoals.map((g) => g.sourceId);
  return PRES_SURFACE_DEFS.map((d) => d.key);
}
function presSetFor(kind: 'engram' | 'source' | 'skill' | 'goal'): Set<string> {
  return kind === 'engram' ? presState.allow.engrams
    : kind === 'source' ? presState.allow.sources
    : kind === 'skill' ? presState.allow.skills
    : presState.allow.goals;
}
/** Toggle a whole category: select all if any are unselected, else clear. */
function togglePresSelectAll(kind: 'engram' | 'source' | 'skill' | 'goal' | 'surface'): void {
  const ids = presAllIdsFor(kind);
  if (kind === 'surface') {
    const allOn = ids.every((k) => presState.surfaces[k as PresSurface]);
    for (const k of ids) presState.surfaces[k as PresSurface] = !allOn;
  } else {
    const set = presSetFor(kind);
    const allOn = ids.length > 0 && ids.every((id) => set.has(id));
    set.clear();
    if (!allOn) for (const id of ids) set.add(id);
  }
  savePresentationConfig();
  renderPresentationPane();
  if (presState.active) { applyPresentationMasking(); presRefreshAtlas(); }
}

/** Select/clear every source in one engram group — updates in place so the
 *  group stays open and the sources list doesn't re-fetch/flash. */
function togglePresSourceGroup(graphId: string, det: HTMLElement | null): void {
  if (!graphId || !det) return;
  const ids = presSourcesCache.filter((s) => s.graphId === graphId).map((s) => s.sourceId);
  if (ids.length === 0) return;
  const allOn = ids.every((id) => presState.allow.sources.has(id));
  for (const id of ids) { if (allOn) presState.allow.sources.delete(id); else presState.allow.sources.add(id); }
  savePresentationConfig();
  // Reflect the new state in this group's checkboxes, badge, and button.
  det.querySelectorAll<HTMLInputElement>('input[data-pres-pick="source"]').forEach((cb) => { cb.checked = !allOn; });
  const selNow = allOn ? 0 : ids.length;
  const badge = det.querySelector<HTMLElement>('.pres-group-visible');
  if (badge) { badge.textContent = selNow > 0 ? `✓ ${selNow} will be visible` : ''; badge.classList.toggle('hidden', selNow === 0); }
  const grpBtn = det.querySelector<HTMLElement>('[data-pres-grp-selectall]');
  if (grpBtn) grpBtn.textContent = allOn ? 'Select all' : 'Clear';
  // Update the Sources section "N selected" meta + the global item count.
  const body = document.getElementById('presentation-body');
  body?.querySelectorAll('.pres-section').forEach((sec) => {
    if (sec.querySelector('h3')?.textContent === 'Sources') {
      const meta = sec.querySelector('.pres-section-meta');
      if (meta) meta.textContent = `${presState.allow.sources.size} selected`;
    }
  });
  const count = presSelectionCount();
  const countEl = body?.querySelector('.pres-count');
  if (countEl) countEl.textContent = `${count} item${count === 1 ? '' : 's'} selected`;
  if (presState.active) { applyPresentationMasking(); presRefreshAtlas(); }
}

/** Section header with a Select-all/Clear toggle. */
function presSectionHead(title: string, kind: 'engram' | 'source' | 'skill' | 'goal' | 'surface', selectedLabel: string, hasItems: boolean): string {
  const ids = presAllIdsFor(kind);
  const allOn = ids.length > 0 && (kind === 'surface'
    ? ids.every((k) => presState.surfaces[k as PresSurface])
    : ids.every((id) => presSetFor(kind).has(id)));
  const btn = hasItems
    ? `<button class="pres-selectall" type="button" data-pres-selectall="${kind}">${allOn ? 'Clear' : 'Select all'}</button>`
    : '';
  return `<div class="pres-section-head"><h3>${escape(title)}</h3><div class="pres-section-right">${btn}<span class="pres-section-meta">${escape(selectedLabel)}</span></div></div>`;
}

/** Build the Presentation Mode config page: categorized checklists (all OFF by
 *  default) + surface toggles + the Start/Stop control. */
function renderPresentationPane(): void {
  const host = document.getElementById('presentation-body');
  if (!host) return;
  prunePresAllowlist(); // drop reveals for engrams deleted since they were picked
  const active = presState.active;
  const count = presSelectionCount();

  const engrams = loadedGraphs
    .filter((g) => !g.metadata.archived)
    .sort((a, b) => (a.metadata.displayName ?? a.graphId).localeCompare(b.metadata.displayName ?? b.graphId));
  const engramSection = engrams.length === 0
    ? '<p class="pres-empty">No engrams loaded.</p>'
    : engrams.map((g) => presCheckboxRow(
        presState.allow.engrams.has(g.graphId),
        `data-pres-pick="engram" data-id="${escape(g.graphId)}"`,
        formatEngramLabel(g),
        'Reveals this engram and everything in it',
        `engram:${g.graphId}`,
      )).join('');

  const goals = brainGoals.slice();
  const goalSection = goals.length === 0
    ? '<p class="pres-empty">No goals yet.</p>'
    : goals.map((g) => presCheckboxRow(
        presState.allow.goals.has(g.sourceId),
        `data-pres-pick="goal" data-id="${escape(g.sourceId)}"`,
        g.title,
        engramName(g.graphId),
        `goal:${g.sourceId}`,
      )).join('');

  const surfaceSection = PRES_SURFACE_DEFS.map((d) => presCheckboxRow(
    presState.surfaces[d.key],
    `data-pres-pick="surface" data-id="${escape(d.key)}"`,
    d.label,
    d.hint,
    `surface:${d.key}`, // unchecked surface rows redact on the config page too
  )).join('');

  host.innerHTML = `
    <div class="pres-config">
      <div class="pres-scroll">
        <div class="pres-intro">
          <p>Pick exactly what stays visible while you demo or screen-share. <strong>Everything starts hidden</strong> — check an item to reveal it in full. Everything you don't pick is redacted in place (solid blocks), so your cortex's structure shows but its contents stay private.</p>
          <div class="pres-warning">
            <strong>⚠️ Best-effort, not a guarantee.</strong> Verify every screen yourself before sharing. New content, tooltips, notifications, and anything loaded after you start may not be masked. You accept full responsibility for what you reveal — you'll confirm this before it activates. See the <a href="#" id="pres-warning-terms">Terms of Use</a> and <a href="#" id="pres-warning-privacy">Privacy Policy</a>.
          </div>
        </div>

        <section class="pres-section">
          ${presSectionHead('Engrams', 'engram', `${presState.allow.engrams.size} selected`, engrams.length > 0)}
          <div class="pres-list">${engramSection}</div>
        </section>

        <section class="pres-section">
          ${presSectionHead('Sources', 'source', `${presState.allow.sources.size} selected`, false)}
          <div class="pres-list" id="pres-sources-list"><p class="pres-empty">Loading sources…</p></div>
        </section>

        <section class="pres-section">
          ${presSectionHead('Skills', 'skill', `${presState.allow.skills.size} selected`, skillsLibrary.length > 0)}
          <div class="pres-list" id="pres-skills-list"><p class="pres-empty">Loading skills…</p></div>
        </section>

        <section class="pres-section">
          ${presSectionHead('Goals', 'goal', `${presState.allow.goals.size} selected`, goals.length > 0)}
          <div class="pres-list">${goalSection}</div>
        </section>

        <section class="pres-section">
          ${presSectionHead('Surfaces', 'surface', 'app-wide details', true)}
          <div class="pres-list">${surfaceSection}</div>
        </section>

        <section class="pres-section" data-pres="surface:__phrases__">
          <div class="pres-section-head"><h3>Always redact these phrases</h3></div>
          <p class="pres-row-sub" style="margin:0 0 6px;">Blacked out wherever they appear on screen — even inside revealed content. One per line, case-insensitive.</p>
          <textarea id="pres-phrases" class="pres-phrases" rows="3" placeholder="e.g. project codename&#10;a client's name&#10;an address">${escape(presState.phrases.join('\n'))}</textarea>
        </section>
      </div>

      <div class="pres-actions">
        <button class="pres-clear" id="pres-clear-btn" type="button">Clear all</button>
        <button class="pres-start ${active ? 'is-active' : ''}" id="pres-start-btn" type="button">
          ${active ? '■ Stop Presentation Mode' : '▶ Review & Start Presentation Mode'}
        </button>
        <span class="pres-count">${count} item${count === 1 ? '' : 's'} selected</span>
      </div>
    </div>`;

  // Sources + skills are fetched lazily (inspector_stats / skill:list).
  void renderPresentationSources();
  void renderPresentationSkills();

  host.querySelectorAll<HTMLInputElement>('input[data-pres-pick]').forEach((cb) => {
    cb.addEventListener('change', () => onPresPickChange(cb));
  });
  host.querySelectorAll<HTMLButtonElement>('[data-pres-selectall]').forEach((btn) => {
    btn.addEventListener('click', () => togglePresSelectAll(btn.dataset['presSelectall'] as 'engram' | 'source' | 'skill' | 'goal' | 'surface'));
  });
  const phrasesEl = host.querySelector<HTMLTextAreaElement>('#pres-phrases');
  phrasesEl?.addEventListener('input', () => {
    presState.phrases = phrasesEl.value.split('\n').map((p) => p.trim()).filter(Boolean);
    savePresentationConfig();
    if (presState.active) applyPresentationMasking();
  });
  host.querySelector('#pres-warning-terms')?.addEventListener('click', (e) => {
    e.preventDefault();
    void invoke('plugin:opener|open_url', { url: 'https://docs.graphnosis.com/legal/terms-of-use' });
  });
  host.querySelector('#pres-warning-privacy')?.addEventListener('click', (e) => {
    e.preventDefault();
    void invoke('plugin:opener|open_url', { url: 'https://docs.graphnosis.com/legal/privacy-policy' });
  });
  host.querySelector<HTMLButtonElement>('#pres-clear-btn')?.addEventListener('click', () => {
    presState.allow.engrams.clear(); presState.allow.sources.clear();
    presState.allow.skills.clear(); presState.allow.goals.clear();
    for (const d of PRES_SURFACE_DEFS) presState.surfaces[d.key] = false;
    savePresentationConfig();
    renderPresentationPane();
    if (presState.active) applyPresentationMasking();
  });
  host.querySelector<HTMLButtonElement>('#pres-start-btn')?.addEventListener('click', () => {
    if (presState.active) requestStopPresentation();
    else requestStartPresentation();
  });
  applyPresConfigLock(); // disable unchecked-at-start boxes while presenting
}

/** Skills list — fetched lazily; the library may be empty until skill:list runs
 *  (it's normally loaded only when the Skills pane opens). Imported .gsk skills
 *  appear here too. */
async function renderPresentationSkills(): Promise<void> {
  const list = document.getElementById('pres-skills-list');
  if (!list) return;
  if (skillsLibrary.length === 0) {
    try { await fetchSkillsLibrary(); } catch { /* leave to empty-state */ }
  }
  if (!list.isConnected) return;
  const skills = skillsLibrary.slice().sort((a, b) => skillDisplayName(a.label).localeCompare(skillDisplayName(b.label)));
  if (skills.length === 0) { list.innerHTML = '<p class="pres-empty">No skills trained or imported yet.</p>'; return; }
  list.innerHTML = skills.map((s) => presCheckboxRow(
    presState.allow.skills.has(s.sourceId),
    `data-pres-pick="skill" data-id="${escape(s.sourceId)}"`,
    skillDisplayName(s.label),
    s.engramName,
    `skill:${s.sourceId}`,
  )).join('');
  list.querySelectorAll<HTMLInputElement>('input[data-pres-pick]').forEach((cb) => {
    cb.addEventListener('change', () => onPresPickChange(cb));
  });
  applyPresConfigLock();
  // Refresh the Skills section head now that we know the real count (so the
  // Select-all button appears once the library has loaded).
  const head = list.closest('.pres-section')?.querySelector('.pres-section-head');
  if (head) head.outerHTML = presSectionHead('Skills', 'skill', `${presState.allow.skills.size} selected`, skills.length > 0);
  document.querySelector<HTMLButtonElement>('[data-pres-selectall="skill"]')
    ?.addEventListener('click', () => togglePresSelectAll('skill'));
}

/** Drop allowlist entries for engrams that no longer exist (deleted since they
 *  were revealed). Without this, every reveal-then-delete leaves a stale slug in
 *  the saved config forever — they pile up in the consent list and config page as
 *  raw `obsidian-notes-xxxx` ids. Persists if anything changed. */
function prunePresAllowlist(): void {
  if (loadedGraphs.length === 0) return; // engrams not loaded yet — don't prune blind
  const live = new Set(loadedGraphs.map((g) => g.graphId));
  let changed = false;
  for (const id of [...presState.allow.engrams]) {
    if (!live.has(id)) { presState.allow.engrams.delete(id); changed = true; }
  }
  if (changed) savePresentationConfig();
}

/** Build the "what will be visible" list shown in the consent modal so the user
 *  confirms against the actual items, not an abstraction. */
function presBuildConsentSummary(): string {
  prunePresAllowlist();
  const groups: Array<{ label: string; items: string[] }> = [];
  if (presState.allow.engrams.size) {
    groups.push({ label: 'Engrams', items: [...presState.allow.engrams].map((id) => engramName(id)) });
  }
  if (presState.allow.sources.size) {
    const byId = new Map(presSourcesCache.map((s) => [s.sourceId, s]));
    groups.push({ label: 'Sources', items: [...presState.allow.sources].map((id) => {
      const s = byId.get(id); return s ? (s.ref.split('/').pop() || s.ref) : id;
    }) });
  }
  if (presState.allow.skills.size) {
    const byId = new Map(skillsLibrary.map((s) => [s.sourceId, s]));
    groups.push({ label: 'Skills', items: [...presState.allow.skills].map((id) => {
      const s = byId.get(id); return s ? skillDisplayName(s.label) : id;
    }) });
  }
  if (presState.allow.goals.size) {
    const byId = new Map(brainGoals.map((g) => [g.sourceId, g]));
    groups.push({ label: 'Goals', items: [...presState.allow.goals].map((id) => byId.get(id)?.title ?? id) });
  }
  const surfaces = PRES_SURFACE_DEFS.filter((d) => presState.surfaces[d.key]).map((d) => d.label);
  if (surfaces.length) groups.push({ label: 'App surfaces', items: surfaces });

  if (groups.length === 0) {
    return '<div class="pres-consent-summary-head pres-consent-summary-empty">Nothing selected — <strong>every screen will be fully redacted.</strong></div>';
  }
  const body = groups.map((g) => `<div class="pres-consent-group"><div class="pres-consent-group-label">${escape(g.label)}</div><ul>${g.items.map((it) => `<li>${escape(it)}</li>`).join('')}</ul></div>`).join('');
  return `<div class="pres-consent-summary-head">These items will be shown in full — everything else stays redacted:</div>${body}`;
}

/** Open the consent gate. Masking only activates after the user ticks the
 *  responsibility checkbox and clicks Enter — never silently. */
function requestStartPresentation(): void {
  if (presSelectionCount() === 0
      && !confirm('You haven\'t selected anything to reveal — every screen will be fully redacted. Continue to the consent step anyway?')) {
    return;
  }
  const modal = document.getElementById('presentation-consent-modal');
  const check = document.getElementById('presentation-consent-check') as HTMLInputElement | null;
  const enter = document.getElementById('presentation-consent-enter') as HTMLButtonElement | null;
  if (!modal || !check || !enter) { startPresentation(); return; } // fail-open to feature, never block
  const summary = document.getElementById('presentation-consent-summary');
  if (summary) summary.innerHTML = presBuildConsentSummary();
  check.checked = false;
  enter.disabled = true;
  modal.classList.remove('hidden');
}

/** Confirm before LEAVING — exiting instantly un-redacts everything, so an
 *  accidental exit during a live share is the real hazard. Routes through a
 *  warning modal (falls back to native confirm if the modal is missing). */
function requestStopPresentation(): void {
  if (!presState.active) return;
  const modal = document.getElementById('presentation-exit-modal');
  if (!modal) {
    if (confirm('Exit Presentation Mode? Everything hidden becomes visible again — stop sharing your screen first.')) stopPresentation();
    return;
  }
  modal.classList.remove('hidden');
}

async function renderPresentationSources(): Promise<void> {
  const list = document.getElementById('pres-sources-list');
  if (!list) return;
  let data: StatsSummary | null = null;
  let failed = false;
  try { data = (await invoke('inspector_stats')) as StatsSummary; } catch { failed = true; }
  if (!list.isConnected) return; // page navigated away
  // A failed fetch (sidecar busy — often a consolidation pass) must NOT read as
  // "no sources ingested yet" — that's a false empty. Show loading + retry until
  // it lands; only an actual successful-but-empty result says "none".
  if (failed || data === null) {
    list.innerHTML = '<p class="pres-empty">Loading sources…</p>';
    setTimeout(() => { if (list.isConnected) void renderPresentationSources(); }, 1500);
    return;
  }
  // Archived engrams (and their sources) must never appear anywhere — drop
  // their sources before they reach the cache or the grouped display.
  const archivedGraphs = new Set(
    loadedGraphs.filter((g) => g.metadata.archived).map((g) => g.graphId),
  );
  const sources = (data?.sources ?? []).filter((s) => !archivedGraphs.has(s.graphId));
  presSourcesCache = sources; // so Select-all knows every source id
  if (sources.length === 0) { list.innerHTML = '<p class="pres-empty">No sources ingested yet.</p>'; return; }
  const byGraph = new Map<string, SourceRecord[]>();
  for (const s of sources) { (byGraph.get(s.graphId) ?? byGraph.set(s.graphId, []).get(s.graphId)!).push(s); }
  const graphOrder = [...byGraph.keys()].sort((a, b) => engramName(a).localeCompare(engramName(b)));
  list.innerHTML = graphOrder.map((gid) => {
    const rows = byGraph.get(gid)!.map((s) => {
      const file = (s.ref.split('/').pop() || s.ref).slice(0, 80);
      return presCheckboxRow(
        presState.allow.sources.has(s.sourceId),
        `data-pres-pick="source" data-id="${escape(s.sourceId)}"`,
        file,
        s.kind,
        `source:${s.sourceId}`,
      );
    }).join('');
    const grpSources = byGraph.get(gid)!;
    const sel = grpSources.filter((s) => presState.allow.sources.has(s.sourceId)).length;
    const allOn = grpSources.length > 0 && sel === grpSources.length;
    const visTag = sel > 0 ? `<span class="pres-group-visible" data-pres-group="${escape(gid)}">✓ ${sel} will be visible</span>` : `<span class="pres-group-visible hidden" data-pres-group="${escape(gid)}"></span>`;
    const grpBtn = `<button type="button" class="pres-selectall pres-grp-selectall" data-pres-grp-selectall="${escape(gid)}">${allOn ? 'Clear' : 'Select all'}</button>`;
    return `<details class="pres-source-group" data-pres-grp-engram="${escape(gid)}"><summary><span data-pres="engram:${escape(gid)}">${escape(engramName(gid))}</span> <span class="pres-row-sub">(${grpSources.length})</span>${visTag}<span class="pres-grp-summary-right">${grpBtn}</span></summary>${rows}</details>`;
  }).join('');
  list.querySelectorAll<HTMLInputElement>('input[data-pres-pick]').forEach((cb) => {
    cb.addEventListener('change', () => onPresPickChange(cb));
  });
  applyPresConfigLock();
  // Per-engram "Select all sources" — toggles every source in just that group.
  list.querySelectorAll<HTMLButtonElement>('[data-pres-grp-selectall]').forEach((btn) => {
    btn.addEventListener('click', (e) => {
      e.preventDefault(); e.stopPropagation(); // don't collapse the <details>
      togglePresSourceGroup(btn.dataset['presGrpSelectall'] ?? '', btn.closest<HTMLElement>('.pres-source-group'));
    });
  });
  // Now that sources are loaded, surface the Select-all toggle in the head.
  const head = list.closest('.pres-section')?.querySelector('.pres-section-head');
  if (head) head.outerHTML = presSectionHead('Sources', 'source', `${presState.allow.sources.size} selected`, false);
  document.querySelector<HTMLButtonElement>('[data-pres-selectall="source"]')
    ?.addEventListener('click', () => togglePresSelectAll('source'));
}

/** Apply a single checkbox change to presState, persist, and (if live) re-mask. */
function onPresPickChange(cb: HTMLInputElement): void {
  const kind = cb.dataset['presPick'];
  const id = cb.dataset['id'] ?? '';
  const on = cb.checked;
  if (kind === 'engram') { on ? presState.allow.engrams.add(id) : presState.allow.engrams.delete(id); }
  else if (kind === 'source') { on ? presState.allow.sources.add(id) : presState.allow.sources.delete(id); }
  else if (kind === 'skill') { on ? presState.allow.skills.add(id) : presState.allow.skills.delete(id); }
  else if (kind === 'goal') { on ? presState.allow.goals.add(id) : presState.allow.goals.delete(id); }
  else if (kind === 'surface') { presState.surfaces[id as PresSurface] = on; }
  savePresentationConfig();
  // Update the live section counters without a full re-render (keeps scroll).
  const body = document.getElementById('presentation-body');
  body?.querySelectorAll('.pres-section').forEach((sec) => {
    const h = sec.querySelector('h3')?.textContent;
    const meta = sec.querySelector('.pres-section-meta');
    if (!meta) return;
    if (h === 'Engrams') meta.textContent = `${presState.allow.engrams.size} selected`;
    else if (h === 'Sources') meta.textContent = `${presState.allow.sources.size} selected`;
    else if (h === 'Skills') meta.textContent = `${presState.allow.skills.size} selected`;
    else if (h === 'Goals') meta.textContent = `${presState.allow.goals.size} selected`;
  });
  const count = presSelectionCount();
  const countEl = body?.querySelector('.pres-count');
  if (countEl) countEl.textContent = `${count} item${count === 1 ? '' : 's'} selected`;
  // Update the collapsed source-group's "N will be visible" badge so the count
  // is correct even when the group's rows are hidden.
  if (kind === 'source') {
    const grp = cb.closest<HTMLElement>('.pres-source-group');
    const badge = grp?.querySelector<HTMLElement>('.pres-group-visible');
    if (badge) {
      const sel = grp!.querySelectorAll('input[data-pres-pick="source"]:checked').length;
      badge.textContent = sel > 0 ? `✓ ${sel} will be visible` : '';
      badge.classList.toggle('hidden', sel === 0);
    }
  }
  if (presState.active) { applyPresentationMasking(); presRefreshAtlas(); }
}

/** One-time wiring: the consent gate, the exit banner, and Esc-to-exit. */
function initPresentation(): void {
  loadPresentationConfig();
  // Exit paths all confirm first — leaving instantly un-redacts everything.
  document.getElementById('presentation-banner')?.addEventListener('click', () => requestStopPresentation());
  document.getElementById('presentation-banner-lock')?.addEventListener('click', () => requestStopPresentation());
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && presState.active) { e.preventDefault(); requestStopPresentation(); }
  });

  // Consent gate wiring.
  const modal = document.getElementById('presentation-consent-modal');
  const check = document.getElementById('presentation-consent-check') as HTMLInputElement | null;
  const enter = document.getElementById('presentation-consent-enter') as HTMLButtonElement | null;
  const cancel = document.getElementById('presentation-consent-cancel');
  const closeConsent = (): void => modal?.classList.add('hidden');
  check?.addEventListener('change', () => { if (enter) enter.disabled = !check.checked; });
  cancel?.addEventListener('click', closeConsent);
  enter?.addEventListener('click', () => {
    if (!check?.checked) return; // belt-and-suspenders — Enter is disabled until ticked
    closeConsent();
    startPresentation();
  });
  document.getElementById('presentation-consent-terms')?.addEventListener('click', (e) => {
    e.preventDefault();
    void invoke('plugin:opener|open_url', { url: 'https://docs.graphnosis.com/legal/terms-of-use' });
  });
  document.getElementById('presentation-consent-privacy')?.addEventListener('click', (e) => {
    e.preventDefault();
    void invoke('plugin:opener|open_url', { url: 'https://docs.graphnosis.com/legal/privacy-policy' });
  });

  // Exit gate wiring.
  const exitModal = document.getElementById('presentation-exit-modal');
  document.getElementById('presentation-exit-cancel')?.addEventListener('click', () => exitModal?.classList.add('hidden'));
  document.getElementById('presentation-exit-confirm')?.addEventListener('click', () => {
    exitModal?.classList.add('hidden');
    stopPresentation();
  });
}

function vitalityCopy(v: number): [string, string] {
  if (v >= 75) return ['Your cortex is thriving', 'Well-connected, active, and consistent — keep feeding it.'];
  if (v >= 50) return ['Your cortex is healthy', 'Solid shape. More links and activity will push it higher.'];
  if (v >= 25) return ['Your cortex is waking up', 'Add memories, connect them, and resolve duplicates to strengthen it.'];
  return ['Your cortex is dormant', 'Ingest more knowledge and let Graphnosis form connections.'];
}

function renderLbVitality(): void {
  if (!brainVitalityReport) {
    els.lbVitalityTitle.textContent = 'Computing vitality…';
    els.lbVitalityDetail.textContent = 'Analysing your cortex — score will appear shortly.';
    els.lbBrainStats.style.display = 'none';
    els.lbVitalityScore.textContent = '…';
    els.lbVitalityRing.style.setProperty('--v', '0');
    // Fast-pulse the ring so it reads as "in progress" not "broken".
    els.livingBrain.classList.add('lb-scanning');
    return;
  }
  const v = brainVitalityReport.overall;
  els.livingBrain.classList.remove('lb-scanning'); // score computed — stop the calculating pulse
  els.lbVitalityRing.style.setProperty('--v', String(v));
  els.lbVitalityScore.textContent = String(v);
  const [title, detail] = vitalityCopy(v);
  els.lbVitalityTitle.textContent = title;
  els.lbVitalityDetail.textContent = detail;

  // Temporal decay + synapse stats from the last getStatus() pull.
  if (brainStatus) {
    const decayReport = brainStatus.lastDecayReport;
    const lastDecay = brainStatus.lastRun['temporalDecay'];
    if (decayReport !== null && decayReport !== undefined) {
      els.lbStatDecayNodes.textContent = String(decayReport.nodesDecayed);
      els.lbStatDecayWhen.textContent = lastDecay ? formatRel(Date.now() - lastDecay) : 'not yet run';
      els.lbStatSynapses.textContent = String((brainStatus.sessionSynapsesFormed ?? 0) + (brainStatus.sessionAutoLinksFormed ?? 0));
      els.lbBrainStats.style.display = '';
    } else if (lastDecay) {
      els.lbStatDecayNodes.textContent = '–';
      els.lbStatDecayWhen.textContent = formatRel(Date.now() - lastDecay);
      els.lbStatSynapses.textContent = String((brainStatus.sessionSynapsesFormed ?? 0) + (brainStatus.sessionAutoLinksFormed ?? 0));
      els.lbBrainStats.style.display = '';
    }
  }
}

/** Deterministic Consolidation → "Memory health": the retrieval-quality
 *  breakdown — connectivity, integration, confidence, coherence,
 *  reinforcement activity, and the saturation-guard weight spread — plus
 *  the most recent consolidation summary. All strengthen-only. */
function renderMemoryHealth(): void {
  const host = els.lbMemoryHealth;
  const h = brainMemoryHealth;
  if (!h) {
    host.innerHTML = '<p class="lb-empty">Computing memory health…</p>';
    return;
  }
  const pct = (x: number): number => Math.round(x * 100);
  const metrics: Array<[string, string]> = [
    ['Overall', String(h.overall)],
    ['Connectivity', `${pct(h.connectivity)}%`],
    ['Integration', `${pct(h.integration)}%`],
    ['Confidence', `${pct(h.confidence)}%`],
    ['Coherence', `${pct(h.coherence)}%`],
    ['Reinforcement', `${pct(h.reinforcementActivity)}%`],
    ['Weight spread', `${pct(h.weightSpread)}%`],
  ];
  const stats = metrics.map(([label, val]) =>
    `<div class="lb-stat"><span class="lb-stat-value">${val}</span><span class="lb-stat-label">${label}</span></div>`,
  ).join('');
  const cons = brainStatus?.lastConsolidation ?? null;
  const consLine = cons
    ? `Last consolidation ${formatRel(Date.now() - cons.at)} — ${cons.inferredEdges} connection${cons.inferredEdges === 1 ? '' : 's'} inferred, ${cons.communities} cluster${cons.communities === 1 ? '' : 's'}, ${cons.edgesCleaned} dead edge${cons.edgesCleaned === 1 ? '' : 's'} cleaned.`
    : 'No consolidation cycle has run yet.';
  host.innerHTML = `
    <div class="lb-stats-row">${stats}</div>
    <p class="brain-subtitle" style="margin-top:8px;">${h.crossEngramConnections} cross-engram connection${h.crossEngramConnections === 1 ? '' : 's'} · ${h.inferredEdges} inferred edge${h.inferredEdges === 1 ? '' : 's'}</p>
    <p class="brain-subtitle">${consLine}</p>
  `;
}

/** Deterministic Consolidation → "Graphnosis Neural Network": the opt-in,
 *  non-deterministic link-predictor. A two-step inline confirm guards the
 *  enable action; once on, the user can re-run or remove all predictions. */
// Module-level cache of the Pro license status, populated by
// refreshGnnLicenseStatus() on tab activation. Lets renderNeuralNetwork
// stay synchronous while still rendering a Pro-gate state when needed.
let gnnLicenseFeatureGranted: boolean | null = null;

async function refreshGnnLicenseStatus(): Promise<void> {
  try {
    const status = await ipcLicenseStatus();
    gnnLicenseFeatureGranted = !!(
      status.valid && Array.isArray(status.features) && status.features.includes('gnn-exploration')
    );
  } catch {
    gnnLicenseFeatureGranted = false;
  }
  // Repaint so the gate state reflects the freshly-fetched license.
  renderNeuralNetwork();
  // The .GLL autonomous edge-prediction loop is gated by the SAME
  // gnn-exploration feature in the brain engine. Toggle its visibility
  // here so the section's controls don't sit clickable-but-inert for
  // free users.
  const gllUpgrade = document.getElementById('lb-gll-upgrade');
  const gllControls = document.getElementById('lb-gll-controls');
  if (gllUpgrade && gllControls) {
    const licensed = gnnLicenseFeatureGranted === true;
    gllUpgrade.classList.toggle('hidden', licensed);
    gllControls.classList.toggle('hidden', !licensed);
  }
}

function renderNeuralNetwork(): void {
  const host = els.lbNeuralNetwork;
  const st = brainNeuralNetworkStatus;
  // Pro-gate the entire GNN block when we know the user is free. The
  // sidecar already refuses enable / run for non-Pro tokens; surfacing it
  // here means the user sees the Stripe button before they click anything,
  // matching the GNN Exploration chip in MemoryStudio.
  if (gnnLicenseFeatureGranted === false) {
    host.innerHTML = `
      <div class="pro-upgrade-card" style="margin-top: 8px;">
        <h3>Graphnosis Neural Network is a Pro feature</h3>
        <p class="subtitle">Training the network and storing predicted edges is compute- and storage-heavy. It ships only on the Pro tier — your canonical memory stays untouched either way.</p>
        <div class="pro-upgrade-actions">
          <button class="primary" data-pro-upgrade-btn>Upgrade to Pro</button>
          <button class="btn-ghost" data-pro-paste-token>Paste a license token</button>
        </div>
      </div>`;
    return;
  }
  if (!st) {
    host.innerHTML = '<p class="lb-empty">Loading…</p>';
    return;
  }
  if (st.enabled) {
    const last = st.isRunning
      ? 'Training now… (this may take a few seconds and uses CPU)'
      : st.lastRun
        ? `Last run ${formatRel(Date.now() - st.lastRun.at)} — added ${st.lastRun.edgesAdded}, pruned ${st.lastRun.edgesPruned} stale.`
        : `${st.gnnEdgeCount > 0 ? 'Predictions loaded from last session. ' : ''}Scheduled to run daily; click Run again to run now.`;
    host.innerHTML = `
      <p class="brain-subtitle">Status: <strong>ON</strong> · ${st.gnnEdgeCount} predicted connection${st.gnnEdgeCount === 1 ? '' : 's'} in your cortex. ${last}</p>
      <div class="lb-goal-form-actions">
        <button data-nn="run" class="btn-sm">Run again</button>
        <button data-nn="remove" class="btn-sm">Remove all predicted connections</button>
        <button data-nn="disable" class="btn-sm">Turn off</button>
      </div>`;
  } else if (nnEnablingInProgress) {
    host.innerHTML = `
      <p class="brain-subtitle">Enabling GNN — snapshotting your engrams and training the network… This may take a moment.</p>
      <div class="lb-goal-form-actions">
        <button data-nn="cancel-enabling" class="btn-sm">Cancel</button>
      </div>`;
  } else if (nnConfirmPending) {
    host.innerHTML = `
      <p class="brain-subtitle"><strong>The neural network is non-deterministic</strong> — two runs differ. Its predictions are written to a separate encrypted overlay, never the deterministic graph, and a snapshot of every engram is saved first. You can remove all predictions at any time. Continue?</p>
      <div class="lb-goal-form-actions">
        <button data-nn="cancel" class="btn-sm">Cancel</button>
        <button data-nn="confirm" class="btn-sm primary">Snapshot &amp; enable</button>
      </div>`;
  } else {
    host.innerHTML = `
      <p class="brain-subtitle">Off. Enabling trains a small neural network on your graph and lets it predict likely-missing connections — kept in a separate encrypted overlay, never mixed into the deterministic graph.</p>
      <button data-nn="enable" class="btn-sm">Enable Graphnosis Neural Network…</button>`;
  }
  const on = (action: string, fn: () => void): void => {
    host.querySelector(`[data-nn="${action}"]`)?.addEventListener('click', fn);
  };
  on('enable', () => { nnConfirmPending = true; renderNeuralNetwork(); });
  on('cancel', () => { nnConfirmPending = false; renderNeuralNetwork(); });
  on('confirm', () => {
    nnConfirmPending = false;
    nnEnablingInProgress = true;
    renderNeuralNetwork();
    void ipcCall('brain:enableNeuralNetwork', {})
      .then(() => { nnEnablingInProgress = false; void refreshBrainState(); })
      .catch(() => { nnEnablingInProgress = false; renderNeuralNetwork(); });
  });
  on('cancel-enabling', () => {
    nnEnablingInProgress = false;
    void ipcCall('brain:disableNeuralNetwork', {}).then(() => { void refreshBrainState(); });
    renderNeuralNetwork();
  });
  on('run', () => { void ipcCall('brain:runNeuralNetwork', {}); });
  on('remove', () => {
    void ipcCall('brain:removeNeuralNetworkEdges', {}).then(() => { void refreshBrainState(); });
  });
  on('disable', () => {
    void ipcCall('brain:disableNeuralNetwork', {}).then(() => { void refreshBrainState(); });
  });
}

/** Clamp display text to `n` chars with an ellipsis. The healing journal
 *  stores FULL content snapshots (for the local-LLM review pass) — the
 *  UI only needs a readable preview. */
function clampText(s: string, n: number): string {
  return s.length > n ? `${s.slice(0, n).trimEnd()}…` : s;
}

/** Autonomous Brain → "Self-healing": a log of duplicate memories the
 *  brain merged on its own. Read-only — every merge is a recoverable
 *  soft-delete. Once a local LLM has re-judged a merge, its verdict
 *  rides alongside as a chip + note. */
/** Autonomous Brain → "Self-healing": stats only — how much the brain has
 *  merged, not a per-merge card list. Every merge is op-logged and
 *  recoverable from the Recovery panel, so the count is the at-a-glance
 *  signal; the boxes-per-issue view was noise. */
function renderLbHealingLog(): void {
  const host = els.lbHealingLog;
  const n = brainHealingJournal.length;
  if (n === 0) {
    host.innerHTML = '<p class="lb-empty">Nothing merged yet — consolidation merges exact duplicates and redundant memories automatically as it finds them.</p>';
    return;
  }
  const reviewed = brainHealingJournal.filter((r) => r.llmReviewed).length;
  host.innerHTML = `
    <div class="lb-stats-row">
      <div class="lb-stat">
        <span class="lb-stat-value">${n}</span>
        <span class="lb-stat-label">duplicate memor${n === 1 ? 'y' : 'ies'} merged</span>
      </div>
      ${reviewed > 0 ? `
      <div class="lb-stat">
        <span class="lb-stat-value">${reviewed}</span>
        <span class="lb-stat-label">re-checked by local AI</span>
      </div>` : ''}
    </div>`;
}

/** Fetch the pending pair count and update the Self-healing button badge.
 *  Called after brain scans complete and when the Brain tab is opened. */
async function refreshNeedsReviewBadge(): Promise<void> {
  if (!els.btnNeedsReview) return;
  try {
    const pairs = await ipcCall<BrainDuplicatePair[]>('brain:getDuplicatePairs', {});
    if (pairs.length === 0) {
      els.btnNeedsReview.classList.add('hidden');
    } else {
      els.needsReviewCount.textContent = String(pairs.length);
      els.btnNeedsReview.classList.remove('hidden');
    }
  } catch {
    els.btnNeedsReview.classList.add('hidden');
  }
}

/** Open the "Needs your review" overlay inside the Deterministic Consolidation
 *  tab. Fetches the current pair list, renders cards, and shows the overlay.
 *  The button in Self-healing triggers this; it never auto-opens. */
async function renderNeedsReview(): Promise<void> {
  const host = els.gNeedsReview;
  const overlay = els.needsReviewOverlay;
  if (!host || !overlay) return;
  // Show the overlay immediately so the user gets feedback before the IPC call.
  host.innerHTML = '<p class="lb-empty" style="display:flex;align-items:center;gap:8px;"><span class="boot-status-dot" style="width:8px;height:8px;flex-shrink:0;"></span>Loading memory pairs…</p>';
  overlay.classList.remove('hidden');
  let pairs: BrainDuplicatePair[];
  try {
    pairs = await ipcCall<BrainDuplicatePair[]>('brain:getDuplicatePairs', {});
  } catch {
    overlay.classList.add('hidden');
    return;
  }
  if (pairs.length === 0) {
    overlay.classList.add('hidden');
    host.innerHTML = '<p class="lb-empty">No pairs to review — everything looks good.</p>';
    els.btnNeedsReview.classList.add('hidden');
    return;
  }
  // Update overlay title with live count.
  els.needsReviewOverlayTitle.textContent =
    `Needs your review — ${pairs.length} memory pair${pairs.length === 1 ? '' : 's'}`;
  host.innerHTML = pairs.map((c) => `
    <div class="lb-dup-card">
      <div class="lb-dup-card-pair">
        <div class="lb-snippet"><span class="lb-snippet-tag">A</span>${escape(clampText(c.snippetA, 160))}</div>
        <div class="lb-snippet"><span class="lb-snippet-tag">B</span>${escape(clampText(c.snippetB, 160))}</div>
      </div>
      <div class="lb-dup-card-foot">
        <span style="display:flex; align-items:center; gap:8px; min-width:0;">
          <span class="lb-engram-chip" title="Engram">${escape(engramName(c.graphId))}</span>
          <span class="brain-subtitle">${Math.round(c.similarity * 100)}% similar</span>
        </span>
        <span class="g-nr-actions">
          <button class="btn-sm" data-nr-action="keep-both" data-nr-id="${escape(c.id)}"
            title="They're genuinely different memories — keep both, untouched.">Keep both</button>
          <button class="btn-sm primary" data-nr-action="merge" data-nr-id="${escape(c.id)}"
            title="They're the same memory — merge into one. The duplicate is soft-deleted and stays recoverable.">Same memory — merge</button>
        </span>
      </div>
    </div>`).join('');
  overlay.classList.remove('hidden');
  // Badge stays updated.
  els.needsReviewCount.textContent = String(pairs.length);
  els.btnNeedsReview.classList.remove('hidden');
  host.querySelectorAll<HTMLButtonElement>('[data-nr-action]').forEach((btn) => {
    btn.addEventListener('click', async () => {
      const id = btn.dataset['nrId'];
      const action = btn.dataset['nrAction'] as 'merge' | 'keep-both' | undefined;
      if (!id || !action) return;
      const card = btn.closest<HTMLElement>('.lb-dup-card');
      if (card) {
        card.style.maxHeight = `${card.scrollHeight}px`;
        card.classList.add('lb-healing');
        requestAnimationFrame(() => { card.style.maxHeight = '0px'; });
      }
      try { await ipcCall('brain:resolveDuplicatePair', { id, action }); } catch { /* ignore */ }
      // Re-render after the collapse animation finishes.
      window.setTimeout(() => { void renderNeedsReview(); }, card ? 560 : 0);
    });
  });
}

/** Open the contradictions review overlay (reuses the needs-review overlay
 *  shell). Each card shows the two conflicting memories with their shared
 *  entities. Resolution is asymmetric to duplicates: the user either dismisses
 *  the pair (both genuinely true / context-dependent) or asks their AI to
 *  supersede the outdated side via `edit` — we deliberately do NOT offer a
 *  one-click "delete one side" here, because picking the loser is a judgment
 *  call the correction flow (diff + approval) is built for. */
async function renderContradictionsReview(): Promise<void> {
  const host = els.gNeedsReview;
  const overlay = els.needsReviewOverlay;
  if (!host || !overlay) return;
  host.innerHTML = '<p class="lb-empty" style="display:flex;align-items:center;gap:8px;"><span class="boot-status-dot" style="width:8px;height:8px;flex-shrink:0;"></span>Loading contradictions…</p>';
  overlay.classList.remove('hidden');
  let pairs: BrainContradictionPair[];
  try {
    pairs = await ipcCall<BrainContradictionPair[]>('brain:getContradictionPairs', {});
  } catch {
    overlay.classList.add('hidden');
    return;
  }
  if (pairs.length === 0) {
    overlay.classList.add('hidden');
    void refreshHomeNeeds();
    return;
  }
  els.needsReviewOverlayTitle.textContent =
    `Contradicting memories — ${pairs.length} pair${pairs.length === 1 ? '' : 's'}`;
  host.innerHTML = pairs.map((c) => `
    <div class="lb-dup-card">
      <div class="lb-dup-card-pair">
        <div class="lb-snippet"><span class="lb-snippet-tag">A</span>${escape(clampText(c.snippetA, 160))}</div>
        <div class="lb-snippet"><span class="lb-snippet-tag">B</span>${escape(clampText(c.snippetB, 160))}</div>
      </div>
      <div class="lb-dup-card-foot">
        <span style="display:flex; align-items:center; gap:8px; min-width:0;">
          <span class="lb-engram-chip" title="Engram">${escape(engramName(c.graphId))}</span>
          <span class="brain-subtitle" title="Entities both memories mention">${escape((c.sharedEntities ?? []).slice(0, 3).join(', '))}</span>
        </span>
        <span class="g-nr-actions">
          <button class="btn-sm" data-cr-action="dismiss" data-cr-id="${escape(c.id)}"
            title="Both are true (or context-dependent) — keep both, stop flagging this pair.">Both are true</button>
          <button class="btn-sm primary" data-cr-action="resolve" data-cr-id="${escape(c.id)}"
            title="Open Power Tools to supersede the outdated side via a reviewed edit.">Resolve with an edit →</button>
        </span>
      </div>
    </div>`).join('');
  overlay.classList.remove('hidden');
  els.needsReviewCount.textContent = String(pairs.length);
  host.querySelectorAll<HTMLButtonElement>('[data-cr-action]').forEach((btn) => {
    btn.addEventListener('click', async () => {
      const id = btn.dataset['crId'];
      const action = btn.dataset['crAction'];
      if (!id || !action) return;
      if (action === 'dismiss') {
        const card = btn.closest<HTMLElement>('.lb-dup-card');
        if (card) {
          card.style.maxHeight = `${card.scrollHeight}px`;
          card.classList.add('lb-healing');
          requestAnimationFrame(() => { card.style.maxHeight = '0px'; });
        }
        try { await ipcCall('brain:dismissContradictionPair', { id }); } catch { /* ignore */ }
        window.setTimeout(() => { void renderContradictionsReview(); }, card ? 560 : 0);
      } else {
        // Route to Power Tools (manual edit / correction flow) with the
        // overlay closed — the user supersedes the outdated side there, or
        // asks their AI client to do it via the `edit` MCP tool.
        overlay.classList.add('hidden');
        activateMode('power-tools');
      }
    });
  });
}

function renderLbInsights(): void {
  const host = els.lbInsights;
  const active = brainInsights.filter((i) => !i.dismissed);
  if (active.length === 0) {
    if (brainLlmReady) {
      // Honest diagnostic line based on the last insight run. If we've never
      // run, fall back to the original "Graphnosis analyses every 6 hours" copy.
      // If the last run failed (timeout / parse-error / no-llm), tell the user
      // what happened AND that a retry is scheduled within 1 hour.
      const diag = brainStatus?.lastInsightResult;
      let diagLine: string;
      if (!diag) {
        diagLine = 'No scans completed yet — Graphnosis analyses your engrams every 6 hours and surfaces patterns, gaps, and opportunities here. Click <strong>Scan now</strong> for an immediate pass.';
      } else {
        const when = new Date(diag.at).toLocaleString();
        if (diag.status === 'ok') {
          diagLine = `Last scan completed <strong>${escape(when)}</strong> — ${diag.count > 0 ? `added ${diag.count} insight(s).` : (diag.message ? escape(diag.message) : 'nothing noteworthy this round.')} Next scheduled scan in ~6 h.`;
        } else if (diag.status === 'no-llm') {
          diagLine = `Last scan at <strong>${escape(when)}</strong> couldn't run: ${escape(diag.message ?? 'local LLM unavailable')}. We\'ll retry within 1 hour once the LLM is reachable.`;
        } else if (diag.status === 'timeout') {
          diagLine = `Last scan at <strong>${escape(when)}</strong> <strong style="color:var(--color-status-warn-gold)">timed out</strong> — ${escape(diag.message ?? 'Ollama responded too slowly')}. Retry scheduled within 1 hour.`;
        } else if (diag.status === 'parse-error') {
          diagLine = `Last scan at <strong>${escape(when)}</strong> <strong style="color:var(--color-status-warn-gold)">failed to parse</strong> — ${escape(diag.message ?? 'the LLM output was malformed')}. Retry scheduled within 1 hour.`;
        } else if (diag.status === 'no-data') {
          diagLine = `Last scan at <strong>${escape(when)}</strong> found <strong>no engrams with enough nodes</strong> to summarise — ${escape(diag.message ?? 'add more memories first')}.`;
        } else {
          diagLine = `Last scan at <strong>${escape(when)}</strong> errored: ${escape(diag.message ?? 'unknown error')}.`;
        }
      }
      host.innerHTML =
        `<p class="lb-empty">${diagLine}</p>` +
        '<div style="margin-top:8px;"><button class="btn-sm" id="lb-insight-scan-now">Scan now</button></div>';
      host.querySelector('#lb-insight-scan-now')?.addEventListener('click', () => {
        void ipcCall('brain:runScan', {}).catch(() => { /* non-fatal */ });
      });
    } else {
      // Honest empty state: insights + synapse formation are the only
      // features that need a local model. Make clear this is expected,
      // not a failure, and give a one-click route to set the model up.
      host.innerHTML =
        '<div class="lb-empty lb-needs-llm">'
        + '<p><strong>Insights need a local AI model — and none is set up yet.</strong> '
        + 'This section staying empty is expected, not a bug. The same goes for '
        + 'automatic <em>new-connection forming</em> (synapses).</p>'
        + '<p>Everything else — vitality, duplicate detection, memory decay, '
        + 'goal tracking — already works without it.</p>'
        + '<p class="brain-subtitle">Set one up in the <strong>Local LLM</strong> section '
        + 'below — free, a couple of minutes.</p>'
        + '</div>';
    }
    return;
  }
  host.innerHTML = active.map((i) => `
    <div class="lb-insight">
      <span class="lb-insight-kind">${escape(i.kind)}</span>
      <span class="lb-engram-chip" title="Engram">${escape(engramName(i.graphId))}</span>
      <div class="lb-insight-title">${escape(i.title)}</div>
      <div class="lb-insight-body">${escape(i.body)}</div>
      <div style="margin-top:6px;"><button class="btn-sm" data-dismiss-insight="${escape(i.id)}">Dismiss</button></div>
    </div>`).join('');
  host.querySelectorAll<HTMLButtonElement>('[data-dismiss-insight]').forEach((btn) => {
    btn.addEventListener('click', async () => {
      const id = btn.dataset['dismissInsight'];
      if (!id) return;
      try { await ipcCall('brain:dismissInsight', { id }); } catch { /* ignore */ }
      brainInsights = brainInsights.filter((i) => i.id !== id);
      renderLbInsights();
    });
  });
}

function renderLbGoals(): void {
  const host = els.lbGoals;
  if (brainGoals.length === 0) {
    host.innerHTML = '<p class="lb-empty">No goals yet — develop one below and Graphnosis will track it.</p>';
    return;
  }
  const now = Date.now();
  host.innerHTML = brainGoals.map((g) => {
    let deadline = 'No deadline set';
    if (g.targetDate) {
      const days = Math.ceil((g.targetDate - now) / 86_400_000);
      deadline = days <= 0
        ? '<span class="lb-goal-deadline-soon">Overdue</span>'
        : days <= 7
          ? `<span class="lb-goal-deadline-soon">${days} day${days === 1 ? '' : 's'} left</span>`
          : `${days} days left`;
    }
    const milestones = g.milestones.length > 0
      ? `<div class="lb-goal-meta">Milestones: ${escape(g.milestones.slice(0, 3).join(' · '))}</div>`
      : '';
    return `<div class="lb-goal" data-goal-source="${escape(g.sourceId)}" data-goal-graph="${escape(g.graphId)}" data-goal-title="${escape(g.title)}" data-pres="goal:${escape(g.sourceId)}" data-pres-engram="${escape(g.graphId)}">
      <button class="lb-goal-delete" type="button" title="Delete this goal" aria-label="Delete goal: ${escape(g.title)}">×</button>
      <div class="lb-goal-title">${escape(g.title)}
        <span class="lb-engram-chip" title="Engram">${escape(engramName(g.graphId))}</span>
      </div>
      <div class="lb-goal-meta">${deadline}</div>
      ${milestones}
    </div>`;
  }).join('');

  // Delete buttons — confirm, then forget the backing `goal:` source. Goals
  // aren't a separate store: each is a source the SDK tagged `goal:<ts>`, so
  // deleting the source removes the goal (and its nodes) from the cortex.
  host.querySelectorAll<HTMLButtonElement>('.lb-goal-delete').forEach((btn) => {
    btn.addEventListener('click', (ev) => {
      ev.stopPropagation();
      const card = btn.closest<HTMLElement>('.lb-goal');
      const sourceId = card?.dataset['goalSource'];
      const graphId = card?.dataset['goalGraph'];
      const title = card?.dataset['goalTitle'] ?? 'this goal';
      if (!sourceId || !graphId) return;
      // In-app confirm — window.confirm() is silently swallowed by Tauri's
      // WKWebView, so deletes were going through without ever asking.
      void (async () => {
        const ok = await confirmPermanent(
          `Delete the goal “${title}”? This removes the goal and its tracked milestones from your cortex — it can’t be undone.`,
        );
        if (!ok) return;
        btn.disabled = true;
        try {
          await ipcCall('sources.forget', { graphId, sourceId });
          card?.remove();
          void refreshBrainState();
        } catch (e) {
          btn.disabled = false;
          console.warn('[goals] delete failed', e);
        }
      })();
    });
  });
}

/** Show the empty-state line only when the feed has no real activity items. */
function ensureFeedPlaceholder(): void {
  if (!els.lbFeed.querySelector('.lb-feed-item')) {
    els.lbFeed.innerHTML =
      '<p class="lb-empty">No recent activity yet — Graphnosis scans in the background every few minutes.</p>';
  }
}

/** Cap the activity feed so it doesn't grow unbounded. */
function trimFeed(): void {
  while (els.lbFeed.querySelectorAll('.lb-feed-item').length > 25) {
    els.lbFeed.querySelector('.lb-feed-item:last-child')?.remove();
  }
}

/** Add a "<phase>…" row to the activity feed when a scan loop starts. */
function addFeedStart(phase: string): void {
  // A loop's start frame can arrive while a prior run of the same phase is
  // still in flight — don't stack duplicate "…" rows for it.
  if (els.lbFeed.querySelector(
    `.lb-feed-item[data-phase="${CSS.escape(phase)}"].brain-thinking`,
  )) return;
  els.lbFeed.querySelector('.lb-empty')?.remove();
  const label = BRAIN_PHASE_LABELS[phase] ?? phase;
  const item = document.createElement('div');
  item.className = 'lb-feed-item brain-thinking';
  item.dataset['phase'] = phase;
  item.textContent = `${label}… · ${new Date().toLocaleTimeString()}`;
  els.lbFeed.prepend(item);
  trimFeed();
}

/** Mark the matching feed row done when a scan loop finishes. */
function addFeedDone(phase: string): void {
  const item = els.lbFeed.querySelector<HTMLElement>(
    `.lb-feed-item[data-phase="${CSS.escape(phase)}"].brain-thinking`,
  );
  if (item) {
    item.classList.remove('brain-thinking');
    const label = BRAIN_PHASE_LABELS[phase] ?? phase;
    item.textContent = `${label} — done · ${new Date().toLocaleTimeString()}`;
  }
}

/** (6) Ring ripple + a distinct feed row when the brain forms a synapse. */
function flashSynapse(): void {
  els.lbVitalityRing.classList.remove('lb-synapse-pulse');
  void els.lbVitalityRing.offsetWidth; // reflow so the animation restarts
  els.lbVitalityRing.classList.add('lb-synapse-pulse');
  setTimeout(() => els.lbVitalityRing.classList.remove('lb-synapse-pulse'), 1000);
  els.lbFeed.querySelector('.lb-empty')?.remove();
  const item = document.createElement('div');
  item.className = 'lb-feed-item lb-feed-synapse';
  item.textContent = `⚡ New connection formed · ${new Date().toLocaleTimeString()}`;
  els.lbFeed.prepend(item);
  trimFeed();
}

function handleBrainFrame(graphId: string): void {
  if (graphId.startsWith('__brain_start_')) {
    const phase = graphId.slice('__brain_start_'.length, -2);
    brainActivePhases.add(phase);
    els.livingBrain.classList.add('lb-scanning');
    // 'fullscan' is the wrapper — it drives the scanning state but isn't a
    // feed row of its own; the sub-phases provide the feed detail.
    if (phase !== 'fullscan') addFeedStart(phase);
    renderScanStatus();
    renderStatusProcess();
    refreshPillPulse();
  } else if (graphId.startsWith('__brain_done_')) {
    // phase is '' for the bare '__brain_done__' vitality frame.
    const phase = graphId.slice('__brain_done_'.length, -2);
    if (phase) {
      brainActivePhases.delete(phase);
      if (phase !== 'fullscan') addFeedDone(phase);
    }
    if (brainActivePhases.size === 0) els.livingBrain.classList.remove('lb-scanning');
    renderStatusProcess();
    // The event channel only carries graphId + ts — pull the fresh state.
    void refreshBrainState();
    void refreshBrainStatus();
    // A completed scan may have changed the needs-review queue — update the badge.
    void refreshNeedsReviewBadge();
    renderScanStatus();
    refreshPillPulse();
  } else if (graphId === '__brain_synapse__') {
    flashSynapse();
  } else if (graphId === '__brain_duplicate__' || graphId === '__brain_goal__') {
    void refreshBrainState();
  }
}

// "Scan now" — trigger a fresh full self-scan and repaint. The scan emits
// frames that drive the scanning visuals; this just kicks it off.
els.btnLbRefresh.addEventListener('click', () => {
  void ipcCall('brain:runScan', {}).catch(() => { /* non-fatal */ });
  void renderLivingBrain();
});

// "Needs your review" button — opens the overlay.
els.btnNeedsReview.addEventListener('click', () => { void renderNeedsReview(); });
// Close button inside the overlay — hides it, leaves the badge count intact.
els.btnNeedsReviewClose.addEventListener('click', () => {
  els.needsReviewOverlay.classList.add('hidden');
});

// ── (3) Scan-status countdown line ─────────────────────────────────────────

/** Pull scan status (lastRun + intervals + scanning) into the module cache. */
async function refreshBrainStatus(): Promise<void> {
  try {
    brainStatus = await ipcCall<NonNullable<typeof brainStatus>>('brain:getStatus', {});
  } catch { /* non-fatal */ }
}

function formatRel(ms: number): string {
  const s = Math.floor(ms / 1000);
  if (s < 45) return 'just now';
  const m = Math.floor(s / 60);
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  return `${Math.floor(h / 24)}d ago`;
}

function formatCountdown(ms: number): string {
  const s = Math.max(0, Math.floor(ms / 1000));
  const m = Math.floor(s / 60);
  if (m >= 60) return `${Math.floor(m / 60)}h ${m % 60}m`;
  return `${m}:${String(s % 60).padStart(2, '0')}`;
}

/** Repaint the scan-status line: the live phase while scanning, otherwise a
 *  countdown to the next automatic background self-check. */
/** Human "20 min" / "4 h" for a millisecond interval. */
function formatInterval(ms: number): string {
  const min = Math.round(ms / 60000);
  if (min < 60) return `${min} min`;
  return `${Math.round(min / 60)} h`;
}

/** Autonomous Brain → "Recent brain activity": a one-line summary of how
 *  often each background check runs, so the cadence is never a mystery.
 *  Read live from brainStatus.intervals so it tracks the real constants. */
function renderBrainSchedule(): void {
  const iv = brainStatus?.intervals;
  if (!iv) {
    els.lbSchedule.textContent = 'Background checks run automatically while the app is open.';
    return;
  }
  const parts: string[] = [];
  if (iv['duplicateScan']) parts.push(`duplicate scan every ${formatInterval(iv['duplicateScan'])}`);
  if (iv['reinforce'])     parts.push(`reinforcement every ${formatInterval(iv['reinforce'])}`);
  if (iv['synapse'])       parts.push(`new connections every ${formatInterval(iv['synapse'])}`);
  if (iv['crossEngram'])   parts.push(`engram linking every ${formatInterval(iv['crossEngram'])}`);
  if (iv['consolidation']) parts.push(`consolidation every ${formatInterval(iv['consolidation'])}`);
  if (iv['goalCheck'])     parts.push(`goal check every ${formatInterval(iv['goalCheck'])}`);
  if (iv['insight'])       parts.push(`insights every ${formatInterval(iv['insight'])}`);
  els.lbSchedule.textContent = parts.length > 0
    ? `Runs on its own — ${parts.join(' · ')}.`
    : 'Background checks run automatically while the app is open.';
}

function renderScanStatus(): void {
  const el = els.lbScanStatus;
  if (brainActivePhases.size > 0) {
    const phase = [...brainActivePhases].filter((p) => p !== 'fullscan').pop() ?? 'fullscan';
    el.textContent = `🔬 ${BRAIN_PHASE_LABELS[phase] ?? 'Scanning'}…`;
    return;
  }
  const last = brainStatus?.lastRun?.['duplicateScan'];
  const interval = brainStatus?.intervals?.['duplicateScan'] ?? 20 * 60 * 1000;
  if (!last) {
    el.textContent = '🩺 Background self-checks run automatically';
    return;
  }
  const now = Date.now();
  const until = last + interval - now;
  const rel = formatRel(now - last);
  el.textContent = until <= 0
    ? `🩺 Last self-check ${rel} · next scan due now`
    : `🩺 Last self-check ${rel} · next in ${formatCountdown(until)}`;
}

function startScanTicker(): void {
  if (scanTickerTimer) return;
  renderScanStatus();
  scanTickerTimer = setInterval(renderScanStatus, 1000);
}

function stopScanTicker(): void {
  if (scanTickerTimer) { clearInterval(scanTickerTimer); scanTickerTimer = null; }
}

// ── (7) Ambient neuron field ───────────────────────────────────────────────
//
// Nodes drift very slowly across the full hero background like a living
// cortex map. No attraction — pure Brownian motion. Each node pulses in
// radius independently. Nodes allowed to drift beyond edges (canvas clips).
const neuronField = (() => {
  const CLUSTER_COLORS = [
    '#a78bfa', // violet
    '#6ab3c8', // teal
    '#f472b6', // pink
    '#4ade80', // green
    '#fb923c', // amber
    '#60a5fa', // blue
  ];
  const CLUSTER_COUNT  = CLUSTER_COLORS.length;
  const COUNT          = 56;    // nodes filling the background
  const LINK_DIST      = 130;   // edge drawn when two nodes are within this distance
  const WANDER         = 0.032; // random velocity nudge each tick — keeps drift very slow
  const DAMPING        = 0.996; // high damping → terminal speed stays tiny
  const BASE_R         = 2.4;   // node base radius (px)
  const PULSE_AMP      = 1.6;   // radius oscillates ±1.6 px
  const PULSE_SPD_MIN  = 0.005; // slowest pulse cycle
  const PULSE_SPD_MAX  = 0.018; // fastest pulse cycle
  const RESEED_MARGIN  = 140;   // re-seed a node when it drifts this far outside canvas

  interface NeuronNode {
    x: number; y: number; vx: number; vy: number;
    cluster: number;
    phase: number;      // current pulse phase (radians)
    phaseSpd: number;   // pulse speed (rad/tick)
  }
  interface Pulse { from: number; to: number; t: number; }

  let ctx: CanvasRenderingContext2D | null = null;
  let raf = 0;
  let running = false;
  let w = 0;
  let h = 0;
  let nodes: NeuronNode[] = [];
  let pulses: Pulse[] = [];

  function hex2rgba(hex: string, alpha: number): string {
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    return `rgba(${r},${g},${b},${alpha.toFixed(3)})`;
  }

  function resize(): void {
    const cv = els.lbNeuronCanvas;
    const parent = cv.parentElement;
    if (!parent) return;
    const pw = parent.clientWidth;
    const ph = parent.clientHeight;
    if (pw === 0 || ph === 0) return;
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    w = pw;
    h = ph;
    cv.width  = Math.round(w * dpr);
    cv.height = Math.round(h * dpr);
    ctx = cv.getContext('2d');
    ctx?.setTransform(dpr, 0, 0, dpr, 0, 0);
  }

  function makeNode(ci: number): NeuronNode {
    return {
      x: Math.random() * w,
      y: Math.random() * h,
      vx: (Math.random() - 0.5) * 0.3,
      vy: (Math.random() - 0.5) * 0.3,
      cluster: ci,
      phase: Math.random() * Math.PI * 2,
      phaseSpd: PULSE_SPD_MIN + Math.random() * (PULSE_SPD_MAX - PULSE_SPD_MIN),
    };
  }

  function seed(): void {
    nodes = [];
    for (let i = 0; i < COUNT; i++) nodes.push(makeNode(i % CLUSTER_COUNT));
    pulses = [];
  }

  function tick(): void {
    if (!running || !ctx) return;
    ctx.clearRect(0, 0, w, h);

    // Physics: pure slow Brownian drift, no walls, no attraction.
    for (const n of nodes) {
      n.vx += (Math.random() - 0.5) * WANDER;
      n.vy += (Math.random() - 0.5) * WANDER;
      n.vx *= DAMPING;
      n.vy *= DAMPING;
      n.x  += n.vx;
      n.y  += n.vy;
      // Advance pulse phase.
      n.phase = (n.phase + n.phaseSpd) % (Math.PI * 2);
      // Re-seed from a random inside position if node drifts too far outside.
      if (n.x < -RESEED_MARGIN || n.x > w + RESEED_MARGIN ||
          n.y < -RESEED_MARGIN || n.y > h + RESEED_MARGIN) {
        const replacement = makeNode(n.cluster);
        n.x = replacement.x; n.y = replacement.y;
        n.vx = replacement.vx; n.vy = replacement.vy;
      }
    }

    // Edges — same-cluster: colored; cross-cluster: dim gray.
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const a = nodes[i]!;
        const b = nodes[j]!;
        const d = Math.hypot(a.x - b.x, a.y - b.y);
        if (d >= LINK_DIST) continue;
        const fade = 1 - d / LINK_DIST;
        if (a.cluster === b.cluster) {
          ctx.strokeStyle = hex2rgba(CLUSTER_COLORS[a.cluster]!, 0.30 * fade);
          ctx.lineWidth   = 0.85;
        } else {
          ctx.strokeStyle = `rgba(155,165,185,${0.07 * fade})`;
          ctx.lineWidth   = 0.45;
        }
        ctx.beginPath();
        ctx.moveTo(a.x, a.y);
        ctx.lineTo(b.x, b.y);
        ctx.stroke();
      }
    }

    // Nodes — pulsing radius via per-node sine wave.
    for (const n of nodes) {
      const r = BASE_R + PULSE_AMP * Math.sin(n.phase);
      ctx.fillStyle = hex2rgba(CLUSTER_COLORS[n.cluster]!, 0.70);
      ctx.beginPath();
      ctx.arc(n.x, n.y, Math.max(0.5, r), 0, Math.PI * 2);
      ctx.fill();
    }

    // Synapses — frequent slow-traveling pulse dots between nearby nodes.
    // Spawn up to a few per tick so the field feels alive with directed traffic.
    const spawnAttempts = 3;
    for (let s = 0; s < spawnAttempts; s++) {
      if (Math.random() < 0.10 && nodes.length > 1 && pulses.length < 24) {
        // Prefer nearby pairs so the directed edge feels meaningful (rides
        // along an actual link). Sample a few candidates and pick the closest.
        const from = Math.floor(Math.random() * nodes.length);
        let to = -1;
        let bestD = Infinity;
        for (let k = 0; k < 5; k++) {
          const cand = Math.floor(Math.random() * nodes.length);
          if (cand === from) continue;
          const d = Math.hypot(nodes[from]!.x - nodes[cand]!.x, nodes[from]!.y - nodes[cand]!.y);
          if (d < bestD) { bestD = d; to = cand; }
        }
        if (to >= 0) pulses.push({ from, to, t: 0 });
      }
    }
    pulses = pulses.filter((p) => p.t <= 1);
    for (const p of pulses) {
      p.t += 0.014; // slow, deliberate travel
      const a = nodes[p.from]!;
      const b = nodes[p.to]!;
      const x = a.x + (b.x - a.x) * p.t;
      const y = a.y + (b.y - a.y) * p.t;
      ctx.fillStyle = 'rgba(120,230,255,0.90)';
      ctx.beginPath();
      ctx.arc(x, y, 2.5, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = 'rgba(120,230,255,0.15)';
      ctx.beginPath();
      ctx.arc(x, y, 7, 0, Math.PI * 2);
      ctx.fill();
    }

    raf = requestAnimationFrame(tick);
  }

  function start(): void {
    if (running) return;
    // If the canvas or its parent isn't in the layout tree yet, retry next frame.
    if (els.lbNeuronCanvas.offsetParent === null) {
      requestAnimationFrame(() => start());
      return;
    }
    resize();
    if (w === 0 || h === 0) {
      requestAnimationFrame(() => start());
      return;
    }
    seed();
    running = true;
    tick();
  }

  function stop(): void {
    running = false;
    cancelAnimationFrame(raf);
  }

  return {
    start,
    stop,
    resize,
    get running(): boolean { return running; },
  };
})();

window.addEventListener('resize', () => { if (neuronField.running) neuronField.resize(); });
document.addEventListener('visibilitychange', () => {
  if (document.hidden) neuronField.stop();
  else if (graphnosisActiveTab === 'brain') neuronField.start();
});

// ── LLM / Ollama settings ─────────────────────────────────────────────────

/** Two-step inline confirm flag for enabling the (non-deterministic) local
 *  LLM — mirrors `nnConfirmPending` for the neural network. */
let llmConfirmPending = false;

/**
 * Render the local-LLM master switch into #llm-enable-block. The LLM is
 * opt-in: a running Ollama is never enough to turn it on. Mirrors the neural
 * network's flow — a two-step confirm guards the non-deterministic opt-in;
 * once on, a one-click Turn off.
 */
function renderLlmEnableBlock(reachable: boolean, hasModels: boolean, enabled: boolean): void {
  const host = els.llmEnableBlock;
  const setupDone = reachable && hasModels;

  if (llmConfirmPending) {
    // Confirmation state: show an inline card explaining the non-determinism
    // risk; Cancel bounces back, Confirm enables.
    host.innerHTML =
      `<div class="llm-confirm-inline">`
      + `<p><strong>Before you enable the local LLM</strong> — the local AI model is non-deterministic. `
      + `The same memory can yield slightly different results across runs. `
      + `Everything runs entirely on your device; nothing is sent to the cloud. `
      + `A snapshot of your cortex is saved before the first enable.</p>`
      + `<div class="lb-goal-form-actions">`
      + `<button data-llm="cancel" class="btn-sm">Cancel</button>`
      + `<button data-llm="confirm" class="btn-sm primary">Enable Local LLM</button>`
      + `</div>`
      + `</div>`;
  } else {
    // Normal state: compact card with checkbox toggle. The right-hand status
    // chip combines two signals so the user never confuses "Ollama is
    // reachable" with "the master LLM toggle is on" — both have to be true
    // for any LLM-backed feature (insights, synapses, edge prediction) to
    // actually work. Previous wording ("● Ollama connected" alone) misled
    // users into thinking the LLM was on when only Ollama was up.
    const dimmed = setupDone ? '' : ' style="opacity: 0.55;"';
    const statusChip = (() => {
      if (!reachable) return `<span class="llm-enable-card-status" style="color: var(--err, #d04a4a);">● Ollama not detected</span>`;
      if (!hasModels)  return `<span class="llm-enable-card-status" style="color: #d6a728;">● Ollama up · no model installed</span>`;
      if (!enabled)    return `<span class="llm-enable-card-status" style="color: #d6a728;">● Ollama ready · master toggle OFF</span>`;
      return `<span class="llm-enable-card-status" style="color: var(--ok, #3aa67a);">● ON · Ollama ready</span>`;
    })();
    const recheckBtn = `<button data-llm="recheck" class="btn-sm" style="margin-left:10px;">Recheck</button>`;
    const subtitle = !setupDone
      ? '<p class="brain-subtitle" style="margin: 6px 0 0; padding: 0 14px 12px;">Finish the Ollama setup below to enable the local LLM.</p>'
      : enabled
        ? '<p class="brain-subtitle" style="margin: 6px 0 0; padding: 0 14px 12px;">On — Graphnosis is routing the enabled capabilities through your local model. Runs entirely on your device.</p>'
        : '<p class="brain-subtitle" style="margin: 6px 0 0; padding: 0 14px 12px;">Off — check the box on the left to enable. Graphnosis won\'t route any memory through the local LLM until you do.</p>';

    host.innerHTML =
      `<div class="llm-enable-card${enabled ? ' llm-card-active' : ''}"${dimmed}>`
      + `<label class="llm-enable-card-label" style="cursor: ${setupDone ? 'pointer' : 'not-allowed'};">`
      + `<input type="checkbox" data-llm="toggle" ${enabled ? 'checked' : ''} ${setupDone ? '' : 'disabled'} />`
      + `<strong>Local LLM</strong>`
      + `</label>`
      + `<span style="display:flex; align-items:center; gap:8px;">`
      + statusChip
      + `<span class="studio-llm-loopback" title=""></span>`
      + recheckBtn
      + `</span>`
      + `</div>`
      + subtitle;
    // Sync the newly-rendered loopback chip with the current backend state
    // (the global click handler already routes its click to the explainer).
    if (studioActiveBackend) updateLoopbackBadge(studioActiveBackend.baseUrl);
  }

  const on = (action: string, fn: (ev: Event) => void): void => {
    host.querySelector(`[data-llm="${action}"]`)?.addEventListener('click', fn);
  };
  on('toggle', (ev) => {
    const cb = ev.currentTarget as HTMLInputElement;
    if (!setupDone) { cb.checked = false; return; }
    if (cb.checked && !enabled) {
      // Turning on requires a one-time confirmation — bounce checkbox back.
      cb.checked = false;
      llmConfirmPending = true;
      renderLlmEnableBlock(reachable, hasModels, enabled);
    } else if (!cb.checked && enabled) {
      void ipcCall('llm:setEnabled', { enabled: false }).then(() => { void refreshLlmStatus(); });
    }
  });
  on('recheck', () => { void refreshLlmStatus(); });
  on('cancel', () => { llmConfirmPending = false; renderLlmEnableBlock(reachable, hasModels, enabled); });
  on('confirm', () => {
    llmConfirmPending = false;
    void ipcCall('llm:setEnabled', { enabled: true }).then(() => { void refreshLlmStatus(); });
  });
}

/**
 * Refresh the layered-intelligence pills in the status bar. Each pill is
 * visible only when its corresponding capability is on:
 *   - GLL pill ⇒ master Local LLM toggle is on
 *   - GNN pill ⇒ Graphnosis Neural Network is on
 *
 * Both pills are click-through to the Foresight tab where the
 * relevant toggle lives. Cheap function — called from refreshLlmStatus AND
 * refreshBrainState so the pills react to either kind of state change.
 */
function refreshLayerPills(): void {
  const llmOn = brainLlmReady;
  const gnnOn = brainNeuralNetworkStatus?.enabled === true;
  if (els.statusGllPill) {
    els.statusGllPill.classList.toggle('pill-inactive', !llmOn);
  }
  if (els.statusGnnPill) {
    els.statusGnnPill.classList.toggle('pill-inactive', !gnnOn);
  }
  refreshPillPulse();
}

/**
 * Pulsate GLL/GNN pills while their engines are actively doing background
 * work. GLL pulses when any brain phase is running (all phases invoke the
 * local LLM). GNN pulses when the neural-network isRunning flag is set.
 * Both are gated on the pill being active (enabled) first.
 */
function refreshPillPulse(): void {
  const gllBusy = brainLlmReady && brainActivePhases.size > 0;
  const gnnBusy = brainNeuralNetworkStatus?.enabled === true &&
    (brainNeuralNetworkStatus?.isRunning === true || brainActivePhases.has('gnn'));
  if (els.statusGllPill) {
    els.statusGllPill.classList.toggle('pill-pulsing', gllBusy);
  }
  if (els.statusGnnPill) {
    els.statusGnnPill.classList.toggle('pill-pulsing', gnnBusy);
  }
}

interface LlmCapabilityFlags {
  recallEnrichment: boolean;
  correctionParsing: boolean;
  distillation: boolean;
  insights: boolean;
  edgePrediction: boolean;
}

/**
 * Per-capability checkboxes under the master Local LLM toggle. Each capability
 * maps to one of the side-effect classes:
 *   - Recall enrichment: NO graph mutation (query rewrite at recall time)
 *   - Correction parsing: proposes diffs the user must approve
 *   - Distillation: returns text to the AI client
 *   - Insights: writes only to the LLM event/overlay layer
 *   - Edge prediction: opt-in autonomous loop, writes to .gll overlay
 *
 * The whole block is dimmed (and inputs disabled) when the master switch is
 * off — turning master on restores prior per-capability choices because the
 * settings are persisted independently.
 */
function renderLlmCapabilityBlock(masterEnabled: boolean, caps: LlmCapabilityFlags | undefined): void {
  const hostEl = els.llmCapBlock;
  if (!hostEl) return;
  // No caps from older sidecars — leave the block empty rather than guessing.
  if (!caps) { hostEl.innerHTML = ''; return; }
  const dim = masterEnabled ? '' : ' opacity: 0.5;';
  const disabledAttr = masterEnabled ? '' : 'disabled';
  const row = (id: keyof LlmCapabilityFlags, title: string, blurb: string): string =>
    `<label class="llm-cap-row" style="display:flex; gap:10px; align-items:flex-start; padding:8px 14px; cursor:${masterEnabled ? 'pointer' : 'not-allowed'};">`
    + `<input type="checkbox" data-cap="${id}" ${caps[id] ? 'checked' : ''} ${disabledAttr} style="margin-top:3px;" />`
    + `<span style="display:flex; flex-direction:column; gap:2px;">`
    + `<strong style="font-size:13px;">${title}</strong>`
    + `<span class="brain-subtitle" style="font-size:12px; margin:0;">${blurb}</span>`
    + `</span>`
    + `</label>`;
  hostEl.innerHTML =
    `<div class="llm-cap-card" style="border:1px solid var(--border); border-radius:8px;${dim}">`
    + `<div style="padding:10px 14px 6px; font-size:11px; text-transform:uppercase; letter-spacing:0.08em; color:var(--muted);">Capabilities</div>`
    + row('recallEnrichment', 'Enrich recall queries',
          'Rewrites your query at recall time — adds synonyms, translates across languages, strips framing. <em>No changes to your memory.</em>')
    + row('correctionParsing', 'Parse corrections',
          'Upgrades the <code>correct</code> tool to author multi-memory diffs. You always review and approve before anything is written.')
    + row('distillation', 'Distill facts from text',
          'Lets AI clients call <code>llm_distill</code> to extract structured facts from raw text.')
    + row('insights', 'Surface insights and predictions',
          'Background loop that finds patterns, gaps, and opportunities. Powers <code>insights</code>, <code>develop</code>, <code>predict</code>, <code>llm_query</code>. Writes only to the LLM overlay, never to your engrams.')
    + row('edgePrediction', 'Predict edges autonomously',
          'Opt-in. A background loop proposes new connections between co-recalled memories. Predictions land in the <code>.gll</code> overlay — separate from your canonical engram, fully reversible.')
    + `</div>`;
  hostEl.querySelectorAll<HTMLInputElement>('input[data-cap]').forEach((cb) => {
    cb.addEventListener('change', () => {
      const capability = cb.dataset.cap as keyof LlmCapabilityFlags;
      const enabled = cb.checked;
      void ipcCall('llm:setCapability', { capability, enabled })
        .then(() => { void refreshLlmStatus(); })
        .catch(() => { void refreshLlmStatus(); });
    });
  });
}

async function refreshLlmStatus(): Promise<void> {
  try {
    const status = await ipcCall<{
      ollamaReachable: boolean;
      installedModels: string[];
      activeModel: string | null;
      enabled: boolean;
      capabilities?: LlmCapabilityFlags;
      catalog?: Array<{ id: string; name: string }>;
      backend?: { id: string; displayName: string; baseUrl: string; api: string; processNames: string[]; knownExternalHosts: string[]; defaultPort: number };
    }>('llm:status', {});

    // MemoryStudio loopback badge — drives the green/amber pill in the LLM
    // panel header. Updated on every llm:status refresh so changes to the
    // backend URL (e.g. user points to a remote Ollama) reflect immediately.
    if (status.backend) {
      // If the backend URL/process changed, reset the session probe flag AND
      // drop any stored verification record — a new backend needs fresh
      // verification before we can claim "Last verified" again.
      const changed = studioActiveBackend?.baseUrl !== status.backend.baseUrl
        || studioActiveBackend?.id !== status.backend.id;
      if (changed) {
        studioSessionProbeOK = false;
        const stored = loadVerification();
        if (stored && (stored.baseUrl !== status.backend.baseUrl || stored.backendId !== status.backend.id)) {
          clearVerification();
        }
      }
      studioActiveBackend = status.backend;
      updateLoopbackBadge(status.backend.baseUrl);
    }

    localLlmReachable = status.ollamaReachable;

    if (status.ollamaReachable) {
      els.ollamaStatusBadge.textContent = '● Connected';
      els.ollamaStatusBadge.className = 'ok';
      els.ollamaPullRow.style.display = 'flex';
      els.ollamaNotInstalled.style.display = 'none';
      els.ollamaConnectedHelp.style.display = '';

      const hasModels = status.installedModels.length > 0;
      // Background brain features (insights, synapse formation) need Ollama up,
      // a model installed, AND the user's explicit opt-in toggle.
      brainLlmReady = hasModels && status.enabled;
      // On-demand search features (Synthesize, Enhanced ranking) only need
      // Ollama up + a model — no master-switch required.
      ollamaReadyForSearch = hasModels;
      syncSearchLlmCheckboxes();
      // Active-model row is only useful once at least one model is installed.
      els.ollamaModelRow.style.display = hasModels ? 'flex' : 'none';
      els.ollamaConnectedHelp.innerHTML = hasModels
        ? '✅ Ollama is connected. To add another model, pick it below and click '
          + '<strong>Pull</strong>. To switch which model Graphnosis uses, choose it '
          + 'as the <strong>Active model</strong> and click <strong>Apply</strong>.'
        : '✅ Ollama is connected — last step. Pick a model below and click '
          + '<strong>Pull</strong> to download it (one-time). '
          + '<strong>Llama 3.2 3B</strong> is the recommended starting point. '
          + 'Then turn the local LLM on at the top of this section.';

      // Populate model selector
      els.ollamaModelSelect.innerHTML = '';
      for (const m of status.installedModels) {
        const opt = document.createElement('option');
        opt.value = m;
        opt.textContent = m;
        if (m === status.activeModel) opt.selected = true;
        els.ollamaModelSelect.appendChild(opt);
      }
      renderLlmEnableBlock(true, hasModels, status.enabled);
      renderLlmCapabilityBlock(status.enabled, status.capabilities);
    } else {
      els.ollamaStatusBadge.textContent = '● Not detected';
      els.ollamaStatusBadge.className = 'err';
      els.ollamaModelRow.style.display = 'none';
      els.ollamaPullRow.style.display = 'none';
      els.ollamaConnectedHelp.style.display = 'none';
      els.ollamaNotInstalled.style.display = '';
      brainLlmReady = false;
      ollamaReadyForSearch = false;
      syncSearchLlmCheckboxes();
      renderLlmEnableBlock(false, false, status.enabled);
      renderLlmCapabilityBlock(status.enabled, status.capabilities);
    }
    renderRailGetConnected();
    refreshLayerPills();
  } catch { /* non-fatal */ }
  // Outside the try so a failure earlier in refreshLlmStatus doesn't skip the
  // badge refresh — the helper makes its own llm:status call and is the
  // single source of truth for the Edit/Correct "LLM-assisted" pill.
  void refreshStudioLlmBadge();
}

// "Recheck" — re-probe Ollama after the user installs/starts it, without
// having to close and reopen Settings.
els.btnOllamaRecheck.addEventListener('click', () => {
  els.ollamaStatusBadge.textContent = 'Checking…';
  els.ollamaStatusBadge.className = '';
  void refreshLlmStatus();
});

// Platform tabs inside Prefer the Terminal? — flip the visible pane and
// aria-selected based on the clicked tab. Delegated so we don't bind one
// listener per tab.
document.addEventListener('click', (ev) => {
  const target = ev.target as HTMLElement | null;
  if (!target?.matches('.ollama-cli-tab')) return;
  const tabId = target.dataset.cliTab;
  if (!tabId) return;
  const root = target.closest('.ollama-cli-box');
  if (!root) return;
  root.querySelectorAll<HTMLElement>('.ollama-cli-tab').forEach((t) => {
    t.setAttribute('aria-selected', t.dataset.cliTab === tabId ? 'true' : 'false');
  });
  root.querySelectorAll<HTMLElement>('.ollama-cli-pane').forEach((p) => {
    p.style.display = p.dataset.cliPane === tabId ? '' : 'none';
  });
});

els.btnOllamaApplyModel.addEventListener('click', async () => {
  const model = els.ollamaModelSelect.value;
  if (!model) return;
  try {
    await ipcCall('llm:setModel', { model });
    els.settingsFooterNote.textContent = `Model set to ${model}`;
  } catch (e) {
    els.settingsFooterNote.textContent = `Failed: ${(e as Error).message}`;
  }
});

// Live progress for `ollama pull`, streamed line-by-line from the sidecar.
interface LlmPullProgressPayload {
  model: string;
  status?: string;
  completed?: number;
  total?: number;
}
void listen<LlmPullProgressPayload>('graphnosis://llm-pull-progress', (evt) => {
  const p = evt.payload;
  els.ollamaPullProgress.style.display = '';
  if (p.completed && p.total && p.total > 0) {
    const pct = Math.round((p.completed / p.total) * 100);
    els.ollamaPullBar.style.width = `${pct}%`;
    els.ollamaPullLabel.textContent = `${p.status ?? 'Downloading'} — ${pct}%`;
  } else {
    els.ollamaPullLabel.textContent = p.status ?? 'Downloading…';
  }
});

// ── Embedding model switch progress ────────────────────────────────────────
//
// Driven by the 'embedding.switch-progress' event channel forwarded from the
// sidecar. Phases: 'snapshot' → 'downloading-model' → 'reembedding' (per-
// engram counter) → 'done'. The modal is opened by the Settings → Search
// model Apply button (openEmbeddingProgressModal).
interface EmbeddingSwitchProgressPayload {
  phase: 'snapshot' | 'downloading-model' | 'reembedding' | 'done';
  model?: 'english' | 'multilingual';
  graphId?: string;
  index?: number;
  total?: number;
  nodesInGraph?: number;
  graphsRebuilt?: number;
  cancelled?: boolean;
  errors?: Array<{ graphId: string; error: string }>;
}
function openEmbeddingProgressModal(target: 'english' | 'multilingual'): void {
  const modal = document.getElementById('embedding-switch-modal');
  const phaseEl = document.getElementById('embedding-switch-phase');
  const detailEl = document.getElementById('embedding-switch-detail');
  const barEl = document.getElementById('embedding-switch-bar');
  const counterEl = document.getElementById('embedding-switch-counter');
  const closeBtn = document.getElementById('embedding-switch-close') as HTMLButtonElement | null;
  const cancelBtn = document.getElementById('embedding-switch-cancel') as HTMLButtonElement | null;
  if (!modal || !phaseEl || !detailEl || !barEl || !counterEl || !closeBtn || !cancelBtn) return;
  modal.classList.remove('hidden');
  closeBtn.disabled = true;
  closeBtn.onclick = () => {
    modal.classList.add('hidden');
    void refreshEmbeddingPicker();
  };
  // Cancel: fire the cooperative abort. The host loop bails between
  // engrams; the 'done' progress event will fire with cancelled=true and
  // re-enable the Close button.
  cancelBtn.disabled = false;
  cancelBtn.onclick = () => {
    cancelBtn.disabled = true;
    cancelBtn.textContent = 'Cancelling…';
    void ipcCall('embedding:cancelSwitch', {}).catch(() => { /* non-fatal */ });
  };
  phaseEl.textContent = 'Starting…';
  detailEl.textContent = `Switching to ${target === 'multilingual' ? 'multilingual-e5-large' : 'BGE-small-en-v1.5'}.`;
  barEl.style.width = '0%';
  counterEl.textContent = '';
  void ipcCall<{ ok: boolean; switched: boolean; graphsRebuilt?: number; errors?: Array<{ graphId: string; error: string }> }>('embedding:setModel', { model: target })
    .then((result) => {
      // The 'done' progress event will also flip the close button — this
      // is the fallback in case the event arrived earlier or got lost.
      closeBtn.disabled = false;
      if (!result.switched) {
        phaseEl.textContent = 'No change';
        detailEl.textContent = 'That model was already active.';
      }
    })
    .catch((err) => {
      closeBtn.disabled = false;
      phaseEl.textContent = 'Switch failed';
      detailEl.textContent = String((err as Error).message ?? err);
    });
}
void listen<EmbeddingSwitchProgressPayload>('graphnosis://embedding-switch-progress', (evt) => {
  const phaseEl = document.getElementById('embedding-switch-phase');
  const detailEl = document.getElementById('embedding-switch-detail');
  const barEl = document.getElementById('embedding-switch-bar');
  const counterEl = document.getElementById('embedding-switch-counter');
  const closeBtn = document.getElementById('embedding-switch-close') as HTMLButtonElement | null;
  if (!phaseEl || !detailEl || !barEl || !counterEl || !closeBtn) return;
  const p = evt.payload;
  switch (p.phase) {
    case 'snapshot':
      phaseEl.textContent = 'Snapshotting engrams…';
      detailEl.textContent = 'Saving the current vectors so they\'re recoverable.';
      barEl.style.width = '5%';
      break;
    case 'downloading-model':
      phaseEl.textContent = 'Loading new model…';
      detailEl.textContent = p.model === 'multilingual'
        ? 'First time: downloading multilingual-e5-large (~2.2 GB). Cached for next time.'
        : 'First time: downloading BGE-small-en-v1.5 (~30 MB). Cached for next time.';
      barEl.style.width = '15%';
      break;
    case 'reembedding': {
      const idx = p.index ?? 0;
      const total = p.total ?? 1;
      const pct = Math.min(95, 20 + Math.round((idx / Math.max(1, total)) * 75));
      barEl.style.width = `${pct}%`;
      phaseEl.textContent = 'Re-embedding your memory…';
      if (p.graphId) {
        detailEl.textContent = `Engram: ${p.graphId} (${idx + 1} of ${total}, ${p.nodesInGraph ?? '?'} nodes)`;
      } else {
        detailEl.textContent = 'Finishing…';
      }
      counterEl.textContent = `${idx} / ${total} engrams done`;
      break;
    }
    case 'done': {
      barEl.style.width = '100%';
      phaseEl.textContent = p.cancelled ? 'Cancelled' : 'Done';
      const errs = p.errors ?? [];
      if (p.cancelled) {
        detailEl.textContent = `Cancelled after re-embedding ${p.graphsRebuilt ?? 0} engrams. The remaining engrams kept their old vectors (recoverable from the snapshot if needed).`;
      } else {
        detailEl.textContent = errs.length === 0
          ? `Re-embedded ${p.graphsRebuilt ?? 0} engrams. Your memory now uses the new model.`
          : `Re-embedded ${p.graphsRebuilt ?? 0} engrams; ${errs.length} failed: ${errs.map((e) => e.graphId).join(', ')}.`;
      }
      counterEl.textContent = '';
      closeBtn.disabled = false;
      // Reset the cancel button so it isn't stuck on "Cancelling…" if the
      // user reopens the modal for a future operation.
      const cancelBtn = document.getElementById('embedding-switch-cancel') as HTMLButtonElement | null;
      if (cancelBtn) { cancelBtn.disabled = true; cancelBtn.textContent = 'Cancel'; }
      break;
    }
  }
});

// ── GLL predicted edges (review queue) ──────────────────────────────────────
//
// Populated by the autonomous edge-prediction loop in brain-engine (gated on
// llmCapabilities.edgePrediction). Each row carries the relationship label
// the LLM proposed + a confidence percent + previews of both endpoints, and
// Accept / Reject buttons. Refreshed on demand via the buttons; no live
// subscription (low-frequency content, doesn't need it).
interface GllPredictedEdgeRow {
  id: string;
  graphId: string;
  from: string;
  to: string;
  relationship: string;
  score: number;
  createdAt: number;
  modelTag?: string;
  fromPreview: string;
  toPreview: string;
}
async function refreshGllPredictedEdges(): Promise<void> {
  const listEl = document.getElementById('gll-predicted-list');
  const countEl = document.getElementById('gll-predicted-count');
  if (!listEl) return;
  let edges: GllPredictedEdgeRow[];
  try {
    const result = await ipcCall<{ edges: GllPredictedEdgeRow[] } | undefined>('gll:listPredictedEdges', {});
    // Be defensive: the IPC can return undefined when the sidecar is still
    // booting or the cortex isn't unlocked yet. Show a useful "waiting"
    // state rather than the bare word "undefined" — that was the actual
    // bug behind "Could not load predicted edges: undefined".
    if (!result || !Array.isArray(result.edges)) {
      listEl.innerHTML = '<p class="brain-subtitle">Predicted edges aren\'t available yet. This usually means the sidecar is still warming up or the cortex isn\'t fully loaded — click <strong>Refresh list</strong> in a moment.</p>';
      if (countEl) countEl.textContent = '';
      return;
    }
    edges = result.edges;
  } catch (e) {
    // Robust error formatting — Tauri's invoke can reject with strings,
    // bare objects, or Errors. Cover all three shapes so the user never
    // sees a literal "undefined".
    const message = e instanceof Error
      ? (e.message || e.name || 'unknown error')
      : (typeof e === 'string'
          ? e
          : (e && typeof e === 'object' ? JSON.stringify(e) : 'unknown error'));
    listEl.innerHTML = `<p class="brain-subtitle">Could not load predicted edges: ${message}. If you just opened the app, click <strong>Refresh list</strong> after a moment.</p>`;
    if (countEl) countEl.textContent = '';
    return;
  }
  if (countEl) {
    countEl.textContent = edges.length === 0
      ? 'No predictions yet.'
      : `${edges.length} pending`;
  }
  if (edges.length === 0) {
    listEl.innerHTML = '<p class="brain-subtitle">Nothing predicted yet. Either prediction hasn\'t run, or the LLM didn\'t find anything worth proposing in the latest scan.</p>';
    return;
  }
  const trimPreview = (s: string): string => s.length > 90 ? s.slice(0, 87) + '…' : s;
  listEl.innerHTML = edges.map((e) => {
    const pct = Math.round(e.score * 100);
    const when = new Date(e.createdAt).toLocaleString();
    return `<div class="gll-edge-row" data-edge-id="${e.id}" data-score="${e.score}" data-relationship="${e.relationship.replace(/"/g, '&quot;')}" style="border:1px solid var(--border); border-radius:8px; padding:10px 12px; margin-bottom:8px;">`
      + `<div style="display:flex; justify-content:space-between; align-items:flex-start; gap:10px;">`
      + `<div style="font-size:12px; opacity:0.7;"><strong>${e.graphId}</strong> · ${when} · <em>${pct}% confidence</em></div>`
      + `<div style="display:flex; gap:6px;">`
      + `<button data-gll-action="accept" data-edge-id="${e.id}" class="btn-sm primary">Accept</button>`
      + `<button data-gll-action="reject" data-edge-id="${e.id}" class="btn-sm">Reject</button>`
      + `</div>`
      + `</div>`
      + `<div style="margin-top:8px; font-size:13px;">`
      + `<div style="margin-bottom:4px;"><strong>A:</strong> ${trimPreview(e.fromPreview)}</div>`
      + `<div style="font-weight:600; color:var(--accent,#5b8def); margin:4px 0;">↓ ${e.relationship}</div>`
      + `<div><strong>B:</strong> ${trimPreview(e.toPreview)}</div>`
      + `</div>`
      + `</div>`;
  }).join('');
}
/** Confidence below this triggers a confirmation dialog before promoting a
 *  predicted edge to .gai. High-confidence accepts go straight through —
 *  the user already exercised judgment by clicking Accept. Lower-confidence
 *  ones get an explicit "are you sure?" so a fat-finger click on a 55%
 *  prediction doesn't permanently write a wrong edge into canonical memory. */
const GLL_HIGH_CONFIDENCE = 0.75;

document.addEventListener('click', (ev) => {
  const target = ev.target as HTMLElement | null;
  if (!target?.matches('[data-gll-action]')) return;
  const action = target.dataset.gllAction;
  const id = target.dataset.edgeId;
  if (!action || !id) return;
  if (action === 'reject') {
    void ipcCall('gll:rejectPredictedEdge', { id }).then(() => { void refreshGllPredictedEdges(); });
    return;
  }
  // Accept path. Read the row's confidence + relationship from the data-*
  // attributes we put on the row when rendering so we can decide whether
  // to confirm.
  const row = target.closest<HTMLElement>('.gll-edge-row');
  const score = row ? parseFloat(row.dataset.score ?? '0') : 0;
  const relationship = row?.dataset.relationship ?? 'related';
  if (score < GLL_HIGH_CONFIDENCE) {
    const pct = Math.round(score * 100);
    const ok = confirm(
      `Promote this prediction to your canonical graph?\n\n` +
      `Confidence: ${pct}% (below the ${Math.round(GLL_HIGH_CONFIDENCE * 100)}% high-confidence bar)\n` +
      `Relationship: "${relationship}"\n\n` +
      `Once promoted, the edge lives in your engram and is treated as your attested memory. ` +
      `You can always remove it later via the engram inspector, but the action is recorded in the op-log.\n\n` +
      `Promote anyway?`,
    );
    if (!ok) return;
  }
  void ipcCall('gll:acceptPredictedEdge', { id }).then((result: unknown) => {
    void refreshGllPredictedEdges();
    // Surface the structural edge type the heuristic picked, so the user
    // sees what was actually written (relationship label preserved as
    // evidence, but the SDK enum slot is one of a fixed set).
    const r = result as { ok?: boolean; edgeType?: string; reason?: string } | undefined;
    if (r?.ok && r.edgeType) {
      // Quiet success — no toast; the row disappearing is the feedback.
      console.log(`[gll] promoted as [${r.edgeType}: "${relationship}"]`);
    } else if (r && !r.ok) {
      alert(`Could not promote: ${r.reason ?? 'unknown error'}`);
    }
  });
});
const btnGllRunNow = document.getElementById('btn-gll-run-now') as HTMLButtonElement | null;
btnGllRunNow?.addEventListener('click', () => {
  btnGllRunNow.disabled = true;
  btnGllRunNow.textContent = 'Predicting…';
  void ipcCall('gll:runPredictionNow', {})
    .then(() => { void refreshGllPredictedEdges(); })
    .finally(() => {
      btnGllRunNow.disabled = false;
      btnGllRunNow.textContent = 'Run prediction now';
    });
});
document.getElementById('btn-gll-refresh')?.addEventListener('click', () => {
  void refreshGllPredictedEdges();
});
// Initial render once after first paint; subsequent refreshes are
// button-driven (low-frequency content; no need to subscribe to events).
// Delay 5s so the sidecar IPC is reliably up before we ask — the previous
// 2s window raced cortex-unlock and produced a "could not load: undefined"
// flash on slow boots.
setTimeout(() => { void refreshGllPredictedEdges(); }, 5_000);

// ── Reingest-all progress ──────────────────────────────────────────────────
//
// Driven by the 'reingest.progress' event channel. Phases:
// 'snapshot' → 'reingesting' (per-source counter) → 'done' (with summary).
// Triggered by the "Reingest all sources" button in Settings → Ingest.
interface ReingestPerGraphResult {
  graphId: string;
  reingested: number;
  skipped: Array<{ sourceId: string; reason: string }>;
  failed: Array<{ sourceId: string; ref: string; error: string }>;
}
interface ReingestProgressPayload {
  phase: 'snapshot' | 'reingesting' | 'done';
  graphId?: string;
  graphIndex?: number;
  graphsTotal?: number;
  sourceId?: string;
  ref?: string;
  index?: number;
  total?: number;
  reingested?: number;
  cancelled?: boolean;
  skipped?: number | Array<{ sourceId: string; reason: string }>;
  failed?: number | Array<{ sourceId: string; error: string }>;
  perGraph?: ReingestPerGraphResult[];
}
/**
 * Open the shared reingest-progress modal and kick off a reingest.
 *
 * Pass `graphId` + `displayName` to scope the operation to a single engram
 * (calls `engram:reingestAll`). Omit both to reingest every engram
 * (`engrams:reingestAll`).
 */
function openReingestModal(opts?: { graphId: string; displayName: string }): void {
  const modal = document.getElementById('reingest-modal');
  const phaseEl = document.getElementById('reingest-phase');
  const detailEl = document.getElementById('reingest-detail');
  const barEl = document.getElementById('reingest-bar');
  const counterEl = document.getElementById('reingest-counter');
  const summaryEl = document.getElementById('reingest-summary');
  const closeBtn = document.getElementById('reingest-close') as HTMLButtonElement | null;
  const cancelBtn = document.getElementById('reingest-cancel') as HTMLButtonElement | null;
  if (!modal || !phaseEl || !detailEl || !barEl || !counterEl || !summaryEl || !closeBtn || !cancelBtn) return;
  modal.classList.remove('hidden');
  closeBtn.disabled = true;
  closeBtn.onclick = () => modal.classList.add('hidden');
  // Cancel is enabled for the duration of the operation; the done event
  // re-disables and resets the label so a subsequent run starts clean.
  cancelBtn.disabled = false;
  cancelBtn.textContent = 'Cancel';
  cancelBtn.onclick = () => {
    cancelBtn.disabled = true;
    cancelBtn.textContent = 'Cancelling…';
    void ipcCall('reingest:cancel', {}).catch(() => { /* non-fatal */ });
  };
  phaseEl.textContent = 'Starting…';
  detailEl.textContent = opts
    ? `Taking a snapshot of "${opts.displayName}" first.`
    : 'Taking a snapshot of every engram first.';
  barEl.style.width = '0%';
  counterEl.textContent = '';
  summaryEl.style.display = 'none';
  summaryEl.innerHTML = '';
  const ipc = opts
    ? ipcCall('engram:reingestAll', { graphId: opts.graphId })
    : ipcCall('engrams:reingestAll', {});
  void ipc.catch((err) => {
    closeBtn.disabled = false;
    phaseEl.textContent = 'Reingest failed';
    detailEl.textContent = String((err as Error).message ?? err);
  });
}
void listen<ReingestProgressPayload>('graphnosis://reingest-progress', (evt) => {
  const phaseEl = document.getElementById('reingest-phase');
  const detailEl = document.getElementById('reingest-detail');
  const barEl = document.getElementById('reingest-bar');
  const counterEl = document.getElementById('reingest-counter');
  const summaryEl = document.getElementById('reingest-summary');
  const closeBtn = document.getElementById('reingest-close') as HTMLButtonElement | null;
  if (!phaseEl || !detailEl || !barEl || !counterEl || !summaryEl || !closeBtn) return;
  const p = evt.payload;
  switch (p.phase) {
    case 'snapshot':
      phaseEl.textContent = 'Snapshotting engrams…';
      detailEl.textContent = 'Saving current chunks/vectors so they\'re recoverable.';
      barEl.style.width = '5%';
      break;
    case 'reingesting': {
      const gi = p.graphIndex ?? 0;
      const gt = Math.max(1, p.graphsTotal ?? 1);
      const idx = p.index ?? 0;
      const total = Math.max(1, p.total ?? 1);
      // Outer (engram) progress: 10% → 95% across all engrams. Inner (source)
      // progress is added proportionally inside the current engram's slot.
      const outer = 10 + (gi / gt) * 85;
      const innerSlot = (1 / gt) * 85;
      const pct = Math.min(95, outer + (idx / total) * innerSlot);
      barEl.style.width = `${pct}%`;
      phaseEl.textContent = 'Reingesting your memory…';
      if (p.sourceId) {
        detailEl.textContent = `${p.graphId ?? ''} — ${p.ref ?? p.sourceId} (${idx + 1} of ${total})`;
      } else {
        detailEl.textContent = `Engram ${gi + 1} of ${gt}: finishing up…`;
      }
      counterEl.textContent = `Engram ${gi + 1} / ${gt} · Source ${Math.min(idx + 1, total)} / ${total}`;
      break;
    }
    case 'done': {
      barEl.style.width = '100%';
      phaseEl.textContent = p.cancelled ? 'Cancelled' : 'Done';
      const reingested = p.reingested ?? 0;
      const skippedCount = typeof p.skipped === 'number' ? p.skipped : (p.skipped?.length ?? 0);
      const failedCount = typeof p.failed === 'number' ? p.failed : (p.failed?.length ?? 0);
      detailEl.textContent = p.cancelled
        ? `Cancelled after reingesting ${reingested} source(s). ${skippedCount} skipped before cancel. Remaining sources kept their old chunks (recoverable from snapshot).`
        : `Reingested ${reingested} source(s). ${skippedCount} skipped. ${failedCount} failed.`;
      counterEl.textContent = '';
      // Reset the cancel button so a future reingest starts clean.
      const cancelBtn = document.getElementById('reingest-cancel') as HTMLButtonElement | null;
      if (cancelBtn) { cancelBtn.disabled = true; cancelBtn.textContent = 'Cancel'; }
      // Detailed per-engram summary when we have the structured data.
      if (Array.isArray(p.perGraph) && p.perGraph.length > 0) {
        const rows = p.perGraph.map((g) => {
          const displayName = loadedGraphs.find((lg) => lg.graphId === g.graphId)?.metadata.displayName ?? g.graphId;
          const parts: string[] = [`<strong>${escape(displayName)}</strong>: ${g.reingested} reingested`];
          if (g.skipped.length > 0) parts.push(`${g.skipped.length} skipped`);
          if (g.failed.length > 0) parts.push(`<span style="color:var(--error)">${g.failed.length} failed</span>`);
          let detail = `<div style="margin-bottom:6px;">${parts.join(' · ')}</div>`;
          // List individual failures with their error messages so the user
          // can see exactly what went wrong (lock files, missing cache, etc.)
          if (g.failed.length > 0) {
            const failLines = g.failed.map((f) => {
              const name = escape(f.ref ? (f.ref.split('/').pop() ?? f.ref) : (f.sourceId.split(':').pop() ?? f.sourceId));
              const err  = escape(f.error ?? 'unknown error');
              return `<div style="margin-left:10px;font-size:11px;color:var(--error);margin-bottom:2px;">✗ ${name}: ${err}</div>`;
            });
            detail += failLines.join('');
          }
          return detail;
        });
        summaryEl.innerHTML = rows.join('');
        summaryEl.style.display = '';
      }
      closeBtn.disabled = false;
      break;
    }
  }
});

